const ID_MACRO_STOP: u16 = 2001;
const ID_MACRO_PLAY: u16 = 2002;
const ID_MACRO_RUN_MULTIPLE: u16 = 2003;
const ID_MACRO_SAVE: u16 = 2004;

/// Our cross-thread wake-up message. Producer threads `PostMessage`
/// this to drag the UI thread out of its `GetMessageW` idle and into
/// the `Shell::drain` path.
const WM_APP_WAKE: u32 = WM_APP + 1;

/// Timer id used by `SetTimer` for the periodic session auto-save.
/// The value is local to the main window's timer table; any
/// non-zero `usize` distinct from other timers on the same HWND
/// works. We have only one timer on the main window, so `1` is
/// fine.
const AUTOSAVE_TIMER_ID: usize = 1;
/// Height of the marquee progress bar overlay shown during the
/// async "Unfold All" walk. Standard Win32 progress bar height.
const WORKSPACE_UNFOLD_PROGRESS_HEIGHT_PX: i32 = 16;
/// Gap between the progress bar and its "Expanding folders: N"
/// label directly below it.
const WORKSPACE_UNFOLD_PROGRESS_GAP_PX: i32 = 6;
/// Height reserved for the status label under the progress bar.
const WORKSPACE_UNFOLD_LABEL_HEIGHT_PX: i32 = 18;
/// Batch size for the async "Unfold All" walk — folders processed
/// per `WM_TIMER` tick. Because the tree is hidden during the
/// walk (see `Self::workspace_unfold_progress`), mid-tick paint
/// isn't visible, so we can be a bit aggressive here without
/// re-introducing the flicker. 20 folders × ~15 ms tick =
/// ~1300 folders/sec — a 5000-folder workspace unfolds in ~4 s.
const WORKSPACE_UNFOLD_BATCH_SIZE: usize = 20;
/// `PBM_SETMARQUEE` (`WM_USER + 10`) — turns marquee animation
/// on/off. `WPARAM = 1` to start with an interval of `LPARAM`
/// milliseconds; `WPARAM = 0` to stop. Not exposed by windows-rs
/// 0.62 under a stable name, so declared here as a literal.
const PBM_SETMARQUEE: u32 = 0x040A;
/// `PBS_MARQUEE` (0x08) — window style that makes the progress
/// bar accept `PBM_SETMARQUEE` and animate. Not exposed under a
/// stable name in windows-rs 0.62.
const PBS_MARQUEE: u32 = 0x08;

/// Timer id for the async "Unfold All" walk on the workspace
/// tree. Each tick processes one folder — expanding it (which
/// fires `TVN_ITEMEXPANDING` → lazy `read_dir`) and enqueueing
/// its subfolders for later ticks. Fires every 5 ms while
/// `workspace_unfold_pending` is non-empty; the timer is killed
/// when the queue drains. Bounded work per tick keeps the UI
/// responsive on very large workspaces — the alternative (one
/// synchronous walk of the entire tree) froze the app on any
/// workspace big enough to notice, which is exactly the N++
/// behaviour we set out to avoid.
const WORKSPACE_UNFOLD_TIMER_ID: usize = 2;

/// Auto-save period in milliseconds. 7 s matches Notepad++'s
/// default for its "auto-save unsaved buffers" backup loop —
/// short enough that a crash loses at most a few seconds of work,
/// long enough that the per-tick capture (one `SCI_GETMODIFY` per
/// tab plus a `SCI_GETTEXT` for each dirty tab) doesn't introduce
/// perceptible cost during normal use.
const AUTOSAVE_INTERVAL_MS: u32 = 7_000;

const MAIN_CLASS: PCWSTR = w!("CodePlusPlusMainWindow");
const SCINTILLA_CLASS: PCWSTR = w!("Scintilla");
const STATUSBAR_CLASS: PCWSTR = w!("msctls_statusbar32");

/// Window classes for the find-in-files bottom dock and its draggable
/// splitter. Both are registered lazily on first `run()` invocation.
