const IDC_FR_IN_SELECTION: u16 = 216;
// FIF tab — m4 step 4a. Layout mirrors N++'s "Find in Files" tab:
// Filters + Directory comboboxes, two FIF-only checkboxes
// (sub-folders, hidden folders), and two FIF-only action buttons
// (Find All, Replace in Files). Find what / Replace with /
// Match case / Whole word / Search Mode / Close are shared with
// the Find and Replace tabs.
const IDC_FR_FIF_FILTERS: u16 = 217;
const IDC_FR_FIF_DIRECTORY: u16 = 218;
const IDC_FR_FIF_BROWSE: u16 = 219;
const IDC_FR_FIF_SUBFOLDERS: u16 = 220;
const IDC_FR_FIF_HIDDEN_FOLDERS: u16 = 221;
const IDC_FR_FIF_FIND_ALL: u16 = 222;
const IDC_FR_FIF_REPLACE_IN_FILES: u16 = 223;

/// About dialog window class.
const ABOUT_CLASS: PCWSTR = w!("CodePlusPlusAboutDialog");

/// Style Configurator dialog window class.
const STYLE_CONFIG_CLASS: PCWSTR = w!("CodePlusPlusStyleConfigDialog");

/// Colour-picker preset popup window class — the small
/// floating frame that opens when the user clicks one of the
/// dialog's colour swatches.
const COLOR_PICKER_POPUP_CLASS: PCWSTR = w!("CodePlusPlusColorPickerPopup");

/// About dialog control ids. The URL link is the only interactive
/// child besides the OK button (`IDOK`); `STN_CLICKED` on it opens
/// the home URL via `ShellExecuteW`. The icon STATIC carries the
/// owner-draw style and is identified by id in `WM_DRAWITEM`'s
/// `DRAWITEMSTRUCT.CtlID`.
const IDC_ABOUT_ICON: u16 = 400;
const IDC_ABOUT_TITLE: u16 = 401;
const IDC_ABOUT_HOME_LABEL: u16 = 402;
const IDC_ABOUT_HOME_LINK: u16 = 403;
const IDC_ABOUT_LICENSE_GROUP: u16 = 404;
const IDC_ABOUT_LICENSE_TEXT: u16 = 405;
/// STATIC control that carries the "MIT License" caption sat on
/// top of the etched frame's top edge. Split out from the frame
/// (`IDC_ABOUT_LICENSE_GROUP`, now an unlabelled `SS_ETCHEDFRAME`)
/// so `about_wnd_proc`'s `WM_CTLCOLORSTATIC` can return
/// `dialog_bg_brush` **only** for this label, giving it an opaque
/// background that visually breaks the frame line around it.
/// Every other STATIC still returns `NULL_BRUSH` for transparent
/// text on the dialog background — the caption is the sole
/// exception because it's the only STATIC that has to opaquely
/// overwrite chrome behind it.
const IDC_ABOUT_LICENSE_TITLE: u16 = 406;

/// `STN_CLICKED` — the static-control click notification fired by
/// `SS_NOTIFY` controls. windows-rs doesn't re-export this constant
/// (it overlaps numerically with `BN_CLICKED`), so we declare it
/// inline. See <https://learn.microsoft.com/windows/win32/controls/stn-clicked>.
const STN_CLICKED: u32 = 0;

// Static-control style bits. windows-rs models these as a typed
// `STATIC_STYLES(u32)` newtype under `Win32::System::SystemServices`,
// which is an awkward import path for the few callers that need
// them. Declared inline as plain integers — the values are stable
// SDK constants going back to Win32's first release.
const SS_LEFT: u32 = 0x0000;
/// `SS_OWNERDRAW` — the parent receives `WM_DRAWITEM` to paint the
/// control. Used by the About dialog so the chameleon can be drawn
/// via `DrawIconEx(DI_NORMAL)` (alpha-aware) rather than the
/// default `SS_ICON` paint path, which strips 32bpp alpha and
/// surfaces the icon's transparent pixels as black on Win11.
const SS_OWNERDRAW: u32 = 0x000D;
const SS_NOTIFY: u32 = 0x0100;
/// `SS_ETCHEDFRAME` — a STATIC style that paints just an etched
/// rectangle around the control's client rect, with no text and
/// no title. Used by the About dialog to draw the "MIT License"
/// frame without the `BS_GROUPBOX` title-paint machinery whose
/// classic + themed variants both let the top border line run
/// through the title glyphs on Win11 (a `SetWindowTheme` +
/// `WM_CTLCOLORBTN` workaround didn't hold). Pairing this style
/// with a separately-positioned "MIT License" STATIC that paints
/// on an opaque `dialog_bg_brush` background over the frame's
/// top edge produces the same "titled group" visual with zero
/// dependency on group-box paint behaviour.
pub(crate) const SS_ETCHEDFRAME: u32 = 0x0012;
/// `SS_CENTER` — horizontally-centred STATIC text. Used by the
/// About dialog's "MIT License" caption so the label reads
/// balanced inside its opaque backing rect regardless of tiny
/// hand-tuned differences in the caption's rect width.
pub(crate) const SS_CENTER: u32 = 0x0001;
/// `SS_CENTERIMAGE` — vertically-centre STATIC content within
/// the control's client rect. Named "image" for historical
/// reasons but Windows applies it to text as well (verified
/// against Win11 24H2). Paired with [`SS_CENTER`] on the About
/// dialog's "MIT License" caption so the text's vertical
/// midpoint lands on the etched-frame's top edge — without it
/// text sits at the top of the rect and the border line reads
/// as running through the descenders.
pub(crate) const SS_CENTERIMAGE: u32 = 0x0200;

/// MAKEINTRESOURCEW(1). Windows treats a `PCWSTR` whose high word is
/// zero as a numeric resource id rather than a pointer to a string;
/// `code++.ico` is embedded by `app/build.rs` at resource id 1.
/// Used by the main window's class registration (large + small
/// taskbar icons) and the About dialog (large + home-row icons).
///
/// `1 as *const u16` is the canonical `MAKEINTRESOURCEW` idiom but
/// trips clippy's `manual_dangling_ptr` lint, which misclassifies
/// the integer-as-pointer cast — suppressed with rationale.
#[allow(clippy::manual_dangling_ptr)]
const APP_ICON_RESOURCE: PCWSTR = PCWSTR(1 as *const u16);

// Find/Replace dialog checkbox-grid dimensions. Promoted to module
// scope so `apply_tab_visibility` can reposition Whole word and
// Match case on the FIF tab to align with the right-column
// FIF-only checkboxes. The Y-chain constants (`FR_DLG_*_Y`) are
// shared with `show_find_replace_dialog`: the dialog body's local
// Y constants alias these, so editing a single value propagates
// to both the layout and the runtime checkbox repositioning.
const FR_CHECKBOX_X: i32 = 14;
const FR_CHECKBOX_W: i32 = 200;
const FR_CHECKBOX_H: i32 = 20;
const FR_CHECKBOX_GAP: i32 = 22;
const FR_DLG_ROW1_Y: i32 = 50;
const FR_DLG_ROW_GAP: i32 = 32;
const FR_DLG_REPLACE_ROW_Y: i32 = FR_DLG_ROW1_Y + FR_DLG_ROW_GAP;
const FR_DLG_FIF_FILTERS_Y: i32 = FR_DLG_REPLACE_ROW_Y + FR_DLG_ROW_GAP;
const FR_DLG_FIF_DIRECTORY_Y: i32 = FR_DLG_FIF_FILTERS_Y + FR_DLG_ROW_GAP;
/// Y of the topmost checkbox in the dialog. The 40 px offset
/// past the last edit row leaves space for the combobox dropdown
/// arrow without clipping.
const FR_CHECKBOX_TOP: i32 = FR_DLG_FIF_DIRECTORY_Y + 40;

/// `IDCANCEL` re-projected as `u16` for use in match arms. `IDCANCEL`
/// itself is `MESSAGEBOX_RESULT(2)` in windows-rs and can't appear as
/// a u16 pattern directly.
const IDCANCEL_U16: u16 = IDCANCEL.0 as u16;

/// One per-file FIF outcome buffered while a search is running.
/// The owning [`WindowState`] flushes these into the listview on
/// `FifEvent::Done`.
struct FifPendingFile {
    path: PathBuf,
    matches: Vec<codepp_core::FifMatch>,
    truncated: bool,
}

/// Mapping from a listview row index back to a source location.
/// The `NM_DBLCLK` handler queues an open + a post-load caret jump
/// to the matched span. Line is 1-based as the search engine
/// reports it; cols are UTF-8 byte offsets within the line, which
/// is what Scintilla's position arithmetic expects. Selecting the
/// span (rather than just placing the caret) makes the match
/// instantly visible without further user interaction.
#[derive(Clone)]
struct FifListviewRow {
    path: PathBuf,
    line_no: u32,
    col_start: u32,
    col_end: u32,
}

/// Drag-tracking state captured on `WM_LBUTTONDOWN` over the FIF
/// splitter and consumed on each `WM_MOUSEMOVE` until the matching
/// `WM_LBUTTONUP`. Stored on `WindowState` rather than the splitter
/// itself so the splitter `wnd_proc` stays a thin forwarder; reading
/// the parent's state is one `state_from_hwnd(GetParent(...))` away.
#[derive(Debug, Clone, Copy)]
struct SplitterDrag {
    /// Cursor Y in screen coords at the moment the user pressed.
    /// Compared against `GetCursorPos` on each `WM_MOUSEMOVE` so the
    /// drag tracks the cursor rather than the splitter (which is
    /// itself moving as the user drags).
    start_screen_y: i32,
    /// Dock height when the user started the drag. The new height
    /// is `dock_height_at_start + (start_screen_y - current_y)` —
    /// dragging up grows the dock.
    dock_height_at_start: i32,
}

/// Horizontal-axis sibling of [`SplitterDrag`] — captured by the
/// workspace splitter's `WM_LBUTTONDOWN`, consumed on each
/// `WM_MOUSEMOVE`, cleared on `WM_LBUTTONUP`. Kept as a
/// distinct type from `SplitterDrag` so the axis is visible in
/// the field's type and a mixup between the two splitters would
/// fail to compile.
#[derive(Debug, Clone, Copy)]
struct WorkspaceSplitterDrag {
    /// Cursor X in screen coords at drag start. New workspace
    /// width = `width_at_start + (current_x - start_screen_x)` —
    /// dragging right grows the panel.
    start_screen_x: i32,
    /// Workspace column width at drag start.
    width_at_start: i32,
}

/// Drag-tracking state for the Document Map splitter — mirror of
/// [`WorkspaceSplitterDrag`] on the right column. The sign
/// convention flips: dragging LEFT grows the panel because the
/// panel sits at the right edge, splitter to its left.
#[derive(Debug, Clone, Copy)]
struct DocMapSplitterDrag {
    /// Cursor X in screen coords at drag start. New docmap width
    /// = `width_at_start - (current_x - start_screen_x)` —
    /// dragging left grows the panel.
    start_screen_x: i32,
    /// Docmap column width at drag start.
    width_at_start: i32,
}

/// Drag-tracking state for scroll-by-drag on the Document Map's
/// miniature view. On mouse-down inside the map view, the map's
/// `wnd_proc` subclass takes capture and stores this marker;
/// every subsequent `WM_MOUSEMOVE` while the marker is present
/// scrolls the main editor to the line under the cursor.
/// Released on `WM_LBUTTONUP` or `WM_CAPTURECHANGED`. Stored on
/// the parent state rather than on the subclass so the map's
/// subclass `wnd_proc` stays a thin forwarder — same pattern the
/// workspace
/// splitter uses.
#[derive(Debug, Clone, Copy)]
struct DocMapScrollDrag {
    /// Non-empty marker. No fields today — the current-cursor
    /// position is read fresh on every `WM_MOUSEMOVE` via
    /// `SCI_POSITIONFROMPOINTCLOSE`. A struct rather than a
    /// bare bool leaves room for future scroll-drag state
    /// (initial-line snapshot for "cancel to original scroll,"
    /// scroll offset accumulator, …) without a wire-format
    /// change to `WindowState`.
    _priv: (),
}

/// Drag-tracking state for tab reordering. Captured on
/// `WM_LBUTTONDOWN` over a tab by the tab control's subclass proc
/// and consumed on each `WM_MOUSEMOVE` until the matching
/// `WM_LBUTTONUP`/`WM_CAPTURECHANGED`. Lives on `WindowState`
/// (alongside `SplitterDrag`) rather than the subclass proc itself
/// so the proc stays a thin forwarder.
#[derive(Debug, Clone, Copy)]
struct TabDrag {
    /// Index in `Shell.tabs` of the tab the user grabbed. Updated
    /// after every successful neighbour-swap so subsequent
    /// `WM_MOUSEMOVE`s "carry" the dragged tab toward the cursor.
    source_idx: usize,
    /// Cursor X in tab-control client coords at the moment the
    /// user pressed. Movement past `TAB_DRAG_THRESHOLD_PX` from
    /// this anchor flips `threshold_passed` and starts the
    /// reorder; before that point a click that happens to wiggle
    /// a pixel doesn't trigger a phantom no-op drag.
    start_x: i32,
    /// `false` until the user has moved more than
    /// `TAB_DRAG_THRESHOLD_PX` from `start_x`; once set, every
    /// further `WM_MOUSEMOVE` evaluates a swap with the tab under
    /// the cursor. The flag is sticky for the duration of the
    /// drag — once a click qualifies as a drag, dragging back
    /// over the original tab still allows further reordering.
    threshold_passed: bool,
}

/// Pixels the cursor must travel from its `WM_LBUTTONDOWN` anchor
/// before a tab click promotes to a drag. Matches the system's
/// drag-detection threshold closely enough that clicks feel
/// instant; could be replaced by `GetSystemMetrics(SM_CXDRAG)` if
/// per-user calibration ever matters.
const TAB_DRAG_THRESHOLD_PX: i32 = 4;

/// One plugin-registered docking dialog. Plugins call
/// `NPPM_DMMREGASDCKDLG` with a `tTbData` whose `h_client` is the
/// plugin's pre-built dialog HWND; the host wraps that HWND in a
/// `frame_hwnd` it owns and re-parents `h_client` into the frame's
/// client area. The frame's title comes from `name`; the
/// `module_name` is kept so `NPPM_DMMGETPLUGINHWNDBYNAME` can
/// disambiguate when two plugins register dialogs with the same
/// display name.
///
/// Floating-only mode (Phase 4 m4) does not yet act on the
/// docking-position bits in `u_mask` (`DWS_DF_CONT_*`), the
/// `pszAddInfo` add-info string, or the `iPrevCont` previous-
/// container hint. Those become live in the Phase 5 docking
/// manager bring-up.
struct DockEntry {
    /// Plugin's pre-built dialog HWND. Re-parented into
    /// `frame_hwnd`'s client area at registration time. The
    /// plugin retains lifetime ownership; the host MUST NOT
    /// `DestroyWindow` it.
    h_client: HWND,
    /// Host-owned floating frame. Created `WS_OVERLAPPEDWINDOW |
    /// WS_EX_TOOLWINDOW`-style so the user gets a normal
    /// resizable mini-window with title and close buttons but no
    /// taskbar entry. Destroyed by Win32 when the main window
    /// dies (the frame is `owned` by the main HWND).
    frame_hwnd: HWND,
    /// Display title — also the lookup key for
    /// `NPPM_DMMGETPLUGINHWNDBYNAME`. Owned `String`; re-read
    /// from the plugin's `pszName` at registration and not
    /// updated thereafter (Phase 5 polish: refresh on
    /// `NPPM_DMMUPDATEDISPINFO`).
    name: String,
    /// Plugin DLL filename without extension; the optional
    /// disambiguator for the two-arg form of
    /// `NPPM_DMMGETPLUGINHWNDBYNAME`.
    module_name: String,
    /// `tTbData.dlg_id` — carried in `nmhdr.idFrom` for any
    /// future `DMN_*` notification routed back to the plugin
    /// (`DMN_CLOSE` in particular, deferred to Phase 5).
    #[allow(dead_code)]
    dlg_id: i32,
    /// Snapshot of `tTbData.u_mask` at registration time.
    /// Floating-only mode currently checks only `DWS_ICONTAB`;
    /// the other bits are kept for Phase 5.
    #[allow(dead_code)]
    u_mask: u32,
}

/// Per-window state. Box-allocated, pointer stashed in
/// `GWLP_USERDATA`. `wnd_proc` reads it back via
/// `GetWindowLongPtrW(GWLP_USERDATA)` on every message. The main
/// window's own HWND is passed to `wnd_proc` on every dispatch, so we
/// don't store it here.
struct WindowState {
    /// DESIGN.md §8 instrumentation. Inert unless `--perf` was passed;
    /// `Rc` because the message pump in `run` and the `wnd_proc`'s
    /// `SCN_PAINTED` arm both need it and neither owns the other.
    perf: std::rc::Rc<codepp_core::perf::Perf>,
    scintilla_hwnd: HWND,
    status_hwnd: HWND,
    /// Toolbar control HWND. Sits between the menu bar and the tab
    /// strip; populated with file/edit/search/view/macro buttons
    /// bound to existing menu IDs (see `mod toolbar`). One image
    /// list shared by every button — destroyed in `WM_DESTROY`.
    toolbar_hwnd: HWND,
    /// Image list that backs `toolbar_hwnd`. Owned by the window —
    /// `ImageList_Destroy` runs on shutdown so the bitmaps don't
    /// outlive the toolbar that draws them.
    toolbar_image_list: windows::Win32::UI::Controls::HIMAGELIST,
    /// Bitmap pixel size (24 or 48) chosen at toolbar creation
    /// time based on system DPI. Cached on `WindowState` so the
    /// layout pass doesn't repeat the DPI probe — `toolbar_height_px`
    /// derives from this.
    toolbar_bitmap_px: i32,
    /// Win32 tab control HWND. Sits between the menu bar and the
    /// Scintilla view; one tab item per `Shell.tabs[i]`. Multi-tab
    /// (Phase 3 milestone 6b) uses `SCI_SETDOCPOINTER` to repoint
    /// the single Scintilla view at the active tab's document on
    /// each click.
    tab_hwnd: HWND,
    /// Number of tab items currently inserted into [`Self::tab_hwnd`].
    /// Compared against `state.shell.tabs.len()` after each drain
    /// so newly-pushed Shell tabs get a tab-control item without
    /// rebuilding the whole strip from scratch.
    synced_tab_count: usize,
    /// HMENU for the main menu bar — the parent of File/Edit/.../Plugins.
    /// Plugins query this via `NPPM_GETMENUHANDLE(NPPMAINMENU)` to
    /// install accelerator-bound items at the top level.
    main_menu: HMENU,
    /// Accelerator table the message pump consults via
    /// `TranslateAcceleratorW`. Lives on `WindowState` (rather
    /// than as a `run()`-local) so plugin-driven mutations
    /// (`NPPM_REMOVESHORTCUTBYCMDID` and the future
    /// `NPPM_SHORTCUT*` write paths) can replace the handle:
    /// Win32 has no in-place accelerator-table mutation API, so
    /// "remove a binding" is implemented as
    /// "copy → filter → create new → destroy old → swap." The
    /// pump reads this slot fresh on every iteration so a
    /// recreate inside a `WM_COMMAND` / NPPM dispatch takes
    /// effect on the very next keystroke. Cleaned up via
    /// `DestroyAcceleratorTable` in `WM_DESTROY`.
    accel_handle: HACCEL,
    /// HMENU for the per-plugin submenu under "Plugins". Plugins query
    /// this via `NPPM_GETMENUHANDLE(NPPPLUGINMENU)` to add their menu
    /// items. Populated lazily on the first `WM_INITMENUPOPUP` for
    /// this submenu (DESIGN.md §6.4 lazy-load contract).
    plugin_menu: HMENU,
    /// Set once the lazy-load + menu-population dance has run for
    /// `plugin_menu`. Subsequent `WM_INITMENUPOPUP` for the same
    /// menu skip the work; we never reload plugins after the first
    /// touch, even if the user re-opens the menu.
    plugins_menu_initialized: bool,
    /// HMENUs of the five menus whose contents reflect live state
    /// (File → Open in Default Viewer greyed state, encoding
    /// radio, language radio, View toggle/check marks, Window's
    /// per-tab list). The popup HMENU on `WM_INITMENUPOPUP` is
    /// matched against these to dispatch the right refresh
    /// routine.
    file_menu: HMENU,
    /// Number of items the recent-files rebuild logic inserted
    /// into `file_menu` on the previous popup. Used by
    /// [`rebuild_file_menu_recent_region`] to know how many
    /// items to remove from the region between the print cluster
    /// and File → Exit before inserting the fresh ones. Zero on
    /// first paint (nothing to remove).
    file_menu_recent_count: usize,
    view_menu: HMENU,
    encoding_menu: HMENU,
    language_menu: HMENU,
    window_menu: HMENU,
    /// Right-edge open-tabs `▼` popup. Same content as `window_menu`
    /// — rebuilt on `WM_INITMENUPOPUP` by `refresh_window_menu`.
    /// Kept as a separate HMENU so the menu-bar match in the popup
    /// dispatcher can identify which one is opening.
    right_shortcuts_menu: HMENU,
    /// HWND of the modeless Find/Replace dialog, lazily created on
    /// the first Ctrl+F / Ctrl+H / menu click. The main message
    /// loop reads this in `IsDialogMessageW(dlg, &msg)` so Tab /
    /// Enter / Esc work inside the dialog while it's open.
    find_replace_dlg: Option<HWND>,
    /// HWND of the modeless UDL editor dialog (Phase 4.6 m3),
    /// lazily created on the first "Define your language…"
    /// menu click. Same discipline as `find_replace_dlg`: the
    /// main message pump routes `IsDialogMessageW` to it, and a
    /// second menu click reuses the existing HWND rather than
    /// opening a duplicate. Cleared on the editor's `WM_DESTROY`
    /// via the [`udl_editor::WM_APP_UDL_CLOSED`] notification.
    udl_editor_dlg: Option<HWND>,
    /// Plugin-registered modeless-dialog HWNDs. Plugins call
    /// `NPPM_MODELESSDIALOG(MODELESSDIALOGADD, hwnd)` to add a
    /// dialog so the message pump consults it via
    /// `IsDialogMessageW` (Tab / Enter / Esc / mnemonic
    /// handling); `MODELESSDIALOGREMOVE` removes it. Plugins own
    /// the dialog lifetime — they're contracted to call REMOVE
    /// before destroying the HWND. Stored as a Vec because
    /// multiple plugins can each register their own dialogs
    /// (unlike `find_replace_dlg`, which is host-owned and
    /// single-instance).
    plugin_modeless_dialogs: Vec<HWND>,
    /// Plugin-registered dockable dialogs (floating-only mode for
    /// Phase 4 m4 — the multi-zone docking manager lands in Phase
    /// 5). Each entry pairs the plugin's `h_client` HWND with the
    /// host-owned floating frame that wraps it. Driven by the
    /// `NPPM_DMM*` family; the Vec is small (typically 1–4
    /// entries) so linear scans are fine for show / hide / lookup.
    /// Cleaned up implicitly when the main window dies — the
    /// frames are owned by the main HWND so Win32 destroys them
    /// alongside.
    dock_dialogs: Vec<DockEntry>,
    /// FIF results dock (Phase 4 m4 step 3). Hidden until a search
    /// completes and step 4b populates the listview.
    fif_dock_hwnd: HWND,
    /// `SysListView32` child of `fif_dock_hwnd`. Three columns: File
    /// / Line / Match. Cleared on each new search; populated on
    /// the terminal `FifEvent::Done` event.
    fif_listview_hwnd: HWND,
    /// Status STATIC pinned to the dock header — "X matches in Y
    /// files" when results are present.
    fif_dock_status: HWND,
    /// Close-X button at the dock header's right edge. Click
    /// hides the dock without losing the listview contents.
    fif_dock_close: HWND,
    /// Draggable handle that resizes the dock vs. the editor when
    /// the dock is visible. Hidden alongside `fif_dock_hwnd`.
    fif_splitter_hwnd: HWND,
    /// Whether the dock + splitter are currently shown. Set true
    /// when the search-completion drain reveals results; cleared
    /// when the user closes the dock (step 4b's × button) or
    /// starts a new search that yields no results.
    fif_dock_visible: bool,
    /// Persisted dock height across show/hide cycles within one
    /// session. Cross-session persistence lands with the rest of
    /// the FIF dialog state.
    fif_dock_height: i32,
    /// `Some` iff the user is currently mid-drag on the splitter.
    fif_splitter_drag: Option<SplitterDrag>,

    // --- Workspace panel (Phase 4.6 m1+) ---
    //
    // The "Folder as Workspace" panel — the left-column tree view
    // reachable via File → Open Folder as Workspace... Both HWNDs
    // are created eagerly at startup (mirroring the FIF-dock
    // pattern) and toggled visible only when the user opens a
    // folder or restores a persisted session.
    //
    // m1 ships all fields present + zero-effect wiring: the panel
    // is created hidden, `workspace_visible` starts false, and
    // `layout_children` short-circuits the workspace column when
    // hidden. Subsequent milestones fill in the picker (m2), the
    // tree body (m3), and cross-session persistence (m4).
    /// Container HWND for the workspace panel. Header bar + action
    /// bar + tree body land inside as children in m2/m3.
    workspace_hwnd: HWND,
    /// Vertical splitter between the workspace panel and the tab
    /// strip / editor column. Hidden alongside `workspace_hwnd`.
    workspace_splitter_hwnd: HWND,
    /// Whether the workspace panel + splitter are currently shown.
    /// Toggled by the File → Open Folder as Workspace... flow
    /// (m2), the View → Folder as Workspace check (m4), the
    /// header's X button (m2), and session restore (m4).
    workspace_visible: bool,
    /// Persisted workspace-column width across show/hide cycles
    /// within one session. Cross-session persistence lands with
    /// [`codepp_core::session::Session`] in m4.
    workspace_width: i32,
    /// `Some` iff the user is currently mid-drag on the workspace
    /// splitter. Mirror of `fif_splitter_drag` for the horizontal
    /// axis — see [`WorkspaceSplitterDrag`].
    workspace_splitter_drag: Option<WorkspaceSplitterDrag>,
    /// Root path of the currently-shown workspace. `None` when
    /// the panel has never been opened this session (or was
    /// closed without re-opening). Set by the folder picker in
    /// [`show_workspace_panel_prompting`]; consumed by the tree
    /// populate in m3.
    #[allow(dead_code, reason = "consumed by the tree populate in m3")]
    workspace_root: Option<PathBuf>,
    // In-panel child controls (all children of `workspace_hwnd`).
    // Positioned by the panel's own `WM_SIZE` handler; visible
    // whenever the panel is visible (their parent's visibility
    // gates them).
    /// Header row: `SS_ETCHEDFRAME` STATIC enclosing the title
    /// label + close-× button as one visually-grouped box. Same
    /// technique as the About dialog's "MIT License" frame —
    /// paints under the label + close via z-order (created
    /// before them so they sit above at paint time).
    workspace_header_frame: HWND,
    /// Header row: fixed title STATIC ("Folder as Workspace") on
    /// the left; the close-× button on the right. Both painted
    /// on top of [`Self::workspace_header_frame`].
    workspace_header_label: HWND,
    workspace_close_hwnd: HWND,
    /// Action row: three narrow buttons on the right — unfold
    /// all, fold all, locate current file. m2 lays them out and
    /// wires the close-only path; the three action buttons'
    /// click handlers (walk-and-expand, walk-and-collapse,
    /// walk-ancestors-and-reveal) land in m3 alongside the tree
    /// body itself.
    workspace_action_unfold: HWND,
    workspace_action_fold: HWND,
    workspace_action_locate: HWND,
    /// `SysTreeView32` filling the panel body. Populated lazily
    /// — the initial [`show_workspace_panel`] call reads only
    /// the root's direct children (fast, one `read_dir`); each
    /// subfolder gets a hidden placeholder child so the `[+]`
    /// chevron appears; expanding a subfolder fires
    /// `TVN_ITEMEXPANDINGW`, which replaces the placeholder
    /// with a real `read_dir` for that folder only. Contrast
    /// with N++, which walks the whole tree eagerly on open
    /// and freezes on large workspaces.
    workspace_tree_hwnd: HWND,
    /// Real (unsanitized) filesystem component name for every
    /// non-placeholder item in the workspace tree, keyed by
    /// `HTREEITEM.0`.
    ///
    /// The text that reaches [`TVITEMW::pszText`] is passed
    /// through [`sanitize_filename_for_display`] first — a
    /// filename carrying a bidi override (U+202E, the "PDF that
    /// runs as an EXE" trick), a zero-width space, a C0 control,
    /// or any other display-hostile codepoint renders as U+FFFD
    /// so the panel can't spoof an extension. The real name still
    /// has to reach the filesystem for `Open`, `Run by system`,
    /// FIF, Explorer-here etc., so it lives here out of band:
    /// [`tree_item_full_path`] rebuilds a path by looking each
    /// ancestor up in this map, never by reading `pszText` back.
    ///
    /// Same shape as [`Self::fif_listview_index`] — the real
    /// value lives in a side table, the sanitized string lives in
    /// the widget, neither is reconstructed from the other. See
    /// the "Workspace tree renders unsanitized filenames…" entry
    /// in DESIGN.md §7.4 for the full rationale, including why
    /// sanitizing at insert time without a side table would break
    /// every hostile-named file in the panel.
    ///
    /// Cleared by [`tree_clear_all`] (which fires on remove-root
    /// and on re-root through [`show_workspace_panel`]).
    /// Placeholder children (inserted via
    /// [`tree_insert_placeholder`]) are deliberately absent —
    /// they carry no name and never appear on a reconstructed
    /// path.
    workspace_tree_names: HashMap<isize, String>,
    /// DFS queue for the async "Unfold All" walk. Non-empty ⇔
    /// walk in progress. On each `WM_TIMER(WORKSPACE_UNFOLD_TIMER_ID)`
    /// tick we pop one folder, expand it (which fires
    /// `TVN_ITEMEXPANDING` → lazy `read_dir`), and push any of
    /// its unexpanded subfolders back onto the queue. When
    /// empty the timer is killed. This keeps the UI thread
    /// free between ticks so paints / mouse / keys still flow
    /// — the alternative (one synchronous walk of the whole
    /// tree) froze the app end-to-end.
    workspace_unfold_pending: Vec<HTREEITEM>,
    /// Count of folders processed so far in the current
    /// "Unfold All" walk. Used to update
    /// [`Self::workspace_unfold_label`]'s text on each tick.
    /// Resets to 0 in [`start_workspace_unfold_all`].
    workspace_unfold_count: usize,
    /// Marquee progress bar shown while an "Unfold All" walk is
    /// in progress. Sibling of `workspace_tree_hwnd` inside
    /// `workspace_hwnd`; the tree is hidden and this + the
    /// counter label take its place. Hides again when the walk
    /// completes. Prevents the per-tick tree repaint from being
    /// visible to the user — the tree only paints once, at the
    /// end, showing the final expanded state.
    workspace_unfold_progress: HWND,
    /// STATIC child that shows "Expanding folders: N" during the
    /// walk. Paired with [`Self::workspace_unfold_progress`].
    workspace_unfold_label: HWND,
    /// Path + kind of the workspace tree item that was
    /// right-clicked. Populated by
    /// [`show_workspace_tree_context_menu`] immediately before
    /// `TrackPopupMenu` and consumed (`.take()`) by the `WM_COMMAND`
    /// handler for `ID_WORKSPACE_CTX_*`. Between click and command
    /// dispatch it lives here rather than being encoded into the
    /// command id so cmd ids stay static (menu-check enable/grey
    /// paths depend on that) and so the target can carry a full
    /// `PathBuf` without pointer marshalling.
    ///
    /// `.take()` on the command side is deliberate — a stale
    /// target from a previous click that never fired (e.g. user
    /// dismissed the popup by clicking elsewhere) MUST NOT be
    /// picked up by the next click. Each context menu populates
    /// this field afresh.
    workspace_ctx_target: Option<WorkspaceCtxTarget>,
    /// Container HWND for the right-side Document Map panel.
    /// Mirror of [`Self::workspace_hwnd`].
    docmap_hwnd: HWND,
    /// Vertical splitter on the LEFT edge of the docmap panel
    /// — mirror of [`Self::workspace_splitter_hwnd`] on the
    /// opposite column. Drag events forward to
    /// [`layout_children`] with a new docmap width.
    docmap_splitter_hwnd: HWND,
    /// Whether the docmap panel + splitter are currently shown.
    /// Toggled by the View → Document Map menu, the docmap
    /// toolbar button, the header's close-× button, and session
    /// restore.
    docmap_visible: bool,
    /// Persisted docmap-column width across show/hide cycles
    /// AND across interactive splitter drags. Cross-session
    /// persistence rides
    /// [`codepp_core::session::DocMapSession::width`].
    docmap_width: i32,
    /// `Some` iff the user is currently mid-drag on the docmap
    /// splitter. Mirror of [`Self::workspace_splitter_drag`].
    docmap_splitter_drag: Option<DocMapSplitterDrag>,
    /// `Some` iff the user is currently mid-drag on the docmap
    /// Scintilla view (drag-to-scroll — see [`DocMapScrollDrag`]).
    /// Every `WM_MOUSEMOVE` while this is `Some` scrolls the main
    /// editor to the line under the cursor.
    docmap_scroll_drag: Option<DocMapScrollDrag>,
    /// Header row `SS_ETCHEDFRAME` STATIC — same construction as
    /// [`Self::workspace_header_frame`].
    docmap_header_frame: HWND,
    /// Header row title STATIC ("Document Map"). Painted on top
    /// of [`Self::docmap_header_frame`].
    docmap_header_label: HWND,
    /// Header row close-× button. Consumed by the panel's own
    /// `wnd_proc` via [`IDC_DOCMAP_CLOSE`].
    docmap_close_hwnd: HWND,
    /// Second Scintilla control — the miniature view. Bound to
    /// the active tab's document via `SCI_SETDOCPOINTER` so it
    /// mirrors the main editor's text without duplicating any
    /// bytes; the two views share the same `Document` at
    /// Scintilla's level. Configured once at creation
    /// (read-only, invisible caret, no scrollbars, no margins,
    /// heavy zoom-out) and re-bound on every tab switch. The
    /// viewport indicator + drag-to-scroll wiring lands in
    /// later commits of the Document Map feature.
    docmap_scintilla_hwnd: HWND,
    /// Direct-call handle for the map's Scintilla control —
    /// speed-path counterpart to [`Self::editor`] but for the
    /// miniature view. Even though the map isn't a hot path
    /// (config-only messages), using an `EditorHandle` matches
    /// the codebase convention and keeps every `send` call
    /// shape-identical to the main editor's.
    docmap_editor: EditorHandle,
    /// Modeless top-level progress window shown while a FIF job
    /// is running. `None` until the user clicks Find All; the
    /// terminal `FifEvent` (Done or Cancelled) destroys it and
    /// resets back to None.
    fif_progress_hwnd: Option<HWND>,
    /// Job id of the currently-running FIF search. Filters stale
    /// events when a second `start_fif` preempts the first.
    /// Cleared on terminal event.
    fif_active_job: Option<u64>,
    /// Per-file outcomes accumulated during the active job. Drained
    /// into the listview on the terminal `Done` event so the user
    /// sees the full result set at once rather than rows
    /// trickling in.
    fif_pending_results: Vec<FifPendingFile>,
    /// Backing store for the listview's items so `NM_DBLCLK` can
    /// resolve the clicked row index back to a file path + line
    /// number. Index here matches the listview row index 1:1.
    fif_listview_index: Vec<FifListviewRow>,
    /// Caret jumps queued by `NM_DBLCLK` and applied after the
    /// matching file's load completes. Each entry carries the same
    /// (path, line, col) data as a [`FifListviewRow`] — reusing
    /// the struct keeps the dblclk handler free of conversion
    /// noise. The drain applies the jump as a `SCI_SETSEL` so the
    /// matched span is selected (and scrolled into view).
    fif_pending_jumps: Vec<FifListviewRow>,
    /// `(files_modified, total_replacements)` produced by the
    /// in-buffer Replace-in-Files pass that runs *before* the
    /// worker for any open tab whose path falls under the FIF root
    /// and matches the include filter. Set in
    /// `start_fif_from_snapshot` and merged into the displayed
    /// stats by `finalize_fif_job`. `None` for plain Find in Files
    /// or when no open tabs matched. Cleared on the terminal
    /// `FifEvent` so a subsequent search starts fresh.
    fif_in_buffer_counts: Option<(usize, usize)>,
    /// `Some` iff the user is mid-drag on a tab. Captured on
    /// `WM_LBUTTONDOWN` over a tab item by the tab control's
    /// subclass proc; cleared on `WM_LBUTTONUP` /
    /// `WM_CAPTURECHANGED`. The subclass proc reads/writes via
    /// `state_from_hwnd(GetParent(...))`, mirroring the FIF
    /// splitter's drag-state pattern.
    tab_drag: Option<TabDrag>,
    /// 32bpp premultiplied-BGRA `HBITMAP` rendered from
    /// `assets/icons/tab-save.png` (and `@2x.png` for `HiDPI`).
    /// Painted into each tab cell's left margin by
    /// [`paint_tab_item`] when the buffer is clean; the dirty
    /// variant is in [`Self::tab_save_red_hbm`]. Owned by
    /// `WindowState`; freed in `WM_DESTROY` alongside the toolbar
    /// image list.
    tab_save_blue_hbm: HBITMAP,
    /// Companion to [`Self::tab_save_blue_hbm`] — same icon recoloured
    /// red for the dirty-buffer state. Same lifetime contract.
    tab_save_red_hbm: HBITMAP,
    /// 16 or 32 — edge length of the loaded tab icons in pixels.
    /// Picked once at construction via [`pick_tab_bitmap_size`]
    /// based on the system DPI, mirroring the toolbar's 24/48 split.
    tab_bitmap_px: i32,
    /// Index of the tab the cursor is currently over, or `None` when
    /// the cursor is outside the tab strip. Tracked via
    /// `WM_MOUSEMOVE` / `WM_MOUSELEAVE` in the tab subclass proc and
    /// read by [`paint_tab_item`] to decide whether to render the
    /// close-X (visible on hover for inactive tabs).
    tab_hover_idx: Option<usize>,
    /// True iff the cursor sits over the close-X clickable rect of
    /// the tab in [`Self::tab_hover_idx`]. Drives the colour swap
    /// (grey → light red) regardless of which tab is active. Always
    /// `false` when [`Self::tab_hover_idx`] is `None`.
    tab_hover_close_x: bool,
    /// True iff `TrackMouseEvent(TME_LEAVE)` is armed for the tab
    /// strip. Win32 expects the call to be re-armed once per hover
    /// session; without the flag we'd re-arm on every mousemove (a
    /// bound on `TrackMouseEvent` calls per second is documented as
    /// "implementation-defined" — being explicit is safer).
    tab_mouse_tracking: bool,
    /// `Some(idx)` while the user is mid-click on a close-X glyph
    /// (mouse pressed but not yet released). The close fires on the
    /// matching `WM_LBUTTONUP` only if the cursor is still over the
    /// same X — Win32 button convention. Clears on `WM_CAPTURECHANGED`
    /// so a click-and-drag-away pattern cancels the close instead of
    /// firing it on a release outside the X.
    tab_close_armed: Option<usize>,
    /// True iff the cursor sits over the pin-toggle clickable rect
    /// of the tab in [`Self::tab_hover_idx`]. Symmetric to
    /// [`Self::tab_hover_close_x`] — drives the pin's hover paint
    /// tint (a small colour shift signalling clickability) and
    /// gates the click-through disable so `WM_LBUTTONDOWN` on the
    /// pin doesn't also fall through to tab activation / drag
    /// detection. Always `false` when [`Self::tab_hover_idx`] is
    /// `None`.
    tab_hover_pin: bool,
    /// `Some(idx)` while the user is mid-click on a pin glyph
    /// (pressed but not yet released). The pin toggle fires on
    /// the matching `WM_LBUTTONUP` only if the cursor is still
    /// over the same pin — Win32 button convention, mirroring
    /// [`Self::tab_close_armed`]. A click-and-drag-away cancels
    /// the toggle instead of firing on release outside the pin.
    tab_pin_armed: Option<usize>,
    editor: EditorHandle,
    shell: Shell,
}

impl WindowState {
    /// Split into a (shell, ui-platform) pair so we can call
    /// `shell.drain(ui)` without aliasing `&mut self`. `Win32Ui` is
    /// Copy-cheap (two pointer-sized values + `EditorHandle`) so we just
    /// produce a fresh one per call.
    fn split(&mut self) -> (&mut Shell, Win32Ui) {
        let ui = Win32Ui {
            status_hwnd: self.status_hwnd,
            tab_hwnd: self.tab_hwnd,
            toolbar_hwnd: self.toolbar_hwnd,
            main_menu: self.main_menu,
            // SAFETY: `&raw mut` on a field of `*self` produces
            // a pointer valid for the lifetime of `WindowState`
            // (heap-allocated, pinned via `GWLP_USERDATA` for
            // the window's lifetime). The pointer is only
            // dereferenced on the UI thread while `Win32Ui` is
            // in scope — see the `accel_handle` field doc on
            // `Win32Ui` for the full safety argument.
            accel_handle: &raw mut self.accel_handle,
            plugin_modeless_dialogs: &raw mut self.plugin_modeless_dialogs,
            dock_dialogs: &raw mut self.dock_dialogs,
            udl_registry: &raw const self.shell.udl_registry,
            editor: self.editor,
            docmap_editor: self.docmap_editor,
        };
        (&mut self.shell, ui)
    }

    /// Build the per-call `HostHandles` the plugin dispatcher consumes.
    /// Centralized so the route in `WM_USER+1000..` and any future
    /// notification call site share one definition of "what the host's
    /// handles are right now." `HWND` and `HMENU` in windows-rs 0.62
    /// are both `pub struct(pub *mut c_void)`, so `.0` already has
    /// the `Hwnd = *mut c_void` shape the plugin-host crate expects.
    fn host_handles(&self, npp_hwnd: HWND) -> HostHandles {
        HostHandles {
            npp_hwnd: npp_hwnd.0,
            scintilla_main: self.scintilla_hwnd.0,
            scintilla_secondary: core::ptr::null_mut(),
            plugin_menu: self.plugin_menu.0,
            main_menu: self.main_menu.0,
        }
    }
}

/// `UiPlatform` impl. Lightweight — just carries the HWND values
/// `Shell::drain` needs to reach the editor, status bar, and tab
/// strip. The main HWND is intentionally absent: dialogs that
/// need it are deferred (`PendingDialog`) and shown by `wnd_proc`
/// using its own HWND parameter; methods that need to post back
/// to the main window (e.g. `set_tabbar_hidden`'s deferred
/// relayout) derive it via `GetParent(self.tab_hwnd)`.
#[derive(Clone, Copy)]
struct Win32Ui {
    status_hwnd: HWND,
    tab_hwnd: HWND,
    /// Toolbar control HWND. Carried alongside `tab_hwnd` /
    /// `status_hwnd` so the chrome-toggle messages
    /// (`NPPM_HIDETOOLBAR` and friends) can `ShowWindow` it
    /// without re-resolving from `WindowState`.
    toolbar_hwnd: HWND,
    /// Main menu bar HMENU. The chrome-toggle messages flip the
    /// main window's menu between this and NULL via `SetMenu` /
    /// `DrawMenuBar`. Read-only after window creation.
    main_menu: HMENU,
    /// Pointer to `WindowState.accel_handle` so the dispatcher
    /// can both read (via `CopyAcceleratorTableW`, used by
    /// `NPPM_GETSHORTCUTBYCMDID`) and write (via the
    /// recreate-and-swap dance, used by
    /// `NPPM_REMOVESHORTCUTBYCMDID`) the live accelerator
    /// table. `Win32Ui` stays Copy by carrying the raw pointer
    /// rather than a borrow.
    ///
    /// # Safety
    ///
    /// The pointer is dereferenced on the UI thread only, while
    /// the containing `WindowState` (which holds the slot the
    /// pointer addresses) is alive. `WindowState` is heap-
    /// allocated and pinned via `GWLP_USERDATA` for the life of
    /// the main window; `Win32Ui` instances are produced by
    /// `WindowState::split` and never outlive that scope. No
    /// other code mutates `accel_handle` while a `Win32Ui` is in
    /// use — Win32 dispatches messages serially on the owning
    /// thread, and `state_from_hwnd` refuses re-entrant borrows
    /// via `PluginCallGuard`.
    accel_handle: *mut HACCEL,
    /// Pointer to `WindowState.plugin_modeless_dialogs` so
    /// `NPPM_MODELESSDIALOG` dispatch can register and
    /// unregister plugin-owned dialogs. Carries the same
    /// "`Win32Ui` stays Copy, UI-thread-only access" invariant
    /// as `accel_handle`. Multiple plugins can each register
    /// their own dialogs; the Vec is iterated by the message
    /// pump once per `GetMessageW` to call `IsDialogMessageW`
    /// against each.
    plugin_modeless_dialogs: *mut Vec<HWND>,
    /// Pointer to `WindowState.dock_dialogs` so the
    /// `NPPM_DMM*` family can register / show / hide / look up
    /// floating frames. Same "`Win32Ui` stays Copy, UI-thread-only
    /// access" invariant as `accel_handle` and
    /// `plugin_modeless_dialogs`. The Vec is mutated by
    /// `register_dock_dialog` (push) and read by every other
    /// DMM method.
    dock_dialogs: *mut Vec<DockEntry>,
    /// Pointer to `WindowState.shell.udl_registry` so
    /// `apply_udl_lang` can read the loaded UDLs without
    /// reaching back through `state_from_hwnd(GetParent(...))`
    /// — the reach-back would produce a **second** overlapping
    /// `&mut WindowState` in the callers that already hold one
    /// (`handle_close_active_tab_inner`, `handle_tab_selchange`,
    /// `handle_style_config_menu`), aliasing UB under Rust's
    /// `noalias` optimizer even before behavioural bugs
    /// manifest. Same "raw pointer, UI-thread-only,
    /// non-aliased-by-construction" invariant as
    /// [`Self::accel_handle`] and friends.
    ///
    /// **Aliasing discipline.** The registry is populated once
    /// at `Shell::new` and never mutated after — every read
    /// through this pointer is shared, no `&mut` ever crosses
    /// the FFI boundary via this field. When m3's editor modal
    /// mutates the registry, the mutation must go through
    /// `state_from_hwnd(state)` (no `Win32Ui` involvement) so
    /// this pointer never observes a `&mut UdlRegistry`.
    udl_registry: *const codepp_udl::UdlRegistry,
    editor: EditorHandle,
    /// Direct-call handle for the Document Map's miniature
    /// Scintilla view. Carried alongside [`Self::editor`] so
    /// every Shell-driven `activate_tab` — File→Open, File→New,
    /// session restore, plugin `NPPM_SWITCHTOFILE`, and the
    /// `ensure_one_tab` fallback — can rebind the map view in
    /// lockstep with the main view. Skipping the map here (the
    /// Win32-side handlers alone are not enough) leaves the map
    /// pinned to a stale document that's already been closed or
    /// bypassed, which is both a UX bug (shows the wrong buffer)
    /// and a resource leak (the map's implicit ref keeps the
    /// closed doc resident until the next real tab switch).
    docmap_editor: EditorHandle,
}

// -----------------------------------------------------------------
// Notepad++ ABI menu-command ids (IDM_*).
//
// These are the numeric values plugins pass to `NPPM_MENUCOMMAND` and
// `NPPM_SETMENUITEMCHECK` (declared in
// `plugins/nppcompat-headers/menuCmdID.h`). Kept as Rust constants
// alongside Code++'s own [`ID_*`] block so the mapping function below
// can be a single `match` without a magic-number soup. Only the ids
// Code++ actually implements a target for are declared here; new
// mappings add a matching constant when they land.
//
// The values MUST match `menuCmdID.h` exactly — a plugin compiled
// against those constants sends those numeric ids over the ABI, and
// a mismatch here would silently drop the dispatch.
const IDM_BASE: i32 = 40000;
const IDM_FILE: i32 = IDM_BASE + 1000;
const IDM_EDIT: i32 = IDM_BASE + 2000;
const IDM_SEARCH: i32 = IDM_BASE + 3000;
const IDM_VIEW: i32 = IDM_BASE + 4000;
const IDM_FORMAT: i32 = IDM_BASE + 5000;

const IDM_FILE_NEW: i32 = IDM_FILE + 1;
const IDM_FILE_OPEN: i32 = IDM_FILE + 2;
const IDM_FILE_CLOSE: i32 = IDM_FILE + 3;
const IDM_FILE_CLOSEALL: i32 = IDM_FILE + 4;
const IDM_FILE_SAVE: i32 = IDM_FILE + 6;
const IDM_FILE_SAVEALL: i32 = IDM_FILE + 7;
const IDM_FILE_SAVEAS: i32 = IDM_FILE + 8;
const IDM_FILE_PRINT: i32 = IDM_FILE + 9;
const IDM_FILE_EXIT: i32 = IDM_FILE + 11;
const IDM_FILE_RELOAD: i32 = IDM_FILE + 14;
const IDM_FILE_RENAME: i32 = IDM_FILE + 17;

const IDM_EDIT_CUT: i32 = IDM_EDIT + 1;
const IDM_EDIT_COPY: i32 = IDM_EDIT + 2;
const IDM_EDIT_UNDO: i32 = IDM_EDIT + 3;
const IDM_EDIT_REDO: i32 = IDM_EDIT + 4;
const IDM_EDIT_PASTE: i32 = IDM_EDIT + 5;
const IDM_EDIT_DELETE: i32 = IDM_EDIT + 6;
const IDM_EDIT_SELECTALL: i32 = IDM_EDIT + 7;

const IDM_SEARCH_FIND: i32 = IDM_SEARCH + 1;
const IDM_SEARCH_FINDNEXT: i32 = IDM_SEARCH + 2;
const IDM_SEARCH_REPLACE: i32 = IDM_SEARCH + 3;
const IDM_SEARCH_GOTOLINE: i32 = IDM_SEARCH + 4;
const IDM_SEARCH_FINDINFILES: i32 = IDM_SEARCH + 9;

const IDM_VIEW_ZOOMIN: i32 = IDM_VIEW + 3;
const IDM_VIEW_ZOOMOUT: i32 = IDM_VIEW + 4;
const IDM_VIEW_ZOOMRESTORE: i32 = IDM_VIEW + 5;
const IDM_VIEW_WRAP: i32 = IDM_VIEW + 7;

const IDM_FORMAT_ANSI: i32 = IDM_FORMAT + 1;
const IDM_FORMAT_UTF_8: i32 = IDM_FORMAT + 2;
const IDM_FORMAT_UTF_16BE: i32 = IDM_FORMAT + 3;
const IDM_FORMAT_UTF_16LE: i32 = IDM_FORMAT + 4;
const IDM_FORMAT_AS_UTF_8: i32 = IDM_FORMAT + 5;

/// Returns `true` if `idm` falls inside the plugin-owned cmd-id
/// range — either the `FuncItem` band (from `getFuncsArray`,
/// starting at [`PLUGIN_CMD_ID_BASE`]) or the `NPPM_ALLOCATECMDID`
/// pool (which caps at [`PLUGIN_ALLOC_CMD_LIMIT`]). Ids outside this
/// range are either built-in `IDM_*` values (below the base) or
/// garbage (above the limit).
///
/// **Upper bound matters.** `main_wnd_proc`'s `WM_COMMAND` handler
/// keys off only the low 16 bits of `wparam`, so an `idm` above
/// `u16::MAX` posted through `dispatch_npp_menu_command` would
/// truncate down and alias onto whatever built-in `ID_*` sits at
/// that low id (e.g. `ID_FILE_SAVE = 1000`). Refusing values past
/// the alloc-pool ceiling makes buggy plugins fail closed
/// (`dispatch_npp_menu_command` returns `false` on the unknown id)
/// instead of silently triggering an unrelated host command.
#[cfg(target_os = "windows")]
fn is_plugin_cmd_id(idm: i32) -> bool {
    (PLUGIN_CMD_ID_BASE..=PLUGIN_ALLOC_CMD_LIMIT).contains(&idm)
}

/// Translate a Notepad++-ABI `IDM_*` command id into the Code++
/// internal [`ID_*`] `WM_COMMAND` id that runs the equivalent action.
/// Returns `None` for `IDM_*` values Code++ has no target for
/// (e.g. Notepad++ features Code++ doesn't implement yet).
///
/// Plugin-allocated cmd ids (from `getFuncsArray` `FuncItem` entries
/// or `NPPM_ALLOCATECMDID`) are **not** mapped — the caller detects
/// those via [`is_plugin_cmd_id`] and passes them through untouched
/// so a plugin's own menu items dispatch through the same route.
fn map_npp_idm_to_local(idm: i32) -> Option<u16> {
    match idm {
        IDM_FILE_NEW => Some(ID_FILE_NEW),
        IDM_FILE_OPEN => Some(ID_FILE_OPEN),
        IDM_FILE_CLOSE => Some(ID_FILE_CLOSE),
        IDM_FILE_CLOSEALL => Some(ID_FILE_CLOSE_ALL),
        IDM_FILE_SAVE => Some(ID_FILE_SAVE),
        IDM_FILE_SAVEALL => Some(ID_FILE_SAVE_ALL),
        IDM_FILE_SAVEAS => Some(ID_FILE_SAVE_AS),
        IDM_FILE_PRINT => Some(ID_FILE_PRINT),
        IDM_FILE_EXIT => Some(ID_FILE_EXIT),
        IDM_FILE_RELOAD => Some(ID_FILE_RELOAD),
        IDM_FILE_RENAME => Some(ID_FILE_RENAME),
        IDM_EDIT_CUT => Some(ID_EDIT_CUT),
        IDM_EDIT_COPY => Some(ID_EDIT_COPY),
        IDM_EDIT_UNDO => Some(ID_EDIT_UNDO),
        IDM_EDIT_REDO => Some(ID_EDIT_REDO),
        IDM_EDIT_PASTE => Some(ID_EDIT_PASTE),
        IDM_EDIT_DELETE => Some(ID_EDIT_DELETE),
        IDM_EDIT_SELECTALL => Some(ID_EDIT_SELECTALL),
        IDM_SEARCH_FIND => Some(ID_SEARCH_FIND),
        IDM_SEARCH_FINDNEXT => Some(ID_SEARCH_FINDNEXT),
        IDM_SEARCH_REPLACE => Some(ID_SEARCH_REPLACE),
        IDM_SEARCH_GOTOLINE => Some(ID_SEARCH_GOTOLINE),
        IDM_SEARCH_FINDINFILES => Some(ID_SEARCH_FINDINFILES),
        IDM_VIEW_ZOOMIN => Some(ID_VIEW_ZOOMIN),
        IDM_VIEW_ZOOMOUT => Some(ID_VIEW_ZOOMOUT),
        IDM_VIEW_ZOOMRESTORE => Some(ID_VIEW_ZOOMRESET),
        IDM_VIEW_WRAP => Some(ID_VIEW_WORDWRAP),
        IDM_FORMAT_ANSI => Some(ID_ENCODING_ANSI),
        IDM_FORMAT_UTF_8 => Some(ID_ENCODING_UTF8),
        IDM_FORMAT_AS_UTF_8 => Some(ID_ENCODING_UTF8_BOM),
        IDM_FORMAT_UTF_16LE => Some(ID_ENCODING_UTF16_LE),
        IDM_FORMAT_UTF_16BE => Some(ID_ENCODING_UTF16_BE),
        _ => None,
    }
}

impl UiPlatform for Win32Ui {
    fn activate_tab(&mut self, _idx: usize, scintilla_doc: isize) -> isize {
        // Resolve the document pointer. A zero `scintilla_doc` is
        // the contract for "no document yet, please create one"
        // — happens the first time a Tab is bound to the view.
        // SCI_CREATEDOCUMENT(wparam = bytes hint, lparam = options)
        // returns the new doc pointer with refcount 1. We then
        // SCI_SETDOCPOINTER to bind it; that bumps the refcount
        // and decrements the previously-bound doc's refcount, but
        // doesn't free either — Scintilla keeps the previous
        // document alive as long as anyone holds a refcount or
        // it's still pointed at.
        let (doc, freshly_created) = if scintilla_doc != 0 {
            (scintilla_doc, false)
        } else {
            (
                self.editor
                    .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT),
                true,
            )
        };
        // Bind the resolved document to the single Scintilla view.
        // wparam is unused; lparam is the doc pointer.
        self.editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Change-history is per-document state — enable on every
        // freshly-minted doc so its lines start tracking edits
        // against the save-point. Bound docs that already existed
        // (the `scintilla_doc != 0` branch) had history enabled at
        // their own creation site, so the call would be a no-op.
        if freshly_created {
            enable_change_history(&self.editor);
            // Tab width is per-document Scintilla state (mutates
            // `pdoc->tabInChars`), so every fresh doc needs it
            // re-applied — otherwise the doc starts with
            // Scintilla's built-in default of 8, mis-drawing
            // indent guides for 4-space-indented code.
            apply_tab_width(&self.editor);
        }
        // Always refresh the visible window's line numbers on
        // attach: a brand-new doc needs line 0 seeded; an existing
        // doc may have been edited off-screen since last populate
        // (its width or content may have shifted), or its current
        // viewport may sit on a region the populate hasn't reached
        // yet. Cost is bounded by viewport height (~50 lines), not
        // file size — cheap to run unconditionally.
        populate_visible_line_numbers(&self.editor);
        // Rebind the Document Map's miniature view to the same
        // document in lockstep with the main view. This is the
        // shared chokepoint for every Shell-driven activation
        // (File→Open, File→New, session restore, plugin
        // `NPPM_SWITCHTOFILE`, `ensure_one_tab`); Win32-side
        // tab-switch / tab-close paths also call
        // `sync_docmap_to_active_tab` on top for defence in
        // depth (redundant same-doc rebinds are Scintilla
        // no-ops). Without this call the map view stays pinned
        // to whatever doc it was last bound to, both showing
        // stale content AND leaking a Scintilla `Document` ref
        // on any tab the user closed.
        //
        // The viewport-highlight indicator paints against the
        // now-bound document via
        // `update_docmap_viewport_indicator` — same rationale
        // as [`sync_docmap_to_active_tab`]'s own trailing call:
        // without the update the highlight would show the
        // previous tab's visible range against this tab's text
        // until the next scroll event fires an update.
        self.docmap_editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Kick the viewport-highlight update with the two
        // handles directly — no `state_from_hwnd` reach-back,
        // which matters because this method is called from
        // inside `shell.method(&mut ui)` chains where a `&mut
        // WindowState` is already alive via `state.split()`'s
        // reborrow. A second live `&mut WindowState` here would
        // be aliasing UB. Both handles are already `Copy` on
        // `self`, so this is a straight pass-through.
        unsafe {
            update_docmap_viewport_indicator(self.editor, self.docmap_editor);
        }
        doc
    }

    fn set_buffer_text(&mut self, text: &str, cursor: u64) {
        // SCI_SETTEXT requires a null-terminated UTF-8 string. Build
        // a single buffer; the address is valid for the duration of
        // the synchronous direct-call.
        let mut bytes = Vec::with_capacity(text.len() + 1);
        bytes.extend_from_slice(text.as_bytes());
        bytes.push(0);
        self.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
        // Loaded buffers start clean — clear the undo history (Scintilla
        // would otherwise let Ctrl+Z undo the load itself, then mark
        // everything as deleted) and reset the save point so the title
        // bar isn't asterisk'd.
        self.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
        self.editor.send(SCI_SETSAVEPOINT, 0, 0);
        self.editor.send(SCI_GOTOPOS, cursor as usize, 0);
        // Wipe any per-line margin text the doc carried from its
        // previous state — `SCI_SETTEXT` replaces text but Scintilla
        // keeps `SCI_MARGINSETTEXT` annotations on per-line storage,
        // and they end up landing on lines of the *new* content
        // (the bug: `activate_tab`'s populate set "1" on line 0 of
        // the empty starter doc; after `SCI_SETTEXT`-with-multiline
        // that "1" surfaced on the last line of the new content).
        self.editor.send(SCI_MARGINTEXTCLEARALL, 0, 0);
        // Populate the full document. The visible-only populate
        // would miss off-screen lines during session restore
        // (where this method runs *before* the window is laid out
        // and `SCI_LINESONSCREEN` reports 0). Bounded by the
        // doc's line count — fine for a once-per-load operation.
        // Incremental edits still go through the cheaper
        // `populate_visible_line_numbers` path on `SCN_MODIFIED`.
        populate_all_line_numbers(&self.editor);
        // Refresh the Document Map's viewport highlight so it
        // covers the newly-loaded content. `Win32Ui::activate_tab`
        // ran BEFORE this call — at that point the doc was empty
        // (Scintilla's built-in single-line placeholder) so
        // `update_docmap_viewport_indicator`'s empty-buffer guard
        // returned without painting. Now that `SCI_SETTEXT` has
        // populated real content, re-fire the update so the
        // highlight paints from the first `WM_PAINT` — without
        // this the map stays visibly empty until the user's
        // first scroll gesture triggers an `SCN_UPDATEUI` with
        // `SC_UPDATE_V_SCROLL`.
        unsafe {
            update_docmap_viewport_indicator(self.editor, self.docmap_editor);
        }
    }

    fn get_buffer_text(&mut self) -> String {
        let len = self.editor.send(SCI_GETLENGTH, 0, 0);
        if len <= 0 {
            return String::new();
        }
        // SCI_GETTEXT writes len+1 bytes (null-terminator inclusive)
        // into our buffer; the wparam is the buffer size including
        // the null.
        let cap = len as usize + 1;
        let mut buf = vec![0u8; cap];
        let written = self
            .editor
            .send(SCI_GETTEXT, cap, buf.as_mut_ptr() as isize);
        if written <= 0 {
            return String::new();
        }
        // Drop the trailing null Scintilla wrote.
        buf.truncate(written as usize);
        // Scintilla stores text as the user types — bytes are valid
        // UTF-8 if the buffer is in UTF-8 mode (our default). Use
        // from_utf8_lossy as a defensive measure: if some weird code
        // path inserted invalid bytes, we get U+FFFD rather than
        // panicking. The save path will then surface an encoding
        // error if those bytes can't be re-encoded.
        String::from_utf8_lossy(&buf).into_owned()
    }

    fn get_cursor_pos(&mut self) -> u64 {
        let pos = self.editor.send(SCI_GETCURRENTPOS, 0, 0);
        pos.max(0) as u64
    }

    fn update_status(
        &mut self,
        lang: codepp_core::LangType,
        encoding: &Encoding,
        eol: Eol,
        _byte_len: u64,
    ) {
        // Sync Scintilla's per-document EOL mode with the tab's
        // authoritative EOL. Fires on every normal user-visible
        // tab-activation and metadata-refresh path —
        // `handle_tab_selchange`'s lazy-populate, the tab-close
        // lazy-materialise, the initial post-load status refresh,
        // and the plugin-driven apply_lang / apply_default_style
        // follow-ups — because the Shell layer routes every such
        // transition through `update_status`. Without this,
        // Scintilla's built-in CRLF default (Windows) applies
        // universally, breaking the EOL-preservation contract per
        // DESIGN.md §5.2: pressing Enter in a pure-LF file would
        // inject CRLF-terminated lines into an otherwise LF file.
        //
        // **Known gaps** (tracked follow-ups, not blockers for the
        // common tab-activation paths):
        //   - `Shell::save_all` reactivates each dirty tab via
        //     `ui.activate_tab(idx, stored_doc)` in a loop without
        //     a subsequent `update_status` call. Only reachable
        //     when a tab loaded in the background never had its
        //     Scintilla doc materialised — the deeper bug there
        //     is that `save_all` would then save an empty file,
        //     so the EOL slice is subsumed.
        //   - `Shell::set_buffer_format` (the NPPM_SETBUFFERFORMAT
        //     dispatcher) flips `tab.eol` metadata but doesn't
        //     call `SCI_CONVERTEOLS` or `update_status` on the
        //     active tab. Full fix requires the doc-pointer-swap
        //     dance already tracked as Phase 5 polish work in
        //     DESIGN.md §7.4.
        apply_eol_mode(&self.editor, eol);
        // Multi-part status bar (see `setup_status_parts` for the
        // 7-slot layout). This call writes the metadata-driven
        // parts (lang / EOL / encoding); the caret-driven parts
        // (length-lines / cursor / INS-OVR) are refreshed by
        // `refresh_status_dynamic_parts` so they pick up the
        // current Scintilla state on every call (including after
        // a file load whose `byte_len` arg here is now stale-by-
        // construction — Scintilla has the authoritative number
        // since the buffer is fully populated by the time
        // `update_status` runs).
        //
        // SAFETY on `&*self.udl_registry`: same as
        // `apply_udl_lang` — the registry is populated once at
        // `Shell::new`, read-only from here, and outlives every
        // `Win32Ui` value that captures a pointer to it.
        let lang_label = resolve_lang_label(lang, unsafe { &*self.udl_registry });
        write_status_part(
            self.status_hwnd,
            STATUS_PART_LANG,
            &format!("  {lang_label}"),
        );
        write_status_part(
            self.status_hwnd,
            STATUS_PART_EOL,
            &format!("  {}", eol.long_label()),
        );
        write_status_part(
            self.status_hwnd,
            STATUS_PART_ENCODING,
            &format!("  {}", encoding.label()),
        );
        // Spring (part 1) stays empty so the status bar can absorb
        // window-resize delta there.
        refresh_status_dynamic_parts(self.status_hwnd, &self.editor);
    }

    fn set_plugin_status(&mut self, section: usize, text: &str) {
        // NPPM_SETSTATUSBAR sections: 0 = doc info, 1 = type, 2 =
        // encoding, etc. The Phase 3 status bar is single-part, so
        // we collapse all plugin-supplied sections onto part 0; the
        // next `update_status` call repaints the standard fields.
        //
        // **Known limitation:** a plugin that calls NPPM_SETSTATUSBAR
        // twice with different sections sees only the last write
        // until milestone 6's multi-part status bar lands. Plugins
        // that depend on per-section persistence will visibly
        // misbehave; this is a documented surface deviation, not a
        // bug to file.
        let _ = section;
        write_status_part(self.status_hwnd, 0, text);
    }

    fn mark_saved(&mut self) {
        // Clear the modified flag on the currently-bound document.
        // Scintilla's dirty glyph (and SCI_GETMODIFY) keys off this.
        self.editor.send(SCI_SETSAVEPOINT, 0, 0);
    }

    fn apply_lang(&mut self, lang: LangType) {
        // Phase 4.6 m1c-3b-1: UDL container-lexer routing. When the
        // target LangType is a UDL id (dynamically assigned at startup
        // in `Shell.udl_registry`), take the container-lexer path: a
        // UDL has no Lexilla lexer, so `apply_lang_theme` would drop it
        // into the plain-text fallback. `apply_udl_lang` puts Scintilla
        // in container-lexer mode, where styling arrives as
        // `SCN_STYLENEEDED` notifications that the WM_NOTIFY handler
        // dispatches to `udl_paint::paint_udl_range`.
        if codepp_udl::is_udl_lang_id(lang.as_npp_id()) {
            self.apply_udl_lang(lang);
            return;
        }
        // Everything else is a Lexilla language. Attaching a lexer and
        // painting its classifications is entirely Scintilla-level work
        // with no Win32 in it, so it lives in `editor` and is shared
        // with the GTK backend — see `codepp_editor::theme` for the
        // ordering contract between lexer swap, style-clear and the
        // per-slot colours.
        codepp_editor::theme::apply_lang_theme(&self.editor, lang);
    }

    fn apply_default_style(&mut self, styles: &codepp_core::styles::Styles) {
        let entry = styles.effective_default();
        let transparency = styles.effective_transparency();

        // Resolve fg / bg. Malformed hex (impossible from a
        // round-tripped doc but possible if a user hand-edits
        // styles.xml) falls back to the built-in default so the
        // editor stays readable rather than rendering invisible
        // text on the user's mistake.
        let fg_rgb = codepp_core::styles::parse_rgb_hex(&entry.fg).unwrap_or((0, 0, 0));
        let bg_rgb = codepp_core::styles::parse_rgb_hex(&entry.bg).unwrap_or((0xFF, 0xFF, 0xFF));
        let fg_cref = rgb_to_colorref(fg_rgb);
        let bg_cref = rgb_to_colorref(bg_rgb);

        // Configure STYLE_DEFAULT first — `SCI_STYLECLEARALL`
        // copies STYLE_DEFAULT to every other style index, so
        // the font / size / colours seed every per-lexer style
        // before the per-lexer overrides re-paint over them.
        self.editor.style_set_font(STYLE_DEFAULT, &entry.font_name);
        self.editor
            .style_set_size(STYLE_DEFAULT, i32::from(entry.font_size));
        self.editor.style_set_fore(STYLE_DEFAULT, fg_cref);
        self.editor.style_set_back(STYLE_DEFAULT, bg_cref);
        self.editor.style_set_bold(STYLE_DEFAULT, entry.bold);
        self.editor.style_set_italic(STYLE_DEFAULT, entry.italic);
        self.editor
            .style_set_underline(STYLE_DEFAULT, entry.underline);

        // Propagate STYLE_DEFAULT to every other style index, then
        // re-apply the line-number margin, brace-highlight styles,
        // and indent-guide style (all sit in the 32-39 predefined-
        // style range that `SCI_STYLECLEARALL` resets to
        // `STYLE_DEFAULT`, losing their per-slot colour pairs).
        self.editor.style_clear_all();
        apply_line_number_margin(&self.editor);
        apply_brace_styles(&self.editor);
        apply_indent_guide_style(&self.editor);

        // Transparency. WS_EX_LAYERED is required for
        // `SetLayeredWindowAttributes` to take effect; when
        // disabled, we strip the bit so the editor doesn't pay
        // the layered-window compositing cost. The conversion
        // from "opacity percent" to the alpha byte is
        // `percent * 255 / 100` (so 100% → 255 fully opaque).
        let main_hwnd = unsafe { GetParent(self.tab_hwnd).unwrap_or_default() };
        if main_hwnd.is_invalid() {
            // The tab strip is always a child of the main window
            // by construction (see `run`); reaching this branch
            // means `GetParent` failed unexpectedly. Log so the
            // missing transparency is observable rather than a
            // silent skip — the alternative is the user wondering
            // why their checked-on transparency setting has no
            // visible effect.
            tracing::warn!(
                "apply_default_style: GetParent on tab_hwnd returned invalid HWND; transparency not applied"
            );
        } else {
            unsafe {
                apply_window_transparency(main_hwnd, &transparency);
            }
        }

        // The current lexer's classifications need to be re-applied
        // on top of the new STYLE_DEFAULT (which `style_clear_all`
        // has just propagated to every style index). Without a
        // forced re-styling, comments / keywords / strings would
        // all render with the new default colour until the user
        // scrolls or edits. The lexer's keyword classes survive
        // SCI_STYLECLEARALL, so a single colourise repaints
        // correctly.
        self.editor.send(SCI_COLOURISE, 0, -1);
    }

    fn search_next(&mut self, query: &str, flags: SearchFlags) -> Option<u64> {
        // Collapse the selection to its END before re-anchoring.
        // `SCI_SEARCHANCHOR` snaps to `SelectionStart` — without
        // the collapse, a Find Next after a successful match
        // would re-anchor to the start of the previous hit and
        // re-find the same match. Collapsing to the end advances
        // past it. `search_next` takes flags directly via wparam,
        // so no sticky-state surprise from a previous Replace All
        // having left SCFIND_REGEX set.
        let end = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as usize;
        self.editor.send(SCI_SETEMPTYSELECTION, end, 0);
        self.editor.search_anchor();
        match self.editor.search_next(query, flags.bits()) {
            -1 => None,
            pos => {
                center_caret_if_offscreen(&self.editor);
                Some(pos as u64)
            }
        }
    }

    fn search_prev(&mut self, query: &str, flags: SearchFlags) -> Option<u64> {
        // Symmetric to `search_next`: collapse to the START so the
        // re-anchor doesn't re-find the previous match when going
        // backward.
        let start = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as usize;
        self.editor.send(SCI_SETEMPTYSELECTION, start, 0);
        self.editor.search_anchor();
        match self.editor.search_prev(query, flags.bits()) {
            -1 => None,
            pos => {
                center_caret_if_offscreen(&self.editor);
                Some(pos as u64)
            }
        }
    }

    fn replace_current(&mut self, query: &str, replacement: &str, flags: SearchFlags) -> bool {
        // Defense-in-depth empty-query guard: `Shell::replace_current`
        // also gates this, but a future caller that bypasses the
        // shell-level wrapper would otherwise hit Scintilla's
        // permissive empty-target-match behaviour and replace the
        // selection with `replacement` regardless of content.
        if query.is_empty() {
            return false;
        }
        // Use the target range to verify the current selection
        // matches the search query before replacing — guards
        // against the user dragging a different selection between
        // a Find and the Replace click. SCI_GET{SELECTIONSTART,END}
        // gives the selection range; SCI_SETTARGETRANGE pins it as
        // the target; SCI_SEARCHINTARGET returns nonneg iff the
        // target text matches `query` under `flags`. SEARCHINTARGET
        // (unlike SEARCH{NEXT,PREV}) reads flags from the sticky
        // state set by SCI_SETSEARCHFLAGS, so set them first.
        let sel_start = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
        let sel_end = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
        if sel_start == sel_end {
            return false;
        }
        self.editor.set_search_flags(flags.bits());
        self.editor.set_target_range(sel_start, sel_end);
        if self.editor.search_in_target(query) < 0 {
            return false;
        }
        // SEARCHINTARGET narrows the target to the match; replace
        // exactly that. Then re-anchor selection on the inserted
        // text so a subsequent Find Next walks past it.
        let _ = self.editor.replace_target(replacement);
        let new_end = self.editor.target_end();
        self.editor
            .send(SCI_SETSELECTIONSTART, sel_start as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, new_end as usize, 0);
        true
    }

    fn replace_all(&mut self, query: &str, replacement: &str, flags: SearchFlags) -> usize {
        if query.is_empty() {
            return 0;
        }
        // Wrap the whole iteration in a single Scintilla undo group
        // so Ctrl+Z reverts the entire Replace All in one step.
        // SEARCHINTARGET reads flags from the sticky state set
        // here once before the loop.
        self.editor.set_search_flags(flags.bits());
        self.editor.send(SCI_BEGINUNDOACTION, 0, 0);
        let mut count = 0usize;
        let mut cursor = 0u64;
        loop {
            // Re-read the document length each iteration — the
            // previous replace_target may have grown or shrunk
            // the document, so a precomputed end would miss
            // matches past the size delta or stop short of them.
            let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
            self.editor.set_target_range(cursor, doc_len);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let _ = self.editor.replace_target(replacement);
            // Resume just past the inserted replacement; without
            // this, replacing "a" with "ab" would re-match the
            // newly-inserted "a" and loop forever.
            let next = self.editor.target_end();
            // A *zero-width* match needs a second guard. With regex
            // search on, a pattern like `x*`, `^` or `\b` and an empty
            // replacement leaves `target_end` exactly at `cursor`, so
            // the line above would re-search the identical range
            // forever and wedge the UI thread with no recovery but a
            // kill. `count_matches` below has always guarded this way;
            // these loops did not.
            cursor = if next > cursor {
                next
            } else {
                self.editor.send(SCI_POSITIONAFTER, next as usize, 0).max(0) as u64
            };
            count += 1;
        }
        self.editor.send(SCI_ENDUNDOACTION, 0, 0);
        count
    }

    fn count_matches(&mut self, query: &str, flags: SearchFlags) -> usize {
        if query.is_empty() {
            return 0;
        }
        // Whole-buffer iteration via SEARCHINTARGET so the user's
        // selection is never disturbed.
        self.editor.set_search_flags(flags.bits());
        let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
        let mut count = 0usize;
        let mut cursor = 0u64;
        while cursor < doc_len {
            self.editor.set_target_range(cursor, doc_len);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            count += 1;
            let next = self.editor.target_end();
            // Zero-width regex matches need an explicit byte
            // advance — but using +1 directly would land
            // mid-codepoint on multi-byte UTF-8. SCI_POSITIONAFTER
            // walks one whole character forward.
            cursor = if next > cursor {
                next
            } else {
                self.editor.send(SCI_POSITIONAFTER, next as usize, 0).max(0) as u64
            };
        }
        count
    }

    fn search_next_in_range(
        &mut self,
        query: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> Option<u64> {
        if query.is_empty() || end <= start {
            return None;
        }
        self.editor.set_search_flags(flags.bits());
        // Anchor at the caret if it's strictly inside the range,
        // otherwise restart from `start`. Without the
        // strict-inside check a forward selection (caret == end)
        // would produce a zero-width target and silently miss
        // every match in the snapshotted range.
        let caret = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
        let lo = if caret >= start && caret < end {
            caret
        } else {
            start
        };
        self.editor.set_target_range(lo, end);
        let hit = self.editor.search_in_target(query);
        if hit < 0 {
            return None;
        }
        let pos = self.editor.target_start();
        let match_end = self.editor.target_end();
        self.editor.send(SCI_SETSELECTIONSTART, pos as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, match_end as usize, 0);
        center_caret_if_offscreen(&self.editor);
        Some(pos)
    }

    fn search_prev_in_range(
        &mut self,
        query: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> Option<u64> {
        if query.is_empty() || end <= start {
            return None;
        }
        self.editor.set_search_flags(flags.bits());
        // Symmetric upper-bound choice to search_next_in_range:
        // use the caret if it's strictly past `start`, else
        // restart from `end`.
        let caret = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
        let upper = if caret > start && caret <= end {
            caret
        } else {
            end
        };
        // Scintilla's SEARCHINTARGET only walks forward, so we
        // accumulate every match in [start, upper) and keep the
        // last one as the "previous" hit relative to the caret.
        let mut last: Option<(u64, u64)> = None;
        let mut cursor = start;
        while cursor < upper {
            self.editor.set_target_range(cursor, upper);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let pos = self.editor.target_start();
            let me = self.editor.target_end();
            last = Some((pos, me));
            cursor = if me > cursor {
                me
            } else {
                self.editor.send(SCI_POSITIONAFTER, me as usize, 0).max(0) as u64
            };
        }
        let (pos, match_end) = last?;
        self.editor.send(SCI_SETSELECTIONSTART, pos as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, match_end as usize, 0);
        center_caret_if_offscreen(&self.editor);
        Some(pos)
    }

    fn replace_all_in_range(
        &mut self,
        query: &str,
        replacement: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> (usize, u64) {
        if query.is_empty() || end <= start {
            return (0, end);
        }
        self.editor.set_search_flags(flags.bits());
        self.editor.send(SCI_BEGINUNDOACTION, 0, 0);
        let mut count = 0usize;
        let mut cursor = start;
        let mut range_end = end;
        loop {
            self.editor.set_target_range(cursor, range_end);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let match_start = self.editor.target_start();
            let match_end = self.editor.target_end();
            let _ = self.editor.replace_target(replacement);
            // The actual byte length inserted is read back from
            // `target_end()` after `replace_target` — using
            // `replacement.len()` would be wrong under regex
            // mode where a `$1` backref expands to whatever the
            // captured group held, not the format-string length.
            // `saturating_sub` defends against a hypothetical
            // Scintilla edge case where `target_end` reports a
            // value below `match_start` — without it the u64
            // wrap would propagate into `range_end` and lock the
            // loop into an infinite spin.
            let new_target_end = self.editor.target_end();
            // Same zero-width guard as `replace_all`: a match that does
            // not advance would pin `cursor` and spin forever.
            let advanced_end = if new_target_end > cursor {
                new_target_end
            } else {
                self.editor
                    .send(SCI_POSITIONAFTER, new_target_end as usize, 0)
                    .max(0) as u64
            };
            let actual_replacement_len = new_target_end.saturating_sub(match_start);
            let delta = actual_replacement_len as i64 - (match_end as i64 - match_start as i64);
            cursor = advanced_end;
            range_end = (range_end as i64 + delta).max(cursor as i64) as u64;
            count += 1;
            if cursor >= range_end {
                break;
            }
        }
        self.editor.send(SCI_ENDUNDOACTION, 0, 0);
        (count, range_end)
    }

    // confirm_reload and show_error were intentionally removed from
    // UiPlatform: each runs `MessageBoxW` whose nested message pump
    // can re-enter the wnd_proc and produce aliasing UB on the
    // GWLP_USERDATA-borrowed WindowState. Modal dialogs are deferred
    // — `Shell::drain` returns `Vec<PendingDialog>` that the wnd_proc
    // shows after the borrow is dropped (see `WM_APP_WAKE`).

    fn is_tabbar_hidden(&self) -> bool {
        // SAFETY: `self.tab_hwnd` was captured from the live tab
        // control during `WindowState::split`; `IsWindowVisible` is
        // a read-only Win32 query that never re-enters wnd_proc.
        // Returns FALSE for an invalid HWND, which we surface as
        // "not hidden" (matching the unstarted-window default).
        // INVARIANT: UI-thread-only. `IsWindowVisible` reads the
        // window's `WS_VISIBLE` style flag; pairing that read with
        // `ShowWindow` writes from another thread is formally a
        // race on the window-style word. Every call site here
        // runs on the UI thread (all `dispatch_nppm` invocations
        // are on the wnd_proc thread).
        !unsafe { IsWindowVisible(self.tab_hwnd).as_bool() }
    }

    fn set_tabbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_tabbar_hidden();
        // ShowWindow + a deferred relayout via PostMessage(WM_SIZE).
        // Synchronous SendMessage would re-enter the wnd_proc on
        // this thread, and any plugin call dispatching this is
        // already inside `PluginCallGuard` — `state_from_hwnd`
        // would refuse the re-borrow and the layout would no-op.
        // PostMessage queues the size message for after the guard
        // drops; the message-pump dequeue then runs WM_SIZE
        // normally with full state access.
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.tab_hwnd, cmd);
            relayout_main_window_via_post(self.tab_hwnd);
        }
        prev
    }

    fn is_toolbar_hidden(&self) -> bool {
        // Same INVARIANT note as `is_tabbar_hidden` — UI-thread-only,
        // reads `WS_VISIBLE` on the toolbar HWND. Returns FALSE for
        // an invalid HWND, surfaced as "not hidden".
        !unsafe { IsWindowVisible(self.toolbar_hwnd).as_bool() }
    }

    fn set_toolbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_toolbar_hidden();
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.toolbar_hwnd, cmd);
            // Same deferred-relayout pattern as `set_tabbar_hidden`:
            // PostMessage(WM_SIZE) so the editor area refills the
            // freed band without re-entering wnd_proc under
            // `PluginCallGuard`.
            relayout_main_window_via_post(self.toolbar_hwnd);
        }
        prev
    }

    fn is_menu_hidden(&self) -> bool {
        // GetMenu returns NULL when the main window has no menu —
        // i.e. the menu is currently hidden. Cheap UI-thread read.
        // SAFETY: every call site is on the UI thread; the parent
        // HWND is derived from `tab_hwnd`, owned by us for the
        // window's lifetime.
        unsafe {
            let Ok(parent) = GetParent(self.tab_hwnd) else {
                return false;
            };
            GetMenu(parent).is_invalid()
        }
    }

    fn set_menu_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_menu_hidden();
        // SAFETY: UI-thread-only; parent HWND derived from
        // `tab_hwnd` (owned by us). `SetMenu(parent, None)` removes
        // the menu without destroying it; `DrawMenuBar` repaints
        // the non-client area so the freed / re-added band is
        // visible immediately. `None` (rather than
        // `Some(HMENU::default())`) is the documented windows-rs
        // 0.62 idiom for "remove menu" — both happen to produce a
        // zero handle today, but `None` is what the binding's
        // `Option<HMENU>` parameter is meant for and won't break
        // if a future windows-rs minor version stops zeroing
        // handles on `unwrap_or`.
        unsafe {
            let Ok(parent) = GetParent(self.tab_hwnd) else {
                return prev;
            };
            let _ = SetMenu(parent, if hidden { None } else { Some(self.main_menu) });
            let _ = DrawMenuBar(parent);
            // Force a full relayout: removing / restoring the menu
            // changes the client-area height by one menu's worth
            // of pixels, which `WM_SIZE` propagates to the
            // editor / toolbar / status-bar stack.
            relayout_main_window_via_post(self.tab_hwnd);
        }
        prev
    }

    fn is_statusbar_hidden(&self) -> bool {
        !unsafe { IsWindowVisible(self.status_hwnd).as_bool() }
    }

    fn set_statusbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_statusbar_hidden();
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.status_hwnd, cmd);
            relayout_main_window_via_post(self.status_hwnd);
        }
        prev
    }

    fn editor_zoom_level(&self) -> i32 {
        // SCI_GETZOOM returns the zoom delta in points (signed
        // int, typically [-10, 20]). Direct-call read, no message
        // pump — same hot-path shape as every other Scintilla
        // query.
        self.editor.send(SCI_GETZOOM, 0, 0) as i32
    }

    fn editor_default_fg_color(&self) -> i32 {
        // `SCI_STYLEGETFORE(STYLE_DEFAULT)` returns Win32
        // `COLORREF` (`0x00BBGGRR`). The `as i32` cast is the
        // identity bit pattern — Scintilla's return is `intptr_t`
        // (`isize`), but only the low 24 bits of the COLORREF
        // are populated.
        self.editor.send(SCI_STYLEGETFORE, STYLE_DEFAULT, 0) as i32
    }

    fn editor_default_bg_color(&self) -> i32 {
        self.editor.send(SCI_STYLEGETBACK, STYLE_DEFAULT, 0) as i32
    }

    fn set_smooth_font(&mut self, smooth: bool) -> bool {
        // `SCI_SETFONTQUALITY` accepts one of the
        // `SC_EFF_QUALITY_*` enum values; LCD-optimised matches
        // the modern Win32 ClearType default for `smooth == true`,
        // and non-antialiased gives "smoothing off" an
        // observable on-screen effect.
        //
        // Scintilla doesn't expose a `SCI_GETFONTQUALITY` peer in
        // the public message set, so we shadow the state in a
        // process-wide atomic. Single-view Code++ has one editor
        // — the shadow is correct as long as the chrome doesn't
        // race the plugin call (UI-thread-only invariant, same
        // as the chrome toggles).
        let prev = SMOOTH_FONT_STATE.load(std::sync::atomic::Ordering::Relaxed);
        let quality = if smooth {
            SC_EFF_QUALITY_LCD_OPTIMIZED
        } else {
            SC_EFF_QUALITY_NON_ANTIALIASED
        };
        self.editor.send(SCI_SETFONTQUALITY, quality as usize, 0);
        SMOOTH_FONT_STATE.store(smooth, std::sync::atomic::Ordering::Relaxed);
        prev
    }

    fn set_editor_border_edge(&mut self, enable: bool) -> bool {
        // Read the current `WS_EX_CLIENTEDGE` flag, mutate, then
        // tell the window the non-client area changed via
        // `SetWindowPos(SWP_FRAMECHANGED)` so the chrome repaints.
        // SAFETY: `self.editor.hwnd()` is the live editor HWND
        // owned by `WindowState` for the window's lifetime —
        // `EditorHandle::hwnd()` exposes it as `*mut c_void` to
        // keep `editor` free of `windows`-crate types, so we wrap
        // it back into a `HWND` newtype here.
        //
        // `GetWindowLongPtrW` returns `isize` (pointer-width) —
        // not `u32`. On 64-bit Windows the extended-style word is
        // returned through the full 64 bits, so a `as u32` cast
        // here would silently drop bits 32+ before the round-trip
        // through `SetWindowLongPtrW`, clearing whatever flags
        // future Microsoft expansions might add. Stay in `isize`
        // throughout the read-modify-write; widen the
        // `WS_EX_CLIENTEDGE` mask (declared `u32` in windows-rs)
        // to `isize` for the bit ops.
        let scintilla = HWND(self.editor.hwnd());
        let prev_ex = unsafe { GetWindowLongPtrW(scintilla, GWL_EXSTYLE) };
        let edge_mask = WS_EX_CLIENTEDGE.0 as isize;
        let prev_has_edge = (prev_ex & edge_mask) != 0;
        if prev_has_edge != enable {
            let new_ex = if enable {
                prev_ex | edge_mask
            } else {
                prev_ex & !edge_mask
            };
            unsafe {
                SetWindowLongPtrW(scintilla, GWL_EXSTYLE, new_ex);
                let _ = SetWindowPos(
                    scintilla,
                    None,
                    0,
                    0,
                    0,
                    0,
                    SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_FRAMECHANGED,
                );
            }
        }
        prev_has_edge
    }

    fn set_line_number_width_mode(&mut self, mode: i32) -> bool {
        // Code++'s line-number margin uses dynamic width by
        // default. The constant-mode path is a Phase 4 polish
        // item — the dispatcher accepts the request and the
        // host records it, but the visible width does not yet
        // stop growing. Returning `true` means the host
        // accepted the value; the GET side reports DYNAMIC
        // unconditionally until the polish lands.
        tracing::trace!(
            mode,
            "NPPM_SETLINENUMBERWIDTHMODE: recorded (CONSTANT-mode pin is Phase 4 polish)"
        );
        true
    }

    fn shortcut_for_cmd_id(&self, cmd_id: i32) -> Option<codepp_plugin_host::ShortcutKey> {
        // Live introspection of the current accelerator table —
        // reads the same HACCEL the message pump consults via
        // `TranslateAcceleratorW`. When
        // `NPPM_REMOVESHORTCUTBYCMDID` rebuilds the table the
        // change shows up here on the next call without any
        // cache invalidation: there's no cache.
        //
        // SAFETY: `self.accel_handle` was set by
        // `WindowState::split` (or the wnd_proc construction
        // sites) to point at `WindowState.accel_handle`. The
        // dereference reads the live HACCEL on the UI thread.
        // See `Win32Ui.accel_handle` field doc for the full
        // safety argument. `CopyAcceleratorTableW` is a
        // read-only Win32 query that doesn't re-enter
        // wnd_proc.
        let haccel = unsafe { *self.accel_handle };
        if haccel.is_invalid() {
            return None;
        }
        let count = unsafe { CopyAcceleratorTableW(haccel, None) };
        if count <= 0 {
            return None;
        }
        let mut entries: Vec<ACCEL> = vec![ACCEL::default(); count as usize];
        let written = unsafe { CopyAcceleratorTableW(haccel, Some(&mut entries)) };
        if written <= 0 {
            return None;
        }
        entries.truncate(written as usize);
        let needle = cmd_id as u16;
        let entry = entries.iter().find(|a| a.cmd == needle)?;
        Some(decode_accel_to_shortcut_key(entry))
    }

    fn register_modeless_dialog(&mut self, dlg: codepp_plugin_host::Hwnd, register: bool) -> bool {
        // The plugin's `Hwnd` opaque pointer is the same
        // `*mut c_void` Win32 ABI uses for `HWND` — wrap it
        // back into windows-rs's newtype here. We never
        // dereference it; we only feed it to
        // `IsDialogMessageW` from the message pump (and even
        // that is the plugin's responsibility to keep valid via
        // the contract that REMOVE precedes destroy).
        let hwnd = HWND(dlg);
        if hwnd.is_invalid() {
            return false;
        }
        // SAFETY: same Win32Ui field invariants as `accel_handle`
        // — the pointer addresses `WindowState.plugin_modeless_dialogs`
        // which is alive for the window's lifetime, dereferenced
        // only on the UI thread, and not aliased while Win32Ui
        // is in scope.
        let dialogs = unsafe { &mut *self.plugin_modeless_dialogs };
        if register {
            // De-duplicate: a plugin that registers the same
            // HWND twice should not double-iterate it in the
            // pump (would cause `IsDialogMessageW` to fire
            // twice per keystroke, breaking Tab/Enter
            // semantics inside the dialog).
            if !dialogs.iter().any(|h| h.0 == hwnd.0) {
                dialogs.push(hwnd);
            }
        } else {
            dialogs.retain(|h| h.0 != hwnd.0);
        }
        true
    }

    fn add_toolbar_icon(&mut self, cmd_id: i32, hicon: codepp_plugin_host::Hwnd) -> bool {
        // Add the plugin's HICON to the toolbar's HIMAGELIST,
        // then append a TBBUTTON bound to `cmd_id` so a click
        // posts `WM_COMMAND` with the plugin's id — the same
        // path Code++'s built-in toolbar buttons use.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // `self.toolbar_hwnd` is the live toolbar HWND owned by
        // `WindowState`. The plugin's HICON is read-only here;
        // `ImageList_ReplaceIcon` internally copies the bits,
        // so the plugin can free its handle immediately after
        // the call returns.
        use windows::Win32::UI::Controls::{
            ImageList_ReplaceIcon, HIMAGELIST, TBBUTTON, TBSTATE_ENABLED, TBSTYLE_BUTTON,
            TB_ADDBUTTONS, TB_AUTOSIZE, TB_GETIMAGELIST,
        };
        let icon_hwnd = HICON(hicon);
        if icon_hwnd.is_invalid() {
            return false;
        }
        unsafe {
            // Pull the toolbar's imagelist via TB_GETIMAGELIST.
            // wparam = imagelist index (0 — the toolbar's
            // primary list, the one `build_image_list`
            // populated at startup); lparam unused.
            let himl_raw =
                SendMessageW(self.toolbar_hwnd, TB_GETIMAGELIST, Some(WPARAM(0)), None).0;
            if himl_raw == 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: TB_GETIMAGELIST returned NULL"
                );
                return false;
            }
            let himl = HIMAGELIST(himl_raw);
            // `ImageList_ReplaceIcon(himl, -1, hicon)` appends
            // the icon and returns its new index. -1 on failure
            // (out of memory / bad icon).
            let new_idx = ImageList_ReplaceIcon(himl, -1, icon_hwnd);
            if new_idx < 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: ImageList_ReplaceIcon returned -1"
                );
                return false;
            }
            // Build the TBBUTTON. `iBitmap` is the imagelist
            // index just returned; `idCommand` is the plugin's
            // cmd id; `fsState` enables the button; `fsStyle` is
            // BTNS_BUTTON (a plain push button — no check, no
            // separator). `iString` and `dwData` are unused
            // (plugin-driven tooltips arrive via TBN_GETINFOTIP
            // notifications, a future polish item handles).
            let btn = TBBUTTON {
                iBitmap: new_idx,
                idCommand: cmd_id,
                fsState: TBSTATE_ENABLED as u8,
                fsStyle: TBSTYLE_BUTTON as u8,
                bReserved: [0; 6],
                dwData: 0,
                iString: 0,
            };
            let added = SendMessageW(
                self.toolbar_hwnd,
                TB_ADDBUTTONS,
                Some(WPARAM(1)),
                Some(LPARAM(&raw const btn as isize)),
            );
            if added.0 == 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: TB_ADDBUTTONS rejected the new TBBUTTON"
                );
                return false;
            }
            // Refresh layout so the new button is visible
            // immediately. No relayout-via-post needed: the
            // toolbar's own auto-size handles the chrome
            // refresh and the parent's WM_SIZE-driven layout
            // picks up the new toolbar height (if any) on the
            // next paint cycle.
            SendMessageW(self.toolbar_hwnd, TB_AUTOSIZE, None, None);
        }
        true
    }

    fn is_dark_mode_enabled(&self) -> bool {
        // Code++ Phase 4 has no host-side dark-mode rendering
        // (DESIGN.md §7.4 Phase-5 polish item). The honest
        // answer is FALSE; plugins watching `NPPN_DARKMODECHANGED`
        // and gating on this query gracefully skip their
        // dark-mode code paths until the host-side dark mode
        // lands.
        false
    }

    fn dark_mode_colors(&self, _out: &mut codepp_plugin_host::NppDarkModeColors) -> bool {
        // No host-side dark mode → no palette to share. The
        // dispatcher already gated on size + nullness, so
        // returning false is the only honest answer here. When
        // Phase 5 wires dark-mode rendering, this writes the
        // 12 active COLORREFs into `out` and returns true.
        false
    }

    fn create_plugin_scintilla(
        &mut self,
        parent: codepp_plugin_host::Hwnd,
    ) -> codepp_plugin_host::Hwnd {
        // Create a Scintilla control as a child of the
        // plugin-supplied `parent`. The Scintilla window class
        // is already registered (`Scintilla_RegisterClasses`
        // runs at startup), so `CreateWindowExW` against
        // `SCINTILLA_CLASS` produces a fresh control with its
        // own document, undo stack, and direct-call function
        // pointer. The plugin owns the new HWND's lifetime.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // The plugin's `Hwnd` opaque pointer is the same
        // `*mut c_void` Win32 ABI uses for `HWND` — we wrap it
        // back into windows-rs's newtype here. We never
        // dereference it; we only feed it to `IsWindow` and
        // pass it as the parent to `CreateWindowExW`.
        //
        // The returned HWND escapes into plugin address space:
        // the plugin holds it past this function's lifetime
        // and is contractually obliged to `DestroyWindow` it
        // before the parent dies. The host has no lifetime
        // hook to detect a misbehaving plugin's use-after-
        // destroy; this is the same in-process "trust the
        // plugin not to crash us" model Notepad++ uses (and
        // documented in DESIGN.md §6.5).
        let parent_hwnd = HWND(parent);
        // Belt-and-suspenders null check. The dispatcher's
        // `lparam <= 0` guard already rejects NULL via the
        // NPPM path, but the `HostServices` trait is `pub` —
        // a future direct caller (e.g. a Phase-5 GTK/Cocoa
        // NPPM bridge) could bypass the dispatcher.
        // `is_invalid()` is the canonical windows-rs null
        // test; the `IsWindow` call below catches dead-but-
        // non-null parents.
        if parent_hwnd.is_invalid() {
            return core::ptr::null_mut();
        }
        unsafe {
            // Defensive: a plugin that passes a HWND it has
            // already destroyed would otherwise feed a dead
            // HWND to `CreateWindowExW`, which Win32 reports as
            // a confusing "invalid window handle" error. Reject
            // up front instead. `IsWindow` also rejects the
            // `HWND_BROADCAST` pseudo-HWND (0xFFFF), the only
            // positive Win32 pseudo-HWND value that would
            // survive the dispatcher's `lparam <= 0` guard.
            //
            // TOCTOU note: Win32 has no atomic "create only if
            // parent is live" syscall, so a plugin that
            // destroys `parent_hwnd` from a worker thread
            // between this `IsWindow` check and the
            // `CreateWindowExW` call can race the host into
            // either a `CreateWindowExW` failure (benign,
            // logged below) or a child whose parent is
            // garbage-collected indeterminately. The plugin is
            // contractually responsible for not racing
            // destroy-against-create on its own HWNDs; the
            // host stays UI-thread-only for its own state, so
            // it cannot itself introduce the race.
            if !IsWindow(Some(parent_hwnd)).as_bool() {
                tracing::warn!(
                    parent = parent_hwnd.0 as usize,
                    "NPPM_CREATESCINTILLAHANDLE: parent HWND is not a live window"
                );
                return core::ptr::null_mut();
            }
            // The host's executable module handle is the right
            // hInstance for `CreateWindowExW` here — Scintilla's
            // window class was registered against this module
            // by `Scintilla_RegisterClasses` at startup. Using
            // the plugin's DLL hInstance here would be wrong;
            // the class is host-owned, not plugin-owned.
            let instance = match GetModuleHandleW(None) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(
                        error = ?e,
                        "NPPM_CREATESCINTILLAHANDLE: GetModuleHandleW failed"
                    );
                    return core::ptr::null_mut();
                }
            };
            // WS_CHILD: parented control, no caption / no system menu.
            // No WS_VISIBLE: the plugin decides when to show — typical
            // pattern is to size + show inside the plugin's own
            // dialog/container after creation. WS_CLIPCHILDREN keeps
            // any future child redraws (Scintilla itself doesn't add
            // any in this configuration, but plugins occasionally
            // overlay tooltips) from flickering. WS_VSCROLL /
            // WS_HSCROLL match the styles N++ uses for plugin-owned
            // Scintillas so plugin scroll messages have a real bar to
            // drive.
            let new_hwnd = match CreateWindowExW(
                WINDOW_EX_STYLE::default(),
                SCINTILLA_CLASS,
                PCWSTR::null(),
                WS_CHILD | WS_CLIPCHILDREN | WS_VSCROLL | WS_HSCROLL,
                0,
                0,
                0,
                0,
                Some(parent_hwnd),
                None,
                Some(instance.into()),
                None,
            ) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(
                        error = ?e,
                        parent = parent_hwnd.0 as usize,
                        "NPPM_CREATESCINTILLAHANDLE: CreateWindowExW failed"
                    );
                    return core::ptr::null_mut();
                }
            };
            // Initialise the codepage to UTF-8 so plugin-owned
            // Scintillas inherit the host's UTF-8-internal
            // invariant. Scintilla 5.x defaults to SC_CP_UTF8
            // already, but setting it explicitly is robust to
            // a future Scintilla version flipping the default.
            // Plugins that need a different codepage can
            // override after the call returns.
            SendMessageW(
                new_hwnd,
                SCI_SETCODEPAGE,
                Some(WPARAM(SC_CP_UTF8 as usize)),
                None,
            );
            new_hwnd.0
        }
    }

    fn register_dock_dialog(&mut self, params: codepp_plugin_host::DockDialogParams) -> bool {
        // Floating-only mode (Phase 4 m4): wrap the plugin's
        // h_client in a host-owned WS_OVERLAPPEDWINDOW frame and
        // re-parent h_client into the frame's client area. The
        // frame is hidden until NPPM_DMMSHOW.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // `dock_dialogs` points at `WindowState.dock_dialogs`,
        // alive for the main window's lifetime; UI-thread-only
        // access is guaranteed by `state_from_hwnd`'s
        // `PluginCallGuard`.
        let h_client = HWND(params.h_client);
        if h_client.is_invalid() {
            return false;
        }
        unsafe {
            if !IsWindow(Some(h_client)).as_bool() {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: h_client is not a live window"
                );
                return false;
            }
            // Reject duplicate registrations of the same h_client.
            // Walking the Vec is O(n) but n is small (typically
            // <= 4 docks per session) and this is the only
            // call-site that grows it.
            let dialogs = &mut *self.dock_dialogs;
            if dialogs.iter().any(|e| e.h_client.0 == h_client.0) {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: h_client already registered"
                );
                return false;
            }
            // Bound the number of registered frames so a buggy
            // / malicious plugin can't exhaust the per-process
            // GDI handle table by flooding REGASDCKDLG with
            // fresh HWNDs.
            if dialogs.len() >= DOCK_DIALOG_REGISTRATION_CAP {
                tracing::warn!(
                    cap = DOCK_DIALOG_REGISTRATION_CAP,
                    "NPPM_DMMREGASDCKDLG: registration cap reached; rejecting"
                );
                return false;
            }
            register_dock_frame_class();
            let instance = match GetModuleHandleW(None) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(error = ?e, "NPPM_DMMREGASDCKDLG: GetModuleHandleW failed");
                    return false;
                }
            };
            // Initial position: use the plugin's `rc_float` if
            // it's non-empty (right > left, bottom > top); else
            // fall back to a default size centred on the
            // primary monitor's working area (cheap, predictable
            // — Phase 5 docking-manager work places the frame
            // relative to the host window).
            let (x, y, width, height) = compute_dock_frame_position(&params.rc_float);
            // Encode the title in UTF-16 for SetWindowTextW. An
            // empty name (plugin sent NULL pszName, or all bad
            // surrogates) falls back to the module name; if
            // both are empty, use "Plugin Dialog".
            let title = if !params.name.is_empty() {
                params.name.as_str()
            } else if !params.module_name.is_empty() {
                params.module_name.as_str()
            } else {
                "Plugin Dialog"
            };
            let title_utf16: Vec<u16> = title.encode_utf16().chain(core::iter::once(0)).collect();
            // Owned by the main window so Win32 destroys the
            // frame when the host shuts down (no leak on
            // forgetful plugins). WS_EX_TOOLWINDOW keeps the
            // frame off the taskbar — these are accessory
            // panels, not standalone documents.
            //
            // Bail if `GetParent` fails: a null owner would make
            // the frame unowned, breaking the "Win32 destroys
            // the frame when the main window dies" invariant
            // and leaking the frame plus the re-parented
            // h_client. Same early-return pattern as the rest
            // of the file's `GetParent(self.tab_hwnd)` call
            // sites.
            let main_hwnd_owner = match GetParent(self.tab_hwnd) {
                Ok(p) if !p.is_invalid() => p,
                _ => {
                    tracing::warn!("NPPM_DMMREGASDCKDLG: GetParent(tab_hwnd) returned no owner");
                    return false;
                }
            };
            let frame = match CreateWindowExW(
                WS_EX_TOOLWINDOW,
                DOCK_FRAME_CLASS,
                PCWSTR(title_utf16.as_ptr()),
                WS_OVERLAPPEDWINDOW,
                x,
                y,
                width,
                height,
                Some(main_hwnd_owner),
                None,
                Some(instance.into()),
                // Plugin's h_client passed via lpCreateParams;
                // dock_frame_wnd_proc stashes it in
                // GWLP_USERDATA at WM_NCCREATE.
                Some(h_client.0.cast_const()),
            ) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(error = ?e, "NPPM_DMMREGASDCKDLG: CreateWindowExW failed");
                    return false;
                }
            };
            // Re-parent the plugin's h_client into the frame's
            // client area. SetParent returns the previous parent
            // on success (the value we don't need); on failure
            // (different desktop, threading mismatch, etc.) it
            // returns Err. We MUST treat failure as fatal
            // here — otherwise we'd push a DockEntry whose
            // frame_hwnd has no child, and dock_frame_wnd_proc's
            // WM_SIZE would resize an unrelated plugin HWND
            // that's still attached to the plugin's original
            // parent (silent UI corruption).
            //
            // TOCTOU note: between the `IsWindow(h_client)`
            // check above and this `SetParent` call there's a
            // window where the plugin could destroy h_client
            // from another thread. Same race the
            // `create_plugin_scintilla` path documents: Win32
            // has no atomic "act on HWND only if alive"
            // primitive, the plugin owns the destroy contract,
            // and the host stays UI-thread-only. SetParent
            // failure here is the catch-all for any reason
            // h_client became unusable after the IsWindow
            // check.
            if SetParent(h_client, Some(frame)).is_err() {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: SetParent failed; tearing down frame"
                );
                let _ = DestroyWindow(frame);
                return false;
            }
            // Resize h_client to the frame's client area
            // immediately so the first paint shows it filling
            // the client area; subsequent WM_SIZE on the frame
            // does the same via dock_frame_wnd_proc.
            let mut rc = RECT::default();
            if GetClientRect(frame, &raw mut rc).is_ok() {
                let _ = MoveWindow(h_client, 0, 0, rc.right, rc.bottom, true);
            }
            // Make the plugin's dialog visible inside the frame.
            // The frame itself stays hidden until NPPM_DMMSHOW.
            let _ = ShowWindow(h_client, SW_SHOW);
            dialogs.push(DockEntry {
                h_client,
                frame_hwnd: frame,
                name: params.name,
                module_name: params.module_name,
                dlg_id: params.dlg_id,
                u_mask: params.u_mask,
            });
        }
        true
    }

    fn show_dock_dialog(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        // SAFETY: `dock_dialogs` is alive while `Win32Ui` is in
        // scope; UI-thread-only access — see the field doc on
        // `Win32Ui::dock_dialogs`.
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.h_client.0 == h.0 {
                    let _ = ShowWindow(entry.frame_hwnd, SW_SHOW);
                    return true;
                }
            }
        }
        false
    }

    fn hide_dock_dialog(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.h_client.0 == h.0 {
                    let _ = ShowWindow(entry.frame_hwnd, SW_HIDE);
                    return true;
                }
            }
        }
        false
    }

    fn update_dock_disp_info(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        // Floating-only mode (Phase 4 m4): the registration's
        // cached strings (name, module_name) were read once at
        // REGASDCKDLG time and aren't refreshed here. The full
        // re-read (re-walking the plugin's `tTbData`'s wide
        // strings and updating the frame title) is a Phase 5
        // docking-manager polish item — most real plugins set
        // their title once at registration and never update,
        // so the gap is invisible in practice. Returns success
        // for any registered HWND so plugins that gate on the
        // boolean return don't bail out.
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        unsafe {
            let dialogs = &*self.dock_dialogs;
            dialogs.iter().any(|e| e.h_client.0 == h.0)
        }
    }

    fn dock_hwnd_by_name(&self, name: &str, module_name: Option<&str>) -> codepp_plugin_host::Hwnd {
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.name == name && module_name.is_none_or(|m| m == entry.module_name) {
                    return entry.h_client.0;
                }
            }
        }
        core::ptr::null_mut()
    }

    fn remove_shortcut_for_cmd_id(&mut self, cmd_id: i32) -> bool {
        // Win32 has no in-place mutation API for accelerator
        // tables, so "remove a binding" is implemented as
        // copy → filter → create-new → destroy-old → swap.
        // The new HACCEL is written through `self.accel_handle`
        // back to `WindowState`; the message pump reads the
        // slot fresh on every iteration so the removed binding
        // stops translating on the very next keystroke.
        //
        // SAFETY: same UI-thread, single-mutator invariant as
        // `shortcut_for_cmd_id` above. The destroy-old step
        // happens AFTER the new HACCEL is written, so the
        // pump (which can in principle race the recreate on a
        // future async-dispatched plugin call) never reads a
        // freshly-destroyed handle.
        let old_haccel = unsafe { *self.accel_handle };
        if old_haccel.is_invalid() {
            return false;
        }
        let count = unsafe { CopyAcceleratorTableW(old_haccel, None) };
        if count <= 0 {
            return false;
        }
        let mut entries: Vec<ACCEL> = vec![ACCEL::default(); count as usize];
        let written = unsafe { CopyAcceleratorTableW(old_haccel, Some(&mut entries)) };
        if written <= 0 {
            return false;
        }
        entries.truncate(written as usize);
        let needle = cmd_id as u16;
        let before = entries.len();
        entries.retain(|a| a.cmd != needle);
        if entries.len() == before {
            // Nothing matched — the cmd id had no binding in
            // the table, return `false` so the plugin sees
            // "no removal happened" rather than a misleading
            // success.
            return false;
        }
        // Build the new HACCEL. If creation fails (extremely
        // rare — only possible on resource exhaustion), keep
        // the old one so the host stays in a known-good state.
        let new_haccel = match unsafe { CreateAcceleratorTableW(&entries) } {
            Ok(h) => h,
            Err(e) => {
                tracing::warn!(error = ?e, "NPPM_REMOVESHORTCUTBYCMDID: CreateAcceleratorTableW failed, keeping old HACCEL");
                return false;
            }
        };
        // Order matters: write the new handle through the
        // pointer FIRST, then destroy the old one. The pump
        // can read the slot at any time; write-then-destroy
        // ensures the read either sees the old (still valid)
        // handle or the new one — never a destroyed one.
        unsafe {
            *self.accel_handle = new_haccel;
        }
        let _ = unsafe { DestroyAcceleratorTable(old_haccel) };
        true
    }

    fn capture_text_from_doc(&mut self, scintilla_doc: isize) -> String {
        if scintilla_doc == 0 {
            // Sentinel for "no document attached yet" — there's
            // nothing to read. Surface as empty rather than asking
            // Scintilla to dereference a null doc pointer.
            return String::new();
        }
        let prior_doc = self.editor.send(SCI_GETDOCPOINTER, 0, 0);
        if prior_doc == scintilla_doc {
            // Already bound — read directly without round-tripping
            // through SCI_SETDOCPOINTER twice. Common case for the
            // active tab.
            return <Self as UiPlatform>::get_buffer_text(self);
        }
        // Snapshot the prior doc's view state BEFORE the swap.
        // Scintilla's `Editor::SetDocPointer` (Editor.cxx:5464)
        // calls `sel.Clear()` on every doc swap — including the
        // swap-back to the prior doc — so without this snapshot
        // the active tab's caret and scroll get reset to (0, 0)
        // every auto-save tick.
        let view = self.snapshot_active_view();
        self.editor.send(SCI_SETDOCPOINTER, 0, scintilla_doc);
        let text = <Self as UiPlatform>::get_buffer_text(self);
        if prior_doc != 0 {
            self.editor.send(SCI_SETDOCPOINTER, 0, prior_doc);
            self.restore_active_view(view);
        }
        text
    }

    fn replace_doc_text(&mut self, doc: isize, text: &str) -> bool {
        if doc == 0 {
            return false;
        }
        let mut bytes = Vec::with_capacity(text.len() + 1);
        bytes.extend_from_slice(text.as_bytes());
        bytes.push(0);
        let prior_doc = self.editor.send(SCI_GETDOCPOINTER, 0, 0);
        if prior_doc == doc {
            // Already bound — no swap, and no view snapshot needed
            // since nothing rebinds. `SCI_SETTEXT` still moves the
            // caret to the start, which is the same thing Replace All
            // does and is acceptable for a whole-document rewrite.
            self.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
            return true;
        }
        // Same view-snapshot dance as `capture_text_from_doc`: every
        // `SCI_SETDOCPOINTER` clears the selection, including the swap
        // back, so the active tab's caret and scroll must be restored.
        let view = self.snapshot_active_view();
        self.editor.send(SCI_SETDOCPOINTER, 0, doc);
        // `SCI_SETTEXT` only. See the trait docs for why the
        // `SCI_EMPTYUNDOBUFFER` / `SCI_SETSAVEPOINT` pair that
        // `set_buffer_text` adds would be wrong here.
        self.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
        if prior_doc != 0 {
            self.editor.send(SCI_SETDOCPOINTER, 0, prior_doc);
            self.restore_active_view(view);
        }
        true
    }

    fn is_doc_dirty(&mut self, scintilla_doc: isize) -> bool {
        if scintilla_doc == 0 {
            return false;
        }
        let prior_doc = self.editor.send(SCI_GETDOCPOINTER, 0, 0);
        if prior_doc == scintilla_doc {
            return self.editor.send(SCI_GETMODIFY, 0, 0) != 0;
        }
        // Same view-snapshot dance as `capture_text_from_doc`.
        let view = self.snapshot_active_view();
        self.editor.send(SCI_SETDOCPOINTER, 0, scintilla_doc);
        let dirty = self.editor.send(SCI_GETMODIFY, 0, 0) != 0;
        if prior_doc != 0 {
            self.editor.send(SCI_SETDOCPOINTER, 0, prior_doc);
            self.restore_active_view(view);
        }
        dirty
    }

    #[cfg(target_os = "windows")]
    fn dispatch_npp_menu_command(&mut self, idm: i32) -> bool {
        // Resolve the built-in mapping first. Plugin-allocated cmd
        // ids (FuncItem entries or `NPPM_ALLOCATECMDID` allocations)
        // land inside the range checked by [`is_plugin_cmd_id`];
        // those are already installed as menu items owned by the
        // plugin's own submenu and can be dispatched as-is. Unmapped
        // built-in ids AND ids past the plugin-alloc ceiling get
        // logged and dropped — the alternative (posting an
        // unrecognised WM_COMMAND) would either hit the fall-through
        // arm or, worse, collide with an unrelated Code++ ID_* value
        // via `main_wnd_proc`'s low-16-bit `WM_COMMAND` keying.
        let target: u32 = if let Some(local) = map_npp_idm_to_local(idm) {
            u32::from(local)
        } else if is_plugin_cmd_id(idm) {
            // Plugin-allocated cmd id — safe to pass through: it
            // was minted by our own allocator (or came out of the
            // plugin's own FuncItem table) and points at an item
            // in the plugin's submenu. `idm as u32` widens
            // losslessly because `is_plugin_cmd_id` guaranteed
            // `idm >= PLUGIN_CMD_ID_BASE`, which is positive.
            #[allow(clippy::cast_sign_loss)]
            {
                idm as u32
            }
        } else {
            tracing::trace!(idm, "NPPM_MENUCOMMAND: no target for idm");
            return false;
        };
        // Post rather than send: this method runs inside
        // `dispatch_plugin_message`, which holds `&mut Shell` +
        // `&mut Win32Ui` borrows. A synchronous `SendMessageW`
        // would re-enter `main_wnd_proc` on this thread and hit
        // `PluginCallGuard`'s re-borrow refusal (or worse, land
        // in a WM_COMMAND handler that expects those borrows to
        // be free). PostMessage defers the dispatch to the next
        // pump iteration.
        //
        // SAFETY: `self.tab_hwnd`'s parent is the main window,
        // owned by `WindowState` which outlives every `Win32Ui`
        // instance. `PostMessageW` only enqueues; no wnd_proc
        // reentry happens synchronously.
        unsafe {
            let Ok(main_hwnd) = GetParent(self.tab_hwnd) else {
                tracing::warn!("NPPM_MENUCOMMAND: no parent HWND on tab strip");
                return false;
            };
            let _ = PostMessageW(
                Some(main_hwnd),
                WM_COMMAND,
                WPARAM(target as usize),
                LPARAM(0),
            );
        }
        true
    }

    #[cfg(target_os = "windows")]
    fn set_npp_menu_item_check(&mut self, idm: i32, checked: bool) -> bool {
        // Same id-shape decoding as `dispatch_npp_menu_command`:
        // built-in ids go through the mapping table, plugin cmd
        // ids pass through (bounded by `is_plugin_cmd_id`), and
        // everything else is rejected with a trace log. Rejection
        // is symmetric with `dispatch_npp_menu_command` even though
        // `CheckMenuItem` itself doesn't truncate — a plugin
        // sending garbage-past-the-alloc-ceiling is a bug either
        // way, and failing closed on both paths keeps the two
        // dispatch shapes consistent.
        let target: u32 = if let Some(local) = map_npp_idm_to_local(idm) {
            u32::from(local)
        } else if is_plugin_cmd_id(idm) {
            #[allow(clippy::cast_sign_loss)]
            {
                idm as u32
            }
        } else {
            tracing::trace!(idm, "NPPM_SETMENUITEMCHECK: no target for idm");
            return false;
        };
        // `MF_BYCOMMAND` makes `CheckMenuItem` search recursively
        // through every submenu of `self.main_menu` for an item
        // matching `target`. Covers both built-in items (which
        // live in the File / Edit / Search / View submenus) and
        // plugin cmd ids (which live in the Plugins submenu).
        // Returns `-1u32` on failure (item not found) which we
        // surface as `false`; a plugin calling this on an id that
        // has no menu item gets a clean rejection instead of a
        // silent no-op.
        //
        // SAFETY: `self.main_menu` is populated at window
        // construction and never destroyed until window teardown;
        // `Win32Ui` instances are UI-thread-only. `CheckMenuItem`
        // does not re-enter our wnd_proc.
        let flags = MF_BYCOMMAND.0
            | if checked {
                MF_CHECKED.0
            } else {
                MF_UNCHECKED.0
            };
        let prev = unsafe { CheckMenuItem(self.main_menu, target, flags) };
        // `CheckMenuItem` returns `-1u32` (`0xFFFF_FFFF`) when the
        // item can't be found. Every other value is a legitimate
        // previous state (`MF_CHECKED`/`MF_UNCHECKED`).
        prev != u32::MAX
    }

    fn mark_active_buffer_dirty(&mut self) {
        // Scintilla has no direct "flip the modified flag" API —
        // the modified state is derived from whether the current
        // undo position matches the last save-point. To force
        // "dirty" without touching text, we add an opaque
        // container action to the undo stack: that shifts the
        // undo position past the save-point, so `SCI_GETMODIFY`
        // starts returning true.
        //
        // No-op when the buffer is already dirty — a plugin that
        // redundantly re-marks (say, once per keystroke) would
        // otherwise pile up phantom `SC_MOD_CONTAINER` entries the
        // user has to Ctrl+Z past. Once-per-transition matches
        // Notepad++'s own semantic (its `Buffer::setDirty(true)`
        // is idempotent).
        //
        // The container action itself sits on the undo stack as
        // an opaque token (0) with no side effects: if the user
        // does Ctrl+Z all the way back, they'll pass through one
        // phantom step that fires `SCN_MODIFIED` with
        // `SC_MOD_CONTAINER` — Code++ has no `SC_MOD_CONTAINER`
        // handler, so the notification is dropped and the buffer
        // reaches the save-point again (clean). That's the cost
        // of buffer-level "make dirty" without touching text.
        if self.editor.send(SCI_GETMODIFY, 0, 0) != 0 {
            return;
        }
        self.editor.send(SCI_ADDUNDOACTION, 0, 0);
    }
}

/// Snapshot of the editor's view state — the bits Scintilla wipes
/// on `SCI_SETDOCPOINTER` (selection, caret, scroll). Captured
/// before a document-pointer swap by `capture_text_from_doc` and
/// `is_doc_dirty` so that swapping out and back doesn't reset the
/// user's caret to position 0 every auto-save tick.
#[derive(Clone, Copy)]
struct ScintillaViewState {
    /// `SCI_GETCURRENTPOS` — caret end of the selection.
    caret: isize,
    /// `SCI_GETANCHOR` — opposite end of the selection. Equal to
    /// `caret` for a collapsed selection.
    anchor: isize,
    /// `SCI_GETFIRSTVISIBLELINE` — top line of the viewport. Used
    /// with a `SCI_LINESCROLL` delta to restore vertical scroll.
    top_line: isize,
    /// `SCI_GETXOFFSET` — horizontal scroll in pixels. Restored
    /// directly via `SCI_SETXOFFSET`.
    x_offset: isize,
}

impl Win32Ui {
    /// UDL branch of `<Self as UiPlatform>::apply_lang` — set
    /// container-lexer mode, apply the UDL's own style palette,
    /// and immediately paint the whole buffer via the m1c-2
    /// tokeniser. Inherent (not-a-trait-method) so the trait
    /// impl stays focused on Lexilla-lexer routing; UDL is a
    /// different enough dispatch shape (no lexer name, host-side
    /// styling) that co-mingling the two branches would obscure
    /// both.
    ///
    /// Registry lookup runs through `state_from_hwnd(main_hwnd)`
    /// because `Win32Ui` doesn't hold a Shell reference — the
    /// main HWND is derived via `GetParent(self.tab_hwnd)`, the
    /// same pattern `apply_default_style` uses for its
    /// `WindowState` access. If the registry doesn't contain the
    /// requested id (shouldn't happen — Shell only hands out ids
    /// it registered — but defensive), or `GetParent` returns
    /// null (impossible by construction), fall through to plain
    /// text.
    fn apply_udl_lang(&mut self, lang: LangType) {
        // Read the UDL from the pre-populated raw pointer rather
        // than reaching back through `state_from_hwnd` — that
        // would produce a second `&WindowState` overlapping with
        // the outer callers' `&mut WindowState` borrow (aliasing
        // UB in `handle_close_active_tab_inner`,
        // `handle_tab_selchange`, `handle_style_config_menu`).
        // The registry is populated once at `Shell::new` and
        // read-only from here.
        //
        // SAFETY: `self.udl_registry` was captured from
        // `WindowState.shell.udl_registry` at Win32Ui
        // construction. `WindowState` outlives `Win32Ui` (which
        // is Copy but only ever exists as a short-lived value
        // during dispatch), the registry is never mutated after
        // `Shell::new`, and we only take a shared reference
        // for the duration of the clone.
        // Clone only what we need: the style palette (Vec of 24
        // small structs) and the Arc of compiled rules (pointer
        // bump). Was `entry.definition.clone()` — that copied
        // hundreds of keyword strings on every language switch.
        // Both fields survive the registry borrow ending here so
        // the block below can proceed without holding a live
        // `&UdlEntry`.
        let styles_and_rules = unsafe { &*self.udl_registry }
            .find_by_lang_type_id(lang.as_npp_id())
            .map(|entry| {
                (
                    entry.definition.styles.clone(),
                    std::sync::Arc::clone(&entry.compiled),
                )
            });
        let Some((styles, compiled_rules)) = styles_and_rules else {
            tracing::warn!(
                lang = lang.as_npp_id(),
                "UDL LangType not in registry; falling back to plain text"
            );
            self.editor.clear_lexer();
            apply_default_styles(&self.editor);
            self.editor.send(SCI_COLOURISE, 0, -1);
            return;
        };
        // Container-lexer mode: no Lexilla lexer attached. Every
        // subsequent `SCN_STYLENEEDED` on this document fires
        // through the WM_NOTIFY dispatch in `main_wnd_proc` and
        // routes to `udl_paint::paint_udl_range`.
        //
        // **Why the paint below is bounded rather than full-
        // document.** `clear_lexer()` doesn't reset Scintilla's
        // `endStyled` cursor (verified against
        // `vendor/scintilla/src/Document.cxx:65-67` —
        // `SCI_SETILEXER(0, 0)` swaps only the lexer pointer
        // and leaves `endStyled` alone). Without an explicit
        // paint the previously-Lexilla-styled bytes keep their
        // old style indices — which now point at the freshly-
        // cleared per-style palette we just installed above —
        // producing visually-empty styling for the whole
        // document until the user scrolls. So an initial
        // paint IS required.
        //
        // But full-document paint here would violate DESIGN.md
        // §8's UI-never-blocks constraint on the tens-of-MB
        // range. Instead we cap the synchronous initial paint
        // at [`INITIAL_PAINT_CAP`] bytes; the rest fills in
        // via `SCN_STYLENEEDED` as the user scrolls. 64 KiB
        // comfortably covers viewport-sized files AND the
        // visible window on multi-MB files, and the m1c-2
        // tokeniser is linear-time so this bounds the initial-
        // paint wall clock deterministically.
        self.editor.clear_lexer();
        apply_default_styles(&self.editor);
        udl_paint::apply_udl_styles(&self.editor, &styles);
        const INITIAL_PAINT_CAP: usize = 64 * 1024;
        let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
        let cap = doc_len.min(INITIAL_PAINT_CAP);
        // Align to end-of-line so the tokeniser doesn't see a
        // mid-line partial delimiter span at the cap.
        let end_line = self.editor.line_from_position(cap);
        let paint_end = self
            .editor
            .position_from_line(end_line + 1)
            .unwrap_or(doc_len)
            .min(doc_len);
        if paint_end > 0 {
            if let Some(bytes) = self.editor.get_range_bytes(0, paint_end) {
                udl_paint::paint_udl_range(&self.editor, &compiled_rules, 0, &bytes);
            }
        }
    }

    /// Capture every piece of view state that `SCI_SETDOCPOINTER`
    /// would wipe on the swap-back. See `ScintillaViewState`.
    fn snapshot_active_view(&self) -> ScintillaViewState {
        ScintillaViewState {
            caret: self.editor.send(SCI_GETCURRENTPOS, 0, 0),
            anchor: self.editor.send(SCI_GETANCHOR, 0, 0),
            top_line: self.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0),
            x_offset: self.editor.send(SCI_GETXOFFSET, 0, 0),
        }
    }

    /// Restore the snapshotted view state on the currently-bound
    /// document. Caller must have already swapped back to the
    /// document the snapshot belongs to. Selection is restored
    /// via `SCI_SETSEL`; vertical scroll via the delta between
    /// the now-zero `firstvisibleline` and the snapshotted one;
    /// horizontal scroll via `SCI_SETXOFFSET`.
    fn restore_active_view(&self, snap: ScintillaViewState) {
        // SCI_SETSEL takes (anchor, caret) in (wparam, lparam).
        self.editor
            .send(SCI_SETSEL, snap.anchor.max(0) as usize, snap.caret);
        let cur_top = self.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
        let delta = snap.top_line - cur_top;
        if delta != 0 {
            // SCI_LINESCROLL takes (column_delta, line_delta).
            self.editor.send(SCI_LINESCROLL, 0, delta);
        }
        self.editor
            .send(SCI_SETXOFFSET, snap.x_offset.max(0) as usize, 0);
    }
}

/// Visible width of a TAB character in units of one space, and
/// (via Scintilla's `SCI_SETINDENT = 0` default fall-through) the
/// effective indent-level width the indent-guide algorithm uses.
/// 4 matches the modern language convention (Rust / Python / TS
/// / JSON / YAML — every wired lexer with a canonical style guide
/// prescribes 4 spaces). Scintilla's own default is 8, which
/// mis-draws guides on 4-space-indented code: a function body at
/// column 4 sits before the first guide column at width=8, so
/// no guide appears at level 1. **Per-document Scintilla state**
/// (mutates `pdoc->tabInChars` per `vendor/scintilla/src/
/// Editor.cxx:7011-7015`), so [`apply_tab_width`] must fire at
/// every `SCI_CREATEDOCUMENT` site — same discipline as
/// [`enable_change_history`]. Per-language overrides (e.g.
/// Makefile → 8) are future work; when they land, the override
/// must repeat at every doc creation for the same reason.
const TAB_WIDTH_DEFAULT: usize = 4;

/// Background tint Scintilla paints behind the caret's line so the
/// user always sees which line is active. `0x00FAE8D6` is BGR for
/// RGB(214, 232, 250) — a soft pale blue that's clearly distinct
/// from [`BG_DEFAULT`] (white) without compromising the contrast of
/// black foreground text.
const BG_CARET_LINE: u32 = 0x00_FA_E8_D6;

/// Enable caret-line background highlighting and paint the active
/// line with [`BG_CARET_LINE`]. The visibility flag and back colour
/// are view state (not a style index), so unlike
/// [`apply_line_number_margin`] this does not need to be re-applied
/// after `SCI_STYLECLEARALL` — one call at editor creation is
/// enough.
fn apply_caret_line_highlight(editor: &EditorHandle) {
    editor.set_caret_line_back(BG_CARET_LINE);
    editor.set_caret_line_visible(true);
}

/// Margin index for the change-history strip — the narrow vertical
/// orange bar that flags lines edited since the last save. Skips
/// the conventionally-reserved indices (1 = symbols/bookmarks,
/// 2 = fold markers, 3 = future use) so a future plugin-installed
/// marker margin can't collide with it.
const CHANGE_HISTORY_MARGIN: u32 = 4;
/// Pixel width of [`CHANGE_HISTORY_MARGIN`] when populated. 4 px
/// is wide enough for a strip to read at every supported DPI
/// without competing with the line-number column to its left.
const CHANGE_HISTORY_MARGIN_PX: i32 = 4;
/// Marker bitmask for [`CHANGE_HISTORY_MARGIN`]. Includes only the
/// `SC_MARKNUM_HISTORY_MODIFIED` slot so a plugin marker assigned
/// to a different number can't bleed into the strip. Built as
/// `1 << SC_MARKNUM_HISTORY_MODIFIED`; the const-fn shape is
/// preferred over a raw literal so the relationship to the marker
/// number stays auditable.
const CHANGE_HISTORY_MARGIN_MASK: u32 = 1 << SC_MARKNUM_HISTORY_MODIFIED;
/// Stroke colour for the change-history strip — same Material
/// `orange 400` shade [`TAB_ACTIVE_INDICATOR`] uses for the
/// active-tab indicator. Reusing the colour ties the two
/// "you're editing this" cues into one visual language.
const CHANGE_HISTORY_COLOR: u32 = 0x00_26_A7_FF;

/// Configure the change-history margin: type, width, mask, and the
/// `SC_MARKNUM_HISTORY_MODIFIED` marker's symbol + colour. The
/// marker symbol is `SC_MARK_FULLRECT` so it fills the full margin
/// column for any line Scintilla flags as modified. The margin
/// settings are stored on the **view** (not the document), so this
/// one call is enough — surviving every `SCI_SETDOCPOINTER` cycle
/// the tab strip drives. Per-document change-history *enablement*
/// is a separate per-doc setting (see [`enable_change_history`]).
///
/// Critical detail: Scintilla's default mask for margin 1 is
/// `~SC_MASK_FOLDERS` — covering markers 0-24, which *includes*
/// the history-marker family at 21-24. With
/// `SC_CHANGE_HISTORY_MARKERS` enabled, every margin whose mask
/// matches the marker bit renders it. So without explicit cleanup,
/// the history strip would also render in margin 1 at margin 1's
/// width — visually a strip much wider than the 4-px slice we want.
/// Defensively clear margins 1-3's masks (and zero their widths in
/// case a Scintilla update bumps the default) so the strip is
/// confined to margin 4. A future bookmarks/folder-marker feature
/// claiming one of those indices will reconfigure both sides.
fn apply_change_history_margin(editor: &EditorHandle) {
    for unused in 1..=3u32 {
        editor.set_margin_mask(unused, 0);
        editor.set_margin_width(unused, 0);
    }
    // Silence the three sibling history markers we don't want to
    // visualise. Scintilla 5.x's `SC_CHANGE_HISTORY_MARKERS` flag
    // *auto-applies* every member of the family
    // (`REVERTED_TO_ORIGIN`, `SAVED`, `MODIFIED`,
    // `REVERTED_TO_MODIFIED`) to the lines they describe — and
    // each marker carries Scintilla's default symbol/colour until
    // overridden. In particular `SC_MARKNUM_HISTORY_SAVED` paints
    // a green line-background under every line that was modified
    // before the last save (i.e. essentially every line of the
    // file at first display, since the SCI_SETSAVEPOINT after
    // load reclassifies all inserted lines as "saved"). Setting
    // those three to `SC_MARK_EMPTY` makes them no-op visually
    // while preserving Scintilla's internal tracking, so a future
    // feature can light them up without re-enabling the history
    // engine.
    use codepp_scintilla_sys::{
        SC_MARKNUM_HISTORY_REVERTED_TO_MODIFIED, SC_MARKNUM_HISTORY_REVERTED_TO_ORIGIN,
        SC_MARKNUM_HISTORY_SAVED,
    };
    for silenced in [
        SC_MARKNUM_HISTORY_REVERTED_TO_ORIGIN,
        SC_MARKNUM_HISTORY_SAVED,
        SC_MARKNUM_HISTORY_REVERTED_TO_MODIFIED,
    ] {
        editor.marker_define(silenced, SC_MARK_EMPTY);
    }
    editor.set_margin_type(CHANGE_HISTORY_MARGIN, SC_MARGIN_SYMBOL);
    editor.set_margin_mask(CHANGE_HISTORY_MARGIN, CHANGE_HISTORY_MARGIN_MASK);
    editor.marker_define(SC_MARKNUM_HISTORY_MODIFIED, SC_MARK_FULLRECT);
    editor.marker_set_back(SC_MARKNUM_HISTORY_MODIFIED, CHANGE_HISTORY_COLOR);
    editor.set_margin_width(CHANGE_HISTORY_MARGIN, CHANGE_HISTORY_MARGIN_PX);
}

/// Enable Scintilla's change-history tracking on the **currently
/// bound** document. Per-document setting — every fresh document
/// minted via `SCI_CREATEDOCUMENT` starts with history disabled,
/// so this must be called on each new doc immediately after
/// binding it via `SCI_SETDOCPOINTER`. Margin configuration lives
/// on the view ([`apply_change_history_margin`]); only the
/// per-doc enablement is repeated here.
fn enable_change_history(editor: &EditorHandle) {
    editor.set_change_history(SC_CHANGE_HISTORY_ENABLED | SC_CHANGE_HISTORY_MARKERS);
}

// --- Fold margin colours + geometry ---------------------------------
//
// N++'s "Fold" and "Fold margin" entries in stylers.model.xml (verified
// against ScintillaEditView.cpp:3236-3245 and :4624-4640) apply the
// XML `bgColor` to the marker foreground and `fgColor` to the marker
// background — a deliberate swap. The effective palette:
//   - marker outline (fore): #F3F3F3 light grey
//   - marker fill (back):    #808080 mid grey
//   - marker active (hover): #FF0000 red (matches STYLE_BRACELIGHT)
//   - margin strip base:     #E9E9E9 near-white
//   - margin strip hover:    #FFFFFF pure white
// Encoded here as COLORREF (BBGGRR). Greys and white are palindromic.
const FOLD_MARKER_FG: u32 = 0x00_F3_F3_F3;
const FOLD_MARKER_BG: u32 = 0x00_80_80_80;
const FOLD_MARKER_ACTIVE: u32 = 0x00_00_00_FF;
const FOLD_MARGIN_BG: u32 = 0x00_E9_E9_E9;
const FOLD_MARGIN_HI: u32 = 0x00_FF_FF_FF;

/// Margin index for the fold column. Sits between the line-number
/// margin (index 0) and the change-history strip (index 4). N++
/// uses index 3, but Code++'s layout puts change-history at 4, not
/// between bookmark and fold — so fold lands at index 2.
const FOLD_MARGIN: u32 = 2;
/// Pixel width of [`FOLD_MARGIN`]. 14 px matches N++'s default.
const FOLD_MARGIN_PX: i32 = 14;

/// Map [`Eol`] to Scintilla's `SC_EOL_*` code and issue
/// `SCI_SETEOLMODE` on the currently-bound document. Sets the
/// byte sequence Scintilla inserts when the user presses Enter
/// (and the target sequence for a subsequent `SCI_CONVERTEOLS`).
///
/// **Per-document Scintilla state.** `SCI_SETEOLMODE` mutates
/// `pdoc->eolMode`, so every fresh document minted via
/// `SCI_CREATEDOCUMENT` starts at Scintilla's built-in default
/// (CRLF on Windows) regardless of the loaded file's actual EOL.
/// Called from [`Win32Ui::update_status`] on every tab switch
/// (which already receives the tab's authoritative `eol` from
/// the Shell layer), plus once at editor construction in
/// [`Win32Ui::run`] with [`Eol::default`] for the initial
/// implicit document.
///
/// **`Eol::Mixed` maps to LF.** Scintilla has no "mixed" mode —
/// the enum is a Code++-level bookkeeping construct for
/// "preserve each line's original ending on re-write." When the
/// user presses Enter in a Mixed buffer, LF is the least
/// surprising choice and matches [`Eol::bytes`]'s own Mixed
/// fall-through convention.
///
/// Without this call, Scintilla's built-in default of CRLF on
/// Windows applies universally — pressing Enter in a pure-LF
/// file silently starts injecting CRLF-terminated lines into an
/// otherwise LF file, breaking the EOL-preservation contract
/// documented in DESIGN.md §5.2.
fn apply_eol_mode(editor: &EditorHandle, eol: Eol) {
    let sc_eol = match eol {
        Eol::CrLf => SC_EOL_CRLF,
        Eol::Cr => SC_EOL_CR,
        // Mixed collapses to LF, matching `Eol::bytes()`'s own
        // convention for "preserve on re-write, but if we must
        // pick one here, use LF."
        Eol::Lf | Eol::Mixed => SC_EOL_LF,
    };
    editor.send(SCI_SETEOLMODE, sc_eol, 0);
}

/// Set the visible TAB-character width to [`TAB_WIDTH_DEFAULT`]
/// (4 columns) on the currently-bound document. Also implicitly
/// sets the effective indent-level width the indent-guide
/// algorithm uses, because Scintilla's per-document
/// `SCI_SETINDENT` defaults to 0 (which means "use tab width").
///
/// **Per-document Scintilla state.** `SCI_SETTABWIDTH` mutates
/// `pdoc->tabInChars` on the currently-bound document
/// (`vendor/scintilla/src/Editor.cxx:7011-7015`) and does NOT
/// survive `SCI_SETDOCPOINTER` onto a different document.
/// Every fresh document minted via `SCI_CREATEDOCUMENT` starts
/// with Scintilla's built-in `tabInChars = 8`, so this must be
/// called immediately after each such creation — same
/// discipline as [`enable_change_history`]. Currently called at
/// four sites: editor creation in [`Win32Ui::run`], and each of
/// the three real-doc `SCI_CREATEDOCUMENT` sites in
/// [`Win32Ui::activate_tab`], the post-close-tab lazy-materialise
/// path, and the `handle_tab_selchange` lazy-populate path. The
/// short-lived placeholder doc in the tab-close path
/// deliberately skips this call — the doc is bound for one
/// paint cycle and immediately released, and no indent-guide
/// paint on a blank buffer would be observable.
///
/// Without this call, Scintilla defaults to 8 and the
/// indent-guide algorithm draws guides at multiples of 8 —
/// which mis-aligns entirely with the 4-space convention used
/// by every Lexilla-linked lexer with a canonical style guide
/// (Rust / Python / TS / JSON / YAML): a function body at
/// column 4 sits *before* the first guide column (8), so no
/// guide appears at indent level 1, only at level 2. Per-
/// language overrides (e.g. Makefile → 8) are future work; when
/// they land, the same per-doc-repeat discipline applies.
fn apply_tab_width(editor: &EditorHandle) {
    editor.send(SCI_SETTABWIDTH, TAB_WIDTH_DEFAULT, 0);
}

/// Configure the fold margin's view state: allocate margin 2 as a
/// `SC_MASK_FOLDERS` symbol margin, define the BOXPLUS/BOXMINUS
/// shape family with CONNECTED variants for mid-region markers
/// (N++'s default "Box" style), set marker + margin-strip colours,
/// enable selected-marker highlighting, install the "draw
/// horizontal line below collapsed region" flag, and delegate
/// click / marker visibility / auto-expand-on-edit to Scintilla
/// via `SCI_SETAUTOMATICFOLD`.
///
/// **Must be called AFTER [`apply_change_history_margin`]** — that
/// function's defensive `set_margin_mask(1..=3, 0)` loop would
/// otherwise wipe [`FOLD_MARGIN`]'s mask right back to zero. The
/// call order at editor creation is
/// [`apply_change_history_margin`] → [`enable_change_history`] →
/// [`apply_fold_margin`].
///
/// The `fold` property itself is NOT set here — it lives on the
/// attached lexer instance (which doesn't exist yet at editor
/// creation) and, critically, does not carry across
/// `SCI_SETILEXER`: every fresh `CreateLexer` call in
/// [`Win32Ui::apply_lang`] mints a new instance whose
/// `options.fold` starts `false`. `LexState::PropSet` at
/// `ScintillaBase.cxx:687-694` is `if (instance) { … }` — a
/// silent no-op with no lexer bound. See
/// [`Win32Ui::apply_lang`] where the universal `fold` /
/// `fold.compact` / `fold.comment` trio is (re-)issued on every
/// language switch alongside the per-lexer extras.
fn apply_fold_margin(editor: &EditorHandle) {
    editor.set_margin_type(FOLD_MARGIN, SC_MARGIN_SYMBOL);
    editor.set_margin_mask(FOLD_MARGIN, SC_MASK_FOLDERS);
    editor.set_margin_sensitive(FOLD_MARGIN, true);
    editor.set_margin_width(FOLD_MARGIN, FOLD_MARGIN_PX);

    // Marker shapes — N++ default "Box" style, verified against
    // ScintillaEditView.cpp:4624-4640. The CONNECTED variants for
    // FOLDEREND / FOLDEROPENMID render the vertical continuation
    // line through the +/- glyph when nested inside a parent fold.
    for (marker, shape) in [
        (SC_MARKNUM_FOLDEROPEN, SC_MARK_BOXMINUS),
        (SC_MARKNUM_FOLDER, SC_MARK_BOXPLUS),
        (SC_MARKNUM_FOLDERSUB, SC_MARK_VLINE),
        (SC_MARKNUM_FOLDERTAIL, SC_MARK_LCORNER),
        (SC_MARKNUM_FOLDEREND, SC_MARK_BOXPLUSCONNECTED),
        (SC_MARKNUM_FOLDEROPENMID, SC_MARK_BOXMINUSCONNECTED),
        (SC_MARKNUM_FOLDERMIDTAIL, SC_MARK_TCORNER),
    ] {
        editor.marker_define(marker, shape);
        editor.marker_set_fore(marker, FOLD_MARKER_FG);
        editor.marker_set_back(marker, FOLD_MARKER_BG);
        editor.marker_set_back_selected(marker, FOLD_MARKER_ACTIVE);
    }
    editor.marker_enable_highlight(true);

    editor.set_fold_margin_colour(true, FOLD_MARGIN_BG);
    editor.set_fold_margin_hi_colour(true, FOLD_MARGIN_HI);

    // 0x10 = SC_FOLDFLAG_LINEAFTER_CONTRACTED — draws the horizontal
    // rule below a collapsed region so the user always sees a
    // "you-collapsed-a-region-here" cue.
    editor.set_fold_flags(SC_FOLDFLAG_LINEAFTER_CONTRACTED);

    // Vanilla click-to-toggle + marker visibility + auto-expand on
    // edit. Shift/Ctrl-click extensions (fold-all-children) would
    // require a manual SCN_MARGINCLICK handler; deferred.
    editor.set_automatic_fold(
        SC_AUTOMATICFOLD_SHOW | SC_AUTOMATICFOLD_CLICK | SC_AUTOMATICFOLD_CHANGE,
    );
}

/// Return `true` if `c` is one of the six ASCII bracket characters
/// that Scintilla's `SCI_BRACEMATCH` recognises: `()`, `[]`, `{}`,
/// `<>`. N++ matches without filtering by lexer (spurious `<>`
/// matches in non-HTML buffers are the exact N++ behaviour).
#[inline]
const fn is_brace(c: u8) -> bool {
    matches!(c, b'(' | b')' | b'[' | b']' | b'{' | b'}' | b'<' | b'>')
}

/// Dispatch brace-match highlight on the current caret position.
/// Called from the `SCN_UPDATEUI` handler on every selection or
/// content change. Total cost per call: 3-6 direct-call round-trips
/// (get pos, 2× get char, 0-1 `brace_match`, 1 highlight, 1 `bad_light`)
/// — sub-µs on the direct-call path, well inside the 5 ms p99
/// keystroke budget.
fn update_brace_highlight(editor: &EditorHandle) {
    let pos = editor.current_pos() as i64;
    let ch_before = if pos > 0 {
        editor.char_at((pos - 1) as u64)
    } else {
        0
    };
    let ch_at = editor.char_at(pos as u64);

    let brace_pos: i64 = if is_brace(ch_before) {
        pos - 1
    } else if is_brace(ch_at) {
        pos
    } else {
        -1
    };

    // SCI_BRACEHIGHLIGHT and SCI_BRACEBADLIGHT both write into Scintilla's
    // single shared `braces[2]` + `bracesMatchStyle` slot (Editor.cxx:8237,
    // 8248 → SetBraceHighlight at :5407-5423). If we call the "bad" clear
    // AFTER the "good" set, we wipe the state we just wrote and PaintText
    // never overwrites the brace's style byte to STYLE_BRACELIGHT
    // (PositionCache.cxx:219 gate `rangeLine.ContainsCharacter(braces[i])`
    // is false because braces[] is now [-1, -1]). Order: clear the opposite
    // state FIRST, then set the desired one.
    if brace_pos >= 0 {
        let match_pos = editor.brace_match(brace_pos as u64);
        if match_pos >= 0 {
            editor.brace_bad_light(-1);
            editor.brace_highlight(brace_pos, match_pos);
        } else {
            editor.brace_highlight(-1, -1);
            editor.brace_bad_light(brace_pos);
        }
    } else {
        editor.brace_bad_light(-1);
        editor.brace_highlight(-1, -1);
    }
}

/// Number of lines beyond the visible window's bottom edge to
/// pre-populate. A small overscan covers the gap between
/// `SCI_LINESONSCREEN`'s integer-truncated row count and a partial
/// line clipped by the viewport, plus one row of margin so a small
/// scroll doesn't reveal a blank line before the next
/// `SCN_UPDATEUI` lands.
const LINE_NUMBER_OVERSCAN: u64 = 4;

/// Number of decimal digits needed to render `line_count` (so a
/// 100-line buffer wants width `3`, a 99-line buffer wants `2`).
/// The width drives the right-alignment column for every visible
/// line number — when the file grows across a 9→10 / 99→100 /
/// etc. boundary, every visible row's text shifts one column
/// right in lockstep, so 3-digit "100" lines up over the 2-digit
/// "99" with their last digits in the same column.
fn line_number_width(line_count: u64) -> usize {
    let mut digits: usize = 1;
    let mut n = line_count.max(1);
    while n >= 10 {
        digits += 1;
        n /= 10;
    }
    digits
}

/// Write per-line line-number text for lines `[start, end)` into
/// the `LINE_NUMBER_MARGIN` of the currently-bound document, styled
/// as `STYLE_LINENUMBER`. Format is `" {N+1:>width$}"` — a fixed
/// 1-char left pad followed by the line number right-aligned in a
/// `width`-char column, so the rightmost digit of every line falls
/// on the same column. `width` is supplied by the caller (always
/// from [`line_number_width`] of the current document line count)
/// rather than computed per-line so the value is stable across the
/// whole batch.
fn populate_line_numbers_range(editor: &EditorHandle, start: u64, end: u64, width: usize) {
    if start >= end {
        return;
    }
    // Per-call scratch buffer: leading space + right-aligned
    // digits + NUL. `u64` tops out at 20 digits; `" "` + 20 + `\0`
    // = 22 bytes. 32 covers it without a heap alloc.
    let mut buf = [0u8; 32];
    for line in start..end {
        use std::io::Write;
        // `cursor` is re-bound on each iteration, so `write!`
        // always begins at `buf[0]` — `Write for &mut [u8]`
        // advances `cursor` (the slice header) but never `buf`
        // itself, so `buf.as_ptr()` keeps pointing at the bytes
        // we just wrote. Trailing bytes from the previous
        // iteration are harmless: Scintilla reads up to the NUL
        // we wrote and stops.
        let mut cursor = &mut buf[..];
        // " " + {N+1, right-aligned to `width`} + "\0". Line
        // indices are 0-based in Scintilla, 1-based for the user.
        write!(cursor, " {:>width$}\0", line + 1, width = width)
            .expect("32-byte scratch buffer exhausted formatting line number");
        // `line as usize` is sound on every supported target:
        // Scintilla's 2 GiB buffer ceiling caps line count at ~2
        // billion (one byte per line) on 32-bit and 64-bit alike,
        // well within `u32::MAX` and therefore `usize::MAX`.
        editor.send(SCI_MARGINSETTEXT, line as usize, buf.as_ptr() as isize);
        editor.send(SCI_MARGINSETSTYLE, line as usize, STYLE_LINENUMBER as isize);
    }
}

/// Populate line-number text for the lines currently visible in
/// the viewport (plus a small overscan). Cheap and bounded —
/// scales with viewport height, not file size, so a 100k-line
/// file load doesn't stall the UI thread.
///
/// Width is derived from the *total* document line count, not just
/// the visible range. This way the rightmost digit always falls in
/// the same column for every line in the document — when the file
/// grows past a boundary (e.g. 99 → 100) the next call here shifts
/// every visible line one column right uniformly, instead of
/// leaving the visible window with a mix of widths.
///
/// Off-screen lines stay with whatever margin text they last had
/// (typically empty for newly-created lines, or numbers laid out
/// at a stale width from before the latest line-count change).
/// Either is invisible to the user; the `SCN_UPDATEUI` vertical-
/// scroll hook re-populates the new visible window with the
/// current width just before those lines enter the viewport.
///
/// Margin text is per-document state in Scintilla, so this is the
/// right level of write — it survives `SCI_SETDOCPOINTER` cycles
/// and only needs re-running when content changes or the visible
/// range shifts.
/// Populate every line in the document with its margin number.
/// Bounded by document line count, not viewport — used after a
/// bulk content replace (`SCI_SETTEXT` in `set_buffer_text`)
/// when the visible-only populate would miss off-screen lines.
///
/// Cost: ~2 direct-call invocations per line. For typical
/// untitled buffers (a few hundred lines) this is sub-millisecond;
/// for a 100k-line file it's around 100 ms — acceptable on a
/// once-per-load operation. The lazy `SCN_UPDATEUI`-driven path
/// is still the right choice for incremental edits.
///
/// Used specifically because session-restore calls
/// `set_buffer_text` *before* the window has been laid out, so
/// `SCI_LINESONSCREEN` returns 0 / 1 and the visible-only
/// populate covers only the first few lines — leaving the rest
/// blank (or worse, with stale margin text from the previous
/// doc state, e.g. line 0's "1" from `activate_tab`'s populate
/// of the empty starter doc).
fn populate_all_line_numbers(editor: &EditorHandle) {
    let total = editor.send(SCI_GETLINECOUNT, 0, 0).max(1) as u64;
    let width = line_number_width(total);
    populate_line_numbers_range(editor, 0, total, width);
}

fn populate_visible_line_numbers(editor: &EditorHandle) {
    // Scintilla guarantees `SCI_GETLINECOUNT >= 1` for any document
    // (an empty document still has line 0); clamp to 1 so the
    // formatting code downstream — and `line_number_width` —
    // always sees a sensible floor instead of relying on the
    // invariant implicitly.
    let total = editor.send(SCI_GETLINECOUNT, 0, 0).max(1) as u64;
    let first = editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0) as u64;
    let on_screen = editor.send(SCI_LINESONSCREEN, 0, 0).max(0) as u64;
    let last = first
        .saturating_add(on_screen)
        .saturating_add(LINE_NUMBER_OVERSCAN)
        .min(total);
    let width = line_number_width(total);
    populate_line_numbers_range(editor, first.min(total), last, width);
}

/// Bring the caret line into view: if it's already in the visible
/// region just leave the viewport alone (Notepad++ style — quiet
/// on small jumps), otherwise scroll so the caret line lands at
/// the centre of the viewport. Used after Find Next / Find
/// Previous so the user sees the new selection without the view
/// snapping to the bottom edge.
///
/// Note: line numbers here are document lines, which equal visual
/// lines while we're not running with folding or word wrap on.
/// If those land later, swap to `SCI_VISIBLEFROMDOCLINE` for the
/// match-line conversion.
fn center_caret_if_offscreen(editor: &EditorHandle) {
    center_caret_impl(editor, false);
}

/// Unconditionally center the caret line in the viewport.
///
/// Use this after Scintilla messages that auto-scroll (`SCI_SETSEL`,
/// `SCI_SETSELECTIONSTART/END`, `SCI_GOTOPOS`), where
/// [`center_caret_if_offscreen`] would short-circuit because the
/// preceding command already pulled the line on-screen at the
/// nearest edge. Find Next uses `SCI_SEARCHNEXT` which doesn't
/// scroll, so its centring helper can rely on the offscreen check;
/// the FIF "open at result" jump uses `SCI_SETSEL` and needs the
/// re-scroll to land the match in the middle of the editor — even
/// more important when the bottom dock is showing and the editor's
/// usable height is reduced.
fn center_caret(editor: &EditorHandle) {
    center_caret_impl(editor, true);
}

/// Shared centring math. With `force = false` we early-return if
/// the caret line is already on-screen (Find Next behaviour: don't
/// jump the viewport on every successful match); with `force = true`
/// we always re-scroll (FIF dblclk behaviour: `SCI_SETSEL` has just
/// pulled the line edge-visible, so "already on-screen" means "at
/// the bottom edge under the dock" — which is what we're trying to
/// avoid).
fn center_caret_impl(editor: &EditorHandle, force: bool) {
    let pos = editor.send(SCI_GETCURRENTPOS, 0, 0).max(0) as usize;
    let line = editor.send(SCI_LINEFROMPOSITION, pos, 0).max(0);
    let first = editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0);
    let lines = editor.send(SCI_LINESONSCREEN, 0, 0).max(1);
    if !force && line >= first && line < first + lines {
        return;
    }
    let target_first = (line - lines / 2).max(0);
    let delta = target_first - first;
    if delta != 0 {
        editor.send(SCI_LINESCROLL, 0, delta);
    }
}

/// Convert `(r, g, b)` (display order) to a Win32 `COLORREF`
/// (`0x00BBGGRR`). The same packing Scintilla expects for its
/// style colour messages.
fn rgb_to_colorref((r, g, b): (u8, u8, u8)) -> u32 {
    (u32::from(b) << 16) | (u32::from(g) << 8) | u32::from(r)
}

/// Apply the user's transparency settings to the main window.
///
/// Enabling transparency:
///   - Adds `WS_EX_LAYERED` to the window's extended style
///     (required for `SetLayeredWindowAttributes`).
///   - Converts opacity-percent (20..=100) to an 8-bit alpha
///     value: `255 * percent / 100`.
///   - Issues `SetLayeredWindowAttributes(..., alpha, LWA_ALPHA)`.
///
/// Disabling transparency:
///   - Strips `WS_EX_LAYERED` so the window stops paying the
///     compositing cost. A no-op when the bit wasn't set (e.g.
///     first call at startup with `enabled=false`).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn apply_window_transparency(hwnd: HWND, t: &codepp_core::styles::Transparency) {
    // Keep the extended-style word in `isize` throughout to
    // avoid a u32 narrowing of `GetWindowLongPtrW`'s 64-bit
    // return value on 64-bit Windows. Win32 currently fits
    // every extended style bit into the low 32 bits, but the
    // signature is `isize` and the rest of this codebase (e.g.
    // the Scintilla border-style toggle around line 1694)
    // already follows the keep-it-signed pattern.
    let cur_ex = unsafe { GetWindowLongPtrW(hwnd, GWL_EXSTYLE) };
    let layered = WS_EX_LAYERED.0 as isize;
    if t.enabled {
        let want_ex = cur_ex | layered;
        if want_ex != cur_ex {
            unsafe {
                SetWindowLongPtrW(hwnd, GWL_EXSTYLE, want_ex);
            }
        }
        // Clamp percent into the documented 20..=100 range. The
        // dialog's slider enforces the same bounds, but a
        // hand-edited styles.xml could carry anything; treating
        // out-of-range values as "snap to the nearest endpoint"
        // is the safest graceful-degradation choice (the
        // alternative for values below 20 would be the editor
        // becoming barely-visible or invisible). The trace below
        // makes the snap observable so a debugger / log reader
        // can tell that the on-disk value didn't survive verbatim.
        if !(20..=100).contains(&t.percent) {
            tracing::warn!(
                percent = t.percent,
                "transparency percent outside 20..=100; clamping"
            );
        }
        let percent = u32::from(t.percent.clamp(20, 100));
        let alpha = ((255u32 * percent) / 100) as u8;
        let _ = unsafe { SetLayeredWindowAttributes(hwnd, COLORREF(0), alpha, LWA_ALPHA) };
    } else {
        let want_ex = cur_ex & !layered;
        if want_ex != cur_ex {
            unsafe {
                SetWindowLongPtrW(hwnd, GWL_EXSTYLE, want_ex);
            }
        }
    }
}

/// Fire every queued NPPN_* notification through `Shell::notify_plugins`,
/// each call wrapped in `PluginCallGuard` (re-entrance guard) and
/// `catch_unwind` (host-internal panics must not unwind across the
/// `extern "system"` `wnd_proc` frame).
///
/// Each notification grabs a fresh `&mut WindowState` borrow, calls
/// `notify_plugins` (which iterates plugins through `&Shell`), then
/// drops the borrow before the next iteration. A plugin's beNotified
/// that `SendMessage(NPPM_*)`s back hits `state_from_hwnd → None`
/// while the guard is set; the inner `wnd_proc` returns 0 and the
/// outer borrow stays sound.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn fire_queued_notifications(hwnd: HWND) {
    // Drain the queue under one borrow, then release before
    // calling into plugin code — `take_notifications` only needs
    // `&mut Shell` for the swap, no plugin code runs inside it.
    // SAFETY: caller's contract requires UI-thread invocation;
    // state_from_hwnd's own contract is satisfied there.
    let notifications = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.take_notifications()
    } else {
        Vec::new()
    };
    if notifications.is_empty() {
        return;
    }
    for notification in notifications {
        // SAFETY: same as above; UI-thread call.
        if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
            // The guard is created INSIDE the catch_unwind closure
            // so that a panic from `PluginCallGuard::enter()` (the
            // nesting-detection assert) is caught here rather than
            // unwinding across the extern "system" wnd_proc frame.
            // The guard's Drop runs when the closure exits (panic
            // or normal return), tightly scoping
            // PLUGIN_CALL_ACTIVE to the plugin call.
            let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                let _guard = PluginCallGuard::enter();
                state.shell.notify_plugins(notification, hwnd.0);
            }));
        }
        // Borrow on `state` ends at the end of each iteration so
        // the next iteration acquires fresh.
    }
}

/// Close the active tab in response to `WM_COMMAND(ID_FILE_CLOSE)`
/// (Ctrl+W accelerator, File → Close menu item, or future
/// right-click → Close). Drives the platform-side cleanup the
/// shell-side `close_active_tab` doesn't know about: removes the
/// item from the tab control, releases the closed document via
/// `SCI_RELEASEDOCUMENT` (drops Scintilla's last refcount on the
/// buffer so memory is freed), and rebinds the view to the new
/// active document if there is one. Closing the last tab leaves
/// the view bound to a fresh empty document until the next
/// `open_file`.
///
/// Notifications (`NPPN_FILECLOSED` + possibly
/// `NPPN_BUFFERACTIVATED`) are queued by the shell-side close;
/// we deliver them via `fire_queued_notifications` after the
/// borrow ends, so plugin `beNotified` callbacks see a fully
/// quiesced state.
///
/// The function body is wrapped in `catch_unwind` so a host-
/// internal panic (allocation failure inside `Vec::push` or
/// `String::clone`, a misbehaving `tracing` subscriber, the
/// `allocate_buffer_id` overflow assert) doesn't unwind across
/// the `extern "system"` `wnd_proc` frame — that's UB. Plugin
/// code never runs here, so the wrap is purely a defense
/// against host-internal panics.
///
/// Outcome of one close-active-tab attempt — drives the
/// Close-All loop's continue-vs-break decision.
///
///   * `Closed` — the active tab was successfully removed.
///   * `NothingToClose` — there was no active tab to begin
///     with (workspace was empty), or `state_from_hwnd`
///     returned `None` (re-entrant plugin call active).
///   * `Aborted` — the close did not happen because the user
///     dismissed the save-confirm dialog with Cancel, OR
///     because the Save / Save-As path failed (and the
///     error dialog was shown). In a Close-All context this
///     means "stop the loop": closing the next tab is not
///     what the user asked for after they aborted this one.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CloseOutcome {
    Closed,
    NothingToClose,
    Aborted,
}

/// Which subset of tabs the [`close_multiple_documents`] loop
/// should close. Every variant reuses the single-tab close path
/// (dirty-check prompt + Cancel short-circuit), so the user's
/// choices on individual dirty buffers are honoured exactly as
/// they are for `File → Close All`.
// The shared `All` prefix on every variant mirrors the user-facing
// menu labels ("Close All but Active", "Close All to the Left",
// …). Renaming to drop the prefix would only replace one context
// (this enum) with another (a `use CloseMultiKind::*` glob at
// every call site), so silence the pedantic lint.
#[allow(clippy::enum_variant_names)]
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
enum CloseMultiKind {
    /// Every tab except the one that was active when the loop
    /// started. If the active tab is unpinned it stays open;
    /// pinned/unpinned status is irrelevant for this variant.
    AllButActive,
    /// Every tab that is NOT pinned. Pinned tabs stay. The
    /// active tab may or may not survive depending on whether
    /// it's pinned.
    AllButPinned,
    /// Every tab whose current index is < the active tab's
    /// index (i.e. to the left of it in the tab strip).
    AllToLeft,
    /// Every tab whose current index is > the active tab's
    /// index. Everything to the right of the active tab.
    AllToRight,
    /// Every tab that is not dirty (no unsaved changes). Uses
    /// the cached `Tab.dirty` flag which mirrors Scintilla's
    /// `SCI_GETMODIFY` and is maintained by `SCN_SAVEPOINTREACHED`
    /// / `SCN_SAVEPOINTLEFT` — so this is O(n) with no
    /// doc-pointer-swap dance. The active tab is closed too if
    /// it happens to be clean.
    AllUnchanged,
}

/// Close every tab that matches the `kind` predicate. Reuses the
/// single-tab close path per iteration so dirty prompts +
/// Cancel-shortcircuits behave identically to Ctrl+W. Bounds
/// the iteration count by the initial tabs length so a
/// misbehaving close path can't hang the app.
///
/// Loop invariant:
///   * Snapshot the active tab id (the "keeper" for the
///     "All but Active" / "All to the Left" / "All to the
///     Right" variants) BEFORE entering the loop, because
///     activating a target tab mid-loop shifts
///     `shell.active_tab` and picking a fresh keeper on every
///     tick would collapse the loop to a no-op (each iteration
///     would try to skip whichever tab we just activated).
///   * Each iteration: pick the next target tab by
///     `pick_next_target(shell, kind, keeper_id)`; if `None`,
///     we're done. Else activate + close.
///   * `handle_close_active_tab_with_outcome` returns
///     `Aborted` on Cancel or `NothingToClose` when
///     `state_from_hwnd` returns `None` (re-entrant plugin
///     call). Either breaks the loop.
///
/// `ensure_one_tab` is called at the end only if the workspace
/// is empty. All five variants can potentially drain the strip
/// (Close All Unchanged if every tab is clean; Close All but
/// Pinned if none are pinned; etc.), and we don't want to leave
/// the user staring at an empty editor.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn close_multiple_documents(hwnd: HWND, kind: CloseMultiKind) {
    // Snapshot the keeper id + initial tab count under one
    // brief borrow, then drop it before the loop — each
    // iteration re-acquires the borrow inside its own scope.
    //
    // No active tab → return early instead of falling back to a
    // synthetic id: three of the five variants (AllButActive,
    // AllToLeft, AllToRight) are meaningless without a keeper,
    // and a fallback of `0` would silently protect any tab that
    // happens to have that id from being closed. `refresh_file_menu`
    // greys every entry when `active_tab.is_none()`, but a
    // plugin-forged `WM_COMMAND` bypasses that greying and would
    // reach this helper — the early return is the security /
    // correctness gate.
    let (keeper_id, initial_count) = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        let Some(active) = state.shell.active() else {
            return;
        };
        (active.id, state.shell.tabs.len())
    } else {
        return;
    };
    if initial_count == 0 {
        return;
    }
    for _ in 0..initial_count {
        // Pick the next target index under a fresh borrow.
        let next_idx = unsafe { state_from_hwnd(hwnd) }
            .and_then(|state| pick_next_close_target(&state.shell.tabs, kind, keeper_id));
        let Some(idx) = next_idx else {
            break; // No more targets — done.
        };
        // Activate the target tab if it isn't already the
        // active one — `handle_close_active_tab_inner` reads
        // `SCI_GETMODIFY` off the currently-bound Scintilla
        // document and pops the save prompt for THAT document,
        // so the target must be the bound one before we close.
        let active_now = unsafe { state_from_hwnd(hwnd) }.and_then(|s| s.shell.active_tab);
        if active_now != Some(idx) {
            unsafe { handle_window_menu_click(hwnd, idx) };
        }
        match unsafe { handle_close_active_tab_with_outcome(hwnd) } {
            CloseOutcome::Closed => {}
            // Aborted (Cancel or Save failure) OR NothingToClose
            // (re-entrant plugin call blocking state access):
            // stop the loop. Tabs that have already been closed
            // stay closed; the user committed to those decisions.
            CloseOutcome::Aborted | CloseOutcome::NothingToClose => break,
        }
    }
    // If the loop drained the strip (Close All Unchanged with
    // all-clean tabs; Close All but Pinned with none pinned;
    // …), restore the "always at least one tab" invariant.
    let empty = unsafe { state_from_hwnd(hwnd) }.is_some_and(|s| s.shell.tabs.is_empty());
    if empty {
        unsafe { ensure_one_tab(hwnd) };
    }
    unsafe {
        fire_queued_notifications(hwnd);
    }
}

/// Pick the vector index of the next tab to close for `kind`,
/// or `None` if no candidate remains. `keeper_id` is the tab id
/// that must survive for the "All but Active" / "All to the
/// Left / Right" variants — captured once at the loop's start
/// so mid-loop activations don't shift the reference point.
///
/// This is a pure inspector on `Shell`; no mutation, no I/O,
/// no borrow smell. Called once per iteration of the outer
/// close loop.
fn pick_next_close_target(
    tabs: &[codepp_shell::Tab],
    kind: CloseMultiKind,
    keeper_id: i32,
) -> Option<usize> {
    // Never touch a tab whose async load is still in flight.
    // **Data-loss safeguard.** A pending-load tab has no
    // user edits (the user hasn't even seen the file yet);
    // activating it via `handle_window_menu_click` triggers
    // `handle_tab_selchange`'s lazy-populate branch which
    // binds the editor to a freshly-created EMPTY Scintilla
    // document seeded from the empty `tab.text`. Closing that
    // through the standard save-modal path can produce a
    // "Save changes to X.txt?" prompt for a file the user
    // hasn't opened — and a Yes click there writes 0 bytes
    // over the real file on disk. Skipping pending-load tabs
    // at target-selection time makes them unreachable by this
    // bulk-close code path, closing the hazard by design —
    // same discipline `Shell::save_all` uses at its own
    // iteration site. Users can still close a still-loading
    // tab with Ctrl+W once the load completes.
    let is_closable = |t: &codepp_shell::Tab| t.pending_load.is_none();
    match kind {
        CloseMultiKind::AllButActive => tabs
            .iter()
            .position(|t| t.id != keeper_id && is_closable(t)),
        CloseMultiKind::AllButPinned => tabs.iter().position(|t| !t.pinned && is_closable(t)),
        CloseMultiKind::AllToLeft => {
            // Find the keeper's position; then scan the [0, keeper)
            // prefix for the first closable tab. Returns the
            // absolute index (positions inside a slice starting at
            // 0 are already absolute for the base vector).
            let keeper_pos = tabs.iter().position(|t| t.id == keeper_id)?;
            tabs[..keeper_pos].iter().position(is_closable)
        }
        CloseMultiKind::AllToRight => {
            // Symmetric to AllToLeft on the (keeper, end) suffix.
            // `position` returns a relative index; add `keeper_pos
            // + 1` to convert back to an absolute vector index.
            let keeper_pos = tabs.iter().position(|t| t.id == keeper_id)?;
            tabs[keeper_pos + 1..]
                .iter()
                .position(is_closable)
                .map(|rel| keeper_pos + 1 + rel)
        }
        CloseMultiKind::AllUnchanged => tabs.iter().position(|t| !t.dirty && is_closable(t)),
    }
}

/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab(hwnd: HWND) {
    // Single-tab close discards the outcome — Ctrl+W / File→Close
    // / future right-click → Close don't need to know whether the
    // user cancelled. Close-All uses the with-outcome variant.
    //
    // SAFETY: caller's UI-thread contract carries.
    let _ = unsafe { handle_close_active_tab_with_outcome(hwnd) };
}

/// Same close-active-tab flow as [`handle_close_active_tab`],
/// but returns the [`CloseOutcome`] so the Close-All loop can
/// stop on `Aborted` instead of re-prompting the same tab on
/// every iteration.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab_with_outcome(hwnd: HWND) -> CloseOutcome {
    // The `catch_unwind` wraps the inner so a host-internal
    // panic (allocation failure, tracing-subscriber misbehaviour,
    // ...) doesn't unwind across the `extern "system"` wnd_proc
    // frame. On a caught panic we report `Aborted` so a
    // Close-All loop stops rather than spinning on a poisoned
    // close path.
    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        // SAFETY: caller's UI-thread contract carries.
        unsafe { handle_close_active_tab_inner(hwnd) }
    }))
    .unwrap_or(CloseOutcome::Aborted)
}

/// Body of [`handle_close_active_tab_with_outcome`], factored
/// out so the caller can wrap it in a single `catch_unwind`.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab_inner(hwnd: HWND) -> CloseOutcome {
    // Phase 0: dirty-check gate. If the active tab's buffer has
    // unsaved changes, prompt the user with Save / Don't Save /
    // Cancel before any data-model mutation. Cancel aborts the
    // entire close — the buffer stays open.
    //
    // Empty-untitled exception: a brand-new untitled tab the user
    // typed-then-erased still reports SCI_GETMODIFY non-zero (the
    // savepoint never moved past the initial empty state), but
    // there's nothing meaningful to save — asking "Save 'new 1' ?"
    // for a buffer with zero characters is friction, not safety.
    // The exception is scoped to `!has_path` so titled files are
    // not affected: a "Select All + Delete + close" on a path-bound
    // tab still prompts, letting the user explicitly choose between
    // truncate-and-save and discard.
    //
    // We sample (display name, has_path, dirty, length) under a
    // brief read-only borrow, drop it before the modal pump runs
    // (the borrow can't outlive the modal — the Win32 message
    // pump re-enters our wnd_proc, which would alias-UB the
    // `WindowState`), then act on the user's choice.
    //
    // `dirty` OR's the live `SCI_GETMODIFY` bit against the cached
    // `Tab.dirty` from Shell. The two agree for the active tab in
    // normal operation (kept in sync by SCN_SAVEPOINT* notifications),
    // but diverge in the "file removed externally, tab still open"
    // case: Shell flips `Tab.dirty = true` in `apply_file_change`
    // whether the underlying Scintilla doc has been touched or not,
    // so the close-prompt gate here still fires and closing the
    // tab doesn't silently discard the only surviving copy of the
    // buffer text.
    let prelude = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.active().map(|tab| {
            let name = tab_display_name(tab);
            let has_path = tab.path.is_some();
            let has_pending_load = tab.pending_load.is_some();
            let cached_dirty = tab.dirty;
            let dirty = state.editor.send(SCI_GETMODIFY, 0, 0) != 0 || cached_dirty;
            let length = state.editor.send(SCI_GETLENGTH, 0, 0);
            (name, has_path, has_pending_load, dirty, length)
        })
    } else {
        return CloseOutcome::NothingToClose;
    };
    let Some((display_name, has_path, has_pending_load, dirty, length)) = prelude else {
        return CloseOutcome::NothingToClose;
    };
    // **Data-loss safeguard.** A tab whose async load is still
    // in flight has no user edits — the user hasn't even seen
    // the file yet. Any "dirty" state on such a tab's
    // Scintilla document reflects a lazy-populate from an
    // empty `tab.text` (see `handle_tab_selchange`'s
    // lazy-populate branch), not a user modification. Surfacing
    // the "Save changes to X?" modal here would ask the user
    // to sign off on writing an empty buffer over their real
    // file on disk — a catastrophic outcome if the click lands
    // on Yes. Treat pending-load tabs as clean unconditionally
    // so the modal never surfaces; the tab is discarded on close
    // exactly as `SaveConfirmResult::No` would have done. Matches
    // the discipline `Shell::save_all` uses on its own iteration
    // path (`pending_load.is_some()` skips the tab there too).
    if dirty && !has_pending_load && (has_path || length > 0) {
        match show_save_confirm_dialog(hwnd, &display_name) {
            SaveConfirmResult::Cancel => return CloseOutcome::Aborted,
            SaveConfirmResult::No => {
                // Proceed to the close without saving. The
                // buffer's edits are discarded with the doc
                // when SCI_RELEASEDOCUMENT runs in Phase 2.
            }
            SaveConfirmResult::Yes => {
                // `has_path` was sampled BEFORE the confirm
                // modal ran. The modal's nested message pump
                // can dispatch WM_APP_WAKE (which drains
                // shell-level deferred work), but no current
                // code path clears an already-set `tab.path`
                // back to `None` — the invariant holds. If a
                // future code path could break it,
                // `save_current_to_disk` returns
                // `ShellError::NoActivePath` and the error
                // dialog below surfaces it; the worst case is
                // a confusing "Save failed: no active file
                // path" message, not silent data loss.
                if has_path {
                    // Titled tab — save in place. On error,
                    // surface the message and abort the close;
                    // silently dropping the buffer when save
                    // failed is the worst possible outcome.
                    //
                    // `state_from_hwnd` returns `None` when
                    // `PLUGIN_CALL_ACTIVE` is set — i.e. a
                    // plugin's `beNotified` is on the stack
                    // and re-entered our wnd_proc. That path is
                    // currently unreachable here (the modal
                    // pump can dispatch plugin notifications,
                    // but the guard is dropped before the
                    // modal returns), but the early return is
                    // the safe behaviour either way: aborting
                    // the close is better than mutating
                    // `WindowState` while a plugin call is
                    // alive.
                    let save_error = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
                        let (shell, mut ui) = state.split();
                        match shell.save_current_to_disk(&mut ui) {
                            Ok(()) => None,
                            Err(e) => Some(e.to_string()),
                        }
                    } else {
                        return CloseOutcome::Aborted;
                    };
                    if let Some(msg) = save_error {
                        show_error_dialog(hwnd, "Save failed", &msg);
                        return CloseOutcome::Aborted;
                    }
                } else {
                    // Untitled tab — route through the Save As
                    // dialog. `run_save_as_flow` shows its own
                    // error dialog on failure (so we don't
                    // double-prompt) and updates the tab's path
                    // on success. After it returns, re-read
                    // the dirty bit: if the user cancelled the
                    // GetSaveFileNameW dialog or the save
                    // itself failed, the buffer is still dirty
                    // and we must abort the close.
                    unsafe { run_save_as_flow(hwnd) };
                    let still_dirty = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
                        state.editor.send(SCI_GETMODIFY, 0, 0) != 0
                    } else {
                        return CloseOutcome::Aborted;
                    };
                    if still_dirty {
                        return CloseOutcome::Aborted;
                    }
                }
            }
        }
    }

    // Phase 1: ask the shell to do its half. We hold a brief
    // `&mut WindowState` borrow only for the duration of this
    // call — `close_active_tab` is pure data-model work plus an
    // unwatch, no plugin code runs inside it.
    let closed = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.close_active_tab()
    } else {
        return CloseOutcome::NothingToClose;
    };
    let Some(closed) = closed else {
        return CloseOutcome::NothingToClose;
    };

    // Defense in depth: a refactor that ever produced
    // `closed.scintilla_doc == closed.new_active_doc` (e.g. a
    // future "reload in place" path that reuses the existing
    // doc) would have us release the view's only ref to the
    // doc before the rebind — UAF. Catch it as an assert in
    // debug builds; release builds rely on the structural
    // guarantee that `SCI_CREATEDOCUMENT` returns unique pointers.
    if closed.scintilla_doc != 0 && closed.new_active_doc != 0 {
        debug_assert_ne!(
            closed.scintilla_doc, closed.new_active_doc,
            "closed and new-active doc pointers must be distinct"
        );
    }

    // Phase 2: platform cleanup. Re-acquire the borrow; no plugin
    // code runs in this phase either (TCM_*, SCI_* are all
    // synchronous and don't re-enter our wnd_proc).
    if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        // Nuclear-resync the visible strip: delete every item the
        // tab control holds and re-insert from `state.shell.tabs`.
        // This is heavier than a single `TCM_DELETEITEM` for the
        // closed index, but it's the only reliable way to reset
        // the tab control's internal overflow-scroll state — see
        // `force_tab_strip_resync`'s doc-comment for the full
        // rationale (the user-reported bug where closing tabs at
        // the left edge of a scrolled strip leaves the visible
        // region empty even though tabs still exist).
        unsafe {
            force_tab_strip_resync(state);
        }

        // Release the closed tab's Scintilla document. The view
        // is still bound to it at this point, so Scintilla's
        // implicit view-ownership keeps the buffer alive until
        // the rebind below; the SCI_RELEASEDOCUMENT here drops
        // our external reference. Skip when the doc was never
        // materialized (background-loaded tab closed before
        // first activation — no `SCI_CREATEDOCUMENT` was issued).
        if closed.scintilla_doc != 0 {
            state
                .editor
                .send(SCI_RELEASEDOCUMENT, 0, closed.scintilla_doc);
        }

        // Rebind the view to whatever's now active. Three sub-
        // cases:
        //
        //  1. New active tab has a materialized doc — straight
        //     SCI_SETDOCPOINTER. View releases the just-released
        //     `closed.scintilla_doc` (now its final release →
        //     buffer freed) and AddRefs the new doc.
        //  2. New active tab has *no* materialized doc (it was
        //     loaded in the background and never activated).
        //     **Must** lazy-create + populate the doc here, not
        //     defer to a future click: leaving the view bound to
        //     the just-released document would create a use-after-
        //     free window where any keystroke or paint touches a
        //     buffer whose external refcount is zero.
        //  3. No new active tab (closed the last open tab). Bind
        //     the view to a fresh empty placeholder doc so the user
        //     sees an empty editor — not the just-closed file's
        //     stale content. Without this, Scintilla's view-implicit
        //     ref keeps the closed doc alive and visible until the
        //     next open's `activate_tab` rebinds the view, which
        //     produces the visible "closed file's text remained on
        //     screen" bug.
        if state.shell.active_tab.is_none() {
            // Refcount lifecycle:
            //   CREATE         → placeholder.refcount = 1 (our ref)
            //   SETDOCPOINTER  → view AddRefs new + Releases whatever
            //                    was previously bound. If we held a
            //                    materialized closed.scintilla_doc it
            //                    was already explicitly RELEASEDOCUMENT'd
            //                    above (refcount 1 → view's implicit
            //                    ref); SETDOCPOINTER's view-Release
            //                    drops that to 0, freeing it.
            //                    placeholder.refcount becomes 2.
            //   RELEASEDOCUMENT → placeholder.refcount = 1, just the
            //                    view's implicit ref. The next
            //                    SETDOCPOINTER (from a future open's
            //                    activate_tab) drops that final ref
            //                    and the placeholder is freed cleanly.
            //
            // Guard against a NULL CREATEDOCUMENT return (Scintilla
            // returns 0 on allocation failure). Using 0 as the lparam
            // for RELEASEDOCUMENT would invoke release-of-null which
            // isn't part of the public ABI contract; guard the whole
            // block so on OOM we leave the view in whatever state
            // Scintilla's own fallback produces — same observable
            // behaviour as before this fix and not worse.
            let placeholder = state
                .editor
                .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
            if placeholder != 0 {
                state.editor.send(SCI_SETDOCPOINTER, 0, placeholder);
                // Seed the placeholder's empty line 0 so the
                // line-number bar shows "1" instead of blank
                // chrome on the empty editor.
                populate_visible_line_numbers(&state.editor);
                // Deliberately no `enable_change_history` here:
                // the placeholder is bound for one paint cycle,
                // immediately released, and write-protected by
                // the no-active-tab UI state (Ctrl+S, paste, and
                // every other text-mutating command short-circuit
                // when `Shell.active_tab` is `None`). A history
                // tracker on this doc would never observe an
                // edit before the doc is freed.
                state.editor.send(SCI_RELEASEDOCUMENT, 0, placeholder);
            }
            // Refresh chrome to the empty state — status bar should
            // reflect the no-buffer state. The title bar gets
            // refreshed unconditionally in Phase 3 below
            // (`update_window_title`), which already handles the
            // `active_tab.is_none()` case by rendering just "Code++".
            let mut win32_ui = Win32Ui {
                status_hwnd: state.status_hwnd,
                tab_hwnd: state.tab_hwnd,
                toolbar_hwnd: state.toolbar_hwnd,
                main_menu: state.main_menu,
                // SAFETY: see the `accel_handle` field doc on
                // `Win32Ui` — pointer valid for the life of
                // `WindowState`, dereferenced on the UI thread
                // only.
                accel_handle: &raw mut state.accel_handle,
                plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
                dock_dialogs: &raw mut state.dock_dialogs,
                udl_registry: &raw const state.shell.udl_registry,
                editor: state.editor,
                docmap_editor: state.docmap_editor,
            };
            <Win32Ui as UiPlatform>::update_status(
                &mut win32_ui,
                codepp_core::lang::L_TEXT,
                &Encoding::default(),
                Eol::default(),
                0,
            );
        }
        if let Some(active_idx) = state.shell.active_tab {
            if closed.new_active_doc != 0 {
                state
                    .editor
                    .send(SCI_SETDOCPOINTER, 0, closed.new_active_doc);
            } else if let Some(text) = state.shell.tabs.get(active_idx).map(|t| t.text.clone()) {
                // Sub-case 2: lazily materialize the doc from the
                // tab's stored text. `tabs.get(active_idx)` rather
                // than `[active_idx]` so a future refactor that
                // could put `active_tab` out of range fails as a
                // missed-rebind no-op rather than a panic across
                // the `extern "system"` wnd_proc frame. Same
                // pattern as `handle_tab_selchange`'s lazy-create
                // branch.
                let new_doc = state
                    .editor
                    .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
                state.editor.send(SCI_SETDOCPOINTER, 0, new_doc);
                // Per-doc state — every fresh document needs
                // change-history enabled AND tab width re-applied
                // (`SCI_SETTABWIDTH` is per-document; see the
                // `apply_tab_width` doc). The view-side margin
                // already exists from `apply_change_history_margin`
                // at editor creation.
                enable_change_history(&state.editor);
                apply_tab_width(&state.editor);
                let mut bytes = Vec::with_capacity(text.len() + 1);
                bytes.extend_from_slice(text.as_bytes());
                bytes.push(0);
                state.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
                state.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
                state.editor.send(SCI_SETSAVEPOINT, 0, 0);
                if let Some(tab) = state.shell.tabs.get_mut(active_idx) {
                    tab.scintilla_doc = new_doc;
                }
            }

            // Sync the visual selection on the tab strip with
            // the new active index.
            unsafe {
                SendMessageW(
                    state.tab_hwnd,
                    TCM_SETCURSEL,
                    Some(WPARAM(active_idx)),
                    Some(LPARAM(0)),
                );
            }

            // Re-apply the new active tab's lexer/theme AND refresh
            // the status bar. Both fields live on the *view* (lexer
            // attachment) and the chrome (status bar text), neither
            // of which the rebind above touches — without these
            // calls the user sees the closed tab's colours and
            // status text after the close. The two snapshots happen
            // together so we hold the &Tab borrow once. Pulled out
            // of the borrow scope by Copy: status_hwnd is HWND and
            // editor is EditorHandle, both Copy; the Win32Ui
            // methods only touch self.{editor,status_hwnd}, so the
            // outer &mut state borrow stays sound across the calls.
            let snapshot = state
                .shell
                .tabs
                .get(active_idx)
                .map(|t| (t.lang, t.encoding.clone(), t.eol, t.byte_len));
            if let Some((lang, encoding, eol, byte_len)) = snapshot {
                let mut win32_ui = Win32Ui {
                    status_hwnd: state.status_hwnd,
                    tab_hwnd: state.tab_hwnd,
                    toolbar_hwnd: state.toolbar_hwnd,
                    main_menu: state.main_menu,
                    accel_handle: &raw mut state.accel_handle,
                    plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
                    dock_dialogs: &raw mut state.dock_dialogs,
                    udl_registry: &raw const state.shell.udl_registry,
                    editor: state.editor,
                    docmap_editor: state.docmap_editor,
                };
                <Win32Ui as UiPlatform>::apply_lang(&mut win32_ui, lang);
                <Win32Ui as UiPlatform>::update_status(
                    &mut win32_ui,
                    lang,
                    &encoding,
                    eol,
                    byte_len,
                );
                // Same SCI_SETDOCPOINTER-doesn't-fire-SCN_UPDATEUI
                // story as `handle_tab_selchange`: refresh toolbar
                // state explicitly so Undo/Redo and view-toggle
                // checks reflect the now-active buffer.
                // SAFETY: `state.toolbar_hwnd` is owned by us;
                // `state.editor` is bound to the active doc.
                unsafe {
                    toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
                }
            }
        }
    }

    // Phase 3: chrome refresh + notification delivery. No state
    // borrow held while plugin code runs.
    unsafe {
        if let Some(state) = state_from_hwnd(hwnd) {
            update_window_title(hwnd, &state.shell);
        }
        fire_queued_notifications(hwnd);
    }
    // Sync the Document Map's miniature view to the surviving
    // active tab. The "no tabs left" path invokes
    // `ensure_one_tab`, which calls `shell.new_untitled(&mut ui)`
    // — that trip through `Win32Ui::activate_tab` handles the
    // map sync via the primary path. This explicit call covers
    // the surviving-active-tab close case where the Win32-side
    // rebind above (`SCI_SETDOCPOINTER` on the main view for the
    // new active doc) doesn't go through the trait method.
    // Runs after the notifications block so a re-entrant plugin
    // can't race the sync.
    unsafe {
        sync_docmap_to_active_tab(hwnd);
    }
    CloseOutcome::Closed
}

/// Handle a tab-strip selection change (`TCN_SELCHANGE`). Reads the
/// freshly-selected index off the control, updates
/// `Shell.active_tab`, binds the Scintilla view to that tab's
/// document, and refreshes the status bar so encoding/EOL/size
/// reflect the new tab.
///
/// If the target tab has no document yet (`scintilla_doc == 0`),
/// it's a tab whose load completed while it wasn't active —
/// `apply_load_result` populated `tab.text` but skipped the
/// Scintilla document entirely. We materialize the document
/// lazily here: create one, push the tab's stored text, store the
/// pointer back on the tab. Subsequent switches short-circuit.
///
/// Handle `SCN_STYLENEEDED` for a UDL buffer. Called from the
/// `WM_NOTIFY` arm when the active tab's language is inside the
/// UDL dynamic-id range. `target` is the notification's
/// `position` field — the byte offset up to which Scintilla
/// wants styling applied.
///
/// If the active tab isn't a UDL (or the registry lookup
/// fails), the function returns without painting — Scintilla
/// simply leaves the range at whatever style it currently
/// carries. This is the graceful-degradation shape: a UDL
/// buffer whose registry entry got dropped between
/// `apply_udl_lang` and the notification (impossible today
/// but defensive) renders as plain text instead of crashing.
///
/// **Known m1c-3b-1 limitation** — this handler tokenises from
/// a line boundary near `endStyled` without any per-line
/// initial-state carry-over. A multi-line block comment /
/// delimiter span whose opening line falls before the current
/// paint range will mis-style on the first edit inside the
/// span. The fix (tracked follow-up under Phase 4.6 m1c
/// polish): persist per-line initial state via
/// `SCI_SETLINESTATE`, walk back to a line with
/// known-default state before starting the tokenise.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
///
/// **Load-bearing borrow discipline**: `state_from_hwnd` is
/// dropped BEFORE any `editor.send(...)` call. Every
/// `SCI_SETSTYLING` in the paint loop synchronously fires
/// `SCN_MODIFIED(ChangeStyle)` via `Document::SetStyleFor`
/// (`vendor/scintilla/src/Document.cxx:2418-2432` — no
/// `modEventMask` override to suppress it), which re-enters
/// `main_wnd_proc`'s `WM_NOTIFY` dispatcher synchronously. If
/// we still held `&WindowState` at that point, the reentrant
/// `SCN_MODIFIED` handler's attempt to re-borrow would violate
/// Rust's aliasing rules. Clone the definition out of the
/// borrow, drop the borrow, then paint.
unsafe fn handle_udl_style_needed(hwnd: HWND, target: usize) {
    let Some(state) = (unsafe { state_from_hwnd(hwnd) }) else {
        return;
    };
    let Some(active_idx) = state.shell.active_tab else {
        return;
    };
    let Some(tab) = state.shell.tabs.get(active_idx) else {
        return;
    };
    let lang_id = tab.lang.as_npp_id();
    if !codepp_udl::is_udl_lang_id(lang_id) {
        return;
    }
    let Some(entry) = state.shell.udl_registry.find_by_lang_type_id(lang_id) else {
        // Registry entry vanished — no paint, no crash. Log
        // once so a future contributor can spot this in `-v`
        // output if it ever happens.
        tracing::warn!(
            lang = lang_id,
            "SCN_STYLENEEDED for UDL LangType not in registry; skipping paint"
        );
        return;
    };
    // Cheap `Arc` clone rather than deep-copying the whole
    // definition — the whole point of `UdlEntry::compiled` is
    // that this hot path (fires on every keystroke) doesn't
    // rebuild the keyword-class tables. Was
    // `entry.definition.clone()` before the caching layer
    // landed. See `UdlCompiledRules`'s docstring for the
    // DESIGN.md §8 keystroke-budget rationale.
    let compiled = std::sync::Arc::clone(&entry.compiled);
    let editor = state.editor;
    // Compute line-aligned tokenise range. See
    // `udl_paint::line_aligned_range` for the discipline.
    let (range_start, range_end) = udl_paint::line_aligned_range(&editor, target);
    if range_end <= range_start {
        // Nothing to style (empty range or one that inverted
        // under document-length clamping). Skip cleanly.
        return;
    }
    // **Per-notification paint cap** — reviewer-required DoS
    // defence. A plugin or a stray `SCI_COLOURISE(0, -1)` can
    // fire `SCN_STYLENEEDED` with `position` = whole-document,
    // and Scintilla synchronously blocks the UI thread until
    // the handler returns. Cap the per-call paint at 64 KiB
    // (line-aligned). Each `SCI_SETSTYLING` advances Scintilla's
    // `endStyled`, so any bytes past the cap trigger a fresh
    // `SCN_STYLENEEDED` on Scintilla's next paint iteration.
    // The tokeniser is linear-time; 64 KiB is well inside
    // DESIGN.md §8's keystroke budget.
    const MAX_TOKENISE_RANGE: usize = 64 * 1024;
    let capped_end = range_start
        .saturating_add(MAX_TOKENISE_RANGE)
        .min(range_end);
    // Re-align to end-of-line so a mid-line cap doesn't produce
    // a partial-delimiter tail.
    let capped_line = editor.line_from_position(capped_end);
    let doc_len = editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
    let capped_range_end = editor
        .position_from_line(capped_line + 1)
        .unwrap_or(doc_len)
        .min(range_end);
    let range_len = capped_range_end - range_start;
    let Some(bytes) = editor.get_range_bytes(range_start, range_len) else {
        return;
    };
    udl_paint::paint_udl_range(&editor, &compiled, range_start, &bytes);
}

/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_tab_selchange(hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(hwnd) }) else {
        return;
    };
    // SAFETY: tab_hwnd is a live HWND created in `run`.
    let new_idx = unsafe { SendMessageW(state.tab_hwnd, TCM_GETCURSEL, None, None).0 as isize };
    if new_idx < 0 {
        return;
    }
    let new_idx = new_idx as usize;
    if new_idx >= state.shell.tabs.len() {
        // The control's selection is out of sync with the data
        // model — defensive only; should never happen because
        // sync_tab_strip keeps them in lockstep.
        return;
    }
    state.shell.active_tab = Some(new_idx);

    // Snapshot what we need from the tab, then drop the borrow
    // before reaching for `state.editor` (a Copy field) so we can
    // call into Scintilla without a live `&mut Tab` borrow.
    let (mut doc, text_to_populate, encoding, eol, byte_len, lang) = {
        let tab = &state.shell.tabs[new_idx];
        (
            tab.scintilla_doc,
            if tab.scintilla_doc == 0 {
                Some(tab.text.clone())
            } else {
                None
            },
            tab.encoding.clone(),
            tab.eol,
            tab.byte_len,
            tab.lang,
        )
    };

    // Lazily populate the doc on first activation of a background-
    // loaded tab. Create the doc, bind it, push the saved text.
    if let Some(text) = text_to_populate {
        doc = state
            .editor
            .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
        state.editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Per-doc state — every fresh document needs change-history
        // enabled AND tab width re-applied (`SCI_SETTABWIDTH` is
        // per-document; see the `apply_tab_width` doc). Margin
        // configuration was applied once at editor creation and
        // lives on the view, so it carries through every doc swap.
        // Critical to call `enable_change_history` BEFORE
        // `SCI_SETTEXT` so the initial text-insert is treated as
        // the document's starting state (not as edits to track).
        enable_change_history(&state.editor);
        apply_tab_width(&state.editor);
        let mut bytes = Vec::with_capacity(text.len() + 1);
        bytes.extend_from_slice(text.as_bytes());
        bytes.push(0);
        state.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
        state.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
        state.editor.send(SCI_SETSAVEPOINT, 0, 0);
        state.shell.tabs[new_idx].scintilla_doc = doc;
    } else {
        // Doc already exists — just rebind the view.
        state.editor.send(SCI_SETDOCPOINTER, 0, doc);
    }

    // Refresh the status bar so encoding/EOL/size match the
    // newly-active tab. Without this, the user sees the old tab's
    // stats until the next `WM_APP_WAKE` drain (which has no
    // reason to fire on a click-only switch).
    let mut win32_ui = Win32Ui {
        status_hwnd: state.status_hwnd,
        tab_hwnd: state.tab_hwnd,
        toolbar_hwnd: state.toolbar_hwnd,
        main_menu: state.main_menu,
        accel_handle: &raw mut state.accel_handle,
        plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
        dock_dialogs: &raw mut state.dock_dialogs,
        udl_registry: &raw const state.shell.udl_registry,
        editor: state.editor,
        docmap_editor: state.docmap_editor,
    };
    // Re-apply the new tab's lexer/theme. Each tab carries its own
    // LangType; without this call the previous tab's lexer stays
    // bound to the single Scintilla view and colours the new
    // buffer with the wrong rules (or, if the previous tab was
    // L_TEXT, leaves a coloured buffer un-styled).
    <Win32Ui as UiPlatform>::apply_lang(&mut win32_ui, lang);
    <Win32Ui as UiPlatform>::update_status(&mut win32_ui, lang, &encoding, eol, byte_len);

    // Refresh toolbar state for the newly-bound buffer. Same
    // rationale as the status-bar update above: `SCI_SETDOCPOINTER`
    // (the message that bound the new doc to our view) does not
    // fire `SCN_UPDATEUI` per `Editor.cxx::SetDocPointer` — only
    // `Redraw()`. Without this explicit refresh the toolbar's
    // Undo/Redo enabled state and view-toggle checks would keep
    // showing the previous tab's state until the user next types
    // or moves the caret. SAFETY: `state.toolbar_hwnd` is the
    // toolbar we own; `state.editor` is bound to the just-
    // attached doc.
    unsafe {
        toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
    }

    // Reflect the new active tab in the window title.
    // SAFETY: caller's UI-thread contract carries to update_window_title.
    unsafe {
        update_window_title(hwnd, &state.shell);
    }

    // Queue NPPN_BUFFERACTIVATED for plugins that track the
    // active buffer. The borrow on `state` is released by NLL at
    // its last use here (the queue method), before
    // `fire_queued_notifications` re-acquires a fresh borrow.
    state.shell.queue_buffer_activated();
    // Repaint the entire tab strip so both the previously-active
    // and newly-active cells redraw with their correct active /
    // inactive styling. The system tab control invalidates only
    // the cells it knows about (the new selection's cell on
    // `TCM_SETCURSEL`), but our owner-draw paint reads
    // `state.shell.active_tab` per cell — that membership flips
    // for two cells on every selection change, so without this
    // both the outgoing and incoming styles can lag until an
    // unrelated event (mouse hover, window expose) forces a
    // repaint.
    let tab_hwnd = state.tab_hwnd;
    // SAFETY: tab_hwnd is the live tab control we own; passing
    // None for the rect invalidates the whole client area.
    unsafe {
        let _ = InvalidateRect(Some(tab_hwnd), None, false);
    }
    // SAFETY: caller's UI-thread contract carries.
    unsafe {
        fire_queued_notifications(hwnd);
    }
    // Point the Document Map's miniature view at the newly-
    // active tab's document. Runs regardless of panel
    // visibility — a tab switch while the panel is hidden still
    // rebinds so the doc's Scintilla refcount stays coherent
    // (map view's `SCI_SETDOCPOINTER(new)` releases its
    // previous binding, letting the old tab's doc drop to
    // refcount 1 or 0 as appropriate). Also cheap: one
    // direct-call.
    unsafe {
        sync_docmap_to_active_tab(hwnd);
    }
}

/// Set the main window's title to reflect the currently-active tab:
/// `"<filename> - Code++"` when there's an active path,
/// `"Untitled - Code++"` when the active tab has no path yet,
/// `"Code++"` when no tab is open. Called whenever `Shell.active_tab`
/// changes (tab click, sync after open, plugin-driven switch).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn update_window_title(hwnd: HWND, shell: &Shell) {
    // Reuse `tab_display_name` so the title reflects the same
    // resolution order the tab label uses (custom_name → path
    // basename → `new N`). Without this the title would still
    // show the on-disk filename or "Untitled" even after a
    // File → Rename..., creating a visual mismatch with the tab.
    let title = match shell.active() {
        Some(tab) => format!("{} - Code++", tab_display_name(tab)),
        None => "Code++".to_string(),
    };
    let wide: Vec<u16> = title.encode_utf16().chain(std::iter::once(0)).collect();
    // SAFETY: hwnd is a valid main-window HWND owned by the caller's
    // thread; `wide` is a null-terminated UTF-16 buffer that lives
    // for the duration of the synchronous SetWindowTextW call.
    unsafe {
        let _ = SetWindowTextW(hwnd, PCWSTR(wide.as_ptr()));
    }
}

/// Bring the Win32 tab strip into sync with `state.shell.tabs`.
/// Inserts a tab item for each new `Shell.tabs[i]` past the count
/// the strip already knows about, using the file's basename (or
/// "Untitled" if the tab has no path yet) as the label. Then
/// snaps the tab control's selection to `state.shell.active_tab`
/// so a click elsewhere or a programmatic switch (`NPPM_SWITCHTOFILE`)
/// is reflected visually.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `state`'s HWNDs.
/// Bring the visible tab strip and window title into sync with
/// `state.shell` after a synchronous Shell mutation that doesn't
/// route through the loader (and so doesn't naturally trigger a
/// `WM_APP_WAKE`). Used by the File menu handlers (New, Open,
/// Reload, Close, Close All, Save As) — each one mutates
/// `shell.tabs` or `shell.active_tab` in place and then calls
/// this so the user sees the change immediately rather than
/// after the next message-pump cycle.
///
/// # Safety
///
/// Caller must hold the UI thread's `&mut WindowState` borrow and
/// not be in the middle of a plugin callback (`sync_tab_strip`
/// sends synchronous TCM_* messages but doesn't re-enter `wnd_proc`
/// for them).
/// Run the Save As flow: prompt for a destination path (pre-filled
/// with the active tab's current basename), then route through
/// `Shell::save_buffer_as`. Used by both the explicit File→Save As
/// menu path and the File→Save fallback when the active tab has no
/// path (an untitled buffer can't Ctrl+S to "the active path"
/// because there isn't one — we redirect to Save As instead of
/// surfacing a confusing "no active file path" error).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn run_save_as_flow(hwnd: HWND) {
    let suggestion = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state
            .shell
            .active()
            .and_then(|t| t.path.as_ref())
            .and_then(|p| p.file_name())
            .and_then(|s| s.to_str())
            .map(std::string::ToString::to_string)
    } else {
        None
    };
    let new_path = prompt_save_path(hwnd, suggestion.as_deref());
    let save_error: Option<String> = if let Some(p) = new_path {
        if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
            let (shell, mut ui) = state.split();
            let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                shell.save_buffer_as(&mut ui, p)
            }));
            match result {
                Ok(Ok(())) => None,
                Ok(Err(e)) => Some(e.to_string()),
                Err(_) => Some("internal panic during save".to_string()),
            }
        } else {
            None
        }
    } else {
        None
    };
    if let Some(msg) = save_error {
        show_error_dialog(hwnd, "Save As failed", &msg);
    }
    // save_buffer_as updates the tab's path on success — refresh
    // the strip so the label switches from "new N" (or the old
    // basename) to the new file's basename.
    unsafe { refresh_tab_chrome(hwnd) };
}

/// Enforce the "always at least one tab" invariant: if `shell.tabs`
/// is empty after a close path (Close, Close All, startup with no
/// session and no CLI path), create a fresh untitled buffer so the
/// user always sees an editor with at least one tab visible.
///
/// Notepad++ has the same invariant — closing the last tab pops a
/// "new 1" tab into existence rather than leaving an empty editor
/// chrome with no tab to type into.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn ensure_one_tab(hwnd: HWND) {
    let created = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        if state.shell.tabs.is_empty() {
            let (shell, mut ui) = state.split();
            // catch_unwind: same defensive shape as the menu
            // handlers — a panic inside Shell or Win32Ui can't
            // unwind across the wnd_proc's `extern "system"` frame.
            let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                shell.new_untitled(&mut ui);
            }));
            true
        } else {
            false
        }
    } else {
        false
    };
    // Only refresh chrome when we actually created a new tab — the
    // close-path callers already ran `sync_tab_strip` once via
    // `handle_close_active_tab_inner`, and the WM_APP_WAKE caller
    // ran it during the drain. A redundant double-refresh is a
    // wasteful TCM_INSERTITEMW + TCM_SETCURSEL pair on every
    // close, observable in traces.
    if created {
        unsafe { refresh_tab_chrome(hwnd) };
    }
}

unsafe fn refresh_tab_chrome(hwnd: HWND) {
    if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        // SAFETY: caller holds the UI-thread invariant. Both
        // helpers are `unsafe fn` because they send Win32 messages
        // and read `state` through a raw pointer dance, but
        // neither re-enters wnd_proc synchronously, so the borrow
        // we hold here is exclusive for their duration.
        unsafe {
            sync_tab_strip(state);
            update_window_title(hwnd, &state.shell);
        }
    }
}

/// Nuclear-option re-sync of the visible tab strip: delete every
/// item the Win32 control holds, reset our `synced_tab_count`, then
/// re-insert all tabs from `state.shell.tabs` via the standard
/// [`sync_tab_strip`] path.
///
/// **Why this exists:** the Win32 tab control's overflow-scroll
/// state (driven by an internal `msctls_updown32` spinner) doesn't
/// reliably clamp on `TCM_DELETEITEM`. After closing tabs that
/// formed the visible region of a horizontally-scrolled strip, the
/// control's scroll-pos can stay pointing past the (now smaller)
/// item list — the user sees an empty overflow region even though
/// tabs still exist. `WM_SIZE` to the same dimensions doesn't
/// re-trigger the clamp (the handler short-circuits on no-op size
/// changes), and there's no public message to "scroll active into
/// view". The only documented way to fully reset internal state is
/// to delete all items; on re-insert the control rebuilds its
/// scroll bounds from scratch.
///
/// Cost: one `TCM_DELETEALLITEMS` plus N `TCM_INSERTITEMW` calls.
/// For typical workloads (≤100 tabs) that's a few microseconds per
/// close — well below the perceptual threshold and below the
/// per-keystroke budget in DESIGN.md §8.
///
/// # Safety
///
/// Caller must hold the UI thread's `&mut WindowState` borrow. The
/// `SendMessageW` calls dispatch synchronously into the common-
/// control's `WndProc` and don't re-enter our `wnd_proc`.
unsafe fn force_tab_strip_resync(state: &mut WindowState) {
    // SAFETY: tab_hwnd is a valid HWND created in `run`; both
    // messages take no pointer arguments.
    unsafe {
        SendMessageW(
            state.tab_hwnd,
            TCM_DELETEALLITEMS,
            Some(WPARAM(0)),
            Some(LPARAM(0)),
        );
    }
    state.synced_tab_count = 0;
    unsafe {
        sync_tab_strip(state);
    }
}

unsafe fn sync_tab_strip(state: &mut WindowState) {
    while state.synced_tab_count < state.shell.tabs.len() {
        let idx = state.synced_tab_count;
        let label = tab_label_for(&state.shell.tabs[idx]);
        // TCITEMW.pszText is `*mut u16`; the wide buffer must
        // outlive the SendMessage call. The `label_storage` vec
        // is the buffer, kept alive for the call duration.
        let mut label_storage = label;
        let mut item = TCITEMW {
            mask: windows::Win32::UI::Controls::TCITEMHEADERA_MASK(0x0001), // TCIF_TEXT
            pszText: windows::core::PWSTR(label_storage.as_mut_ptr()),
            ..Default::default()
        };
        // SAFETY: tab_hwnd is a valid HWND (created in `run`); item
        // points to live wide-char storage that lives across the
        // SendMessage call.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_INSERTITEMW,
                Some(WPARAM(idx)),
                Some(LPARAM(&raw mut item as isize)),
            );
        }
        state.synced_tab_count += 1;
    }

    // Refresh the labels of tabs already on the strip. Without
    // this, a tab that was inserted while its `path` was still
    // None (synced as "Untitled" right after `open_file`) keeps
    // the placeholder label after `apply_load_result` populates
    // its real path: the insert-only loop above never revisits
    // existing items. TCM_SETITEMW with the same payload shape
    // updates a single TCITEM field in place.
    for idx in 0..state.synced_tab_count {
        // `.get(idx)` rather than `[idx]` so a future refactor
        // that ever lets `synced_tab_count` drift past
        // `shell.tabs.len()` degrades to a missing-update no-op
        // for that one tab rather than panicking across the
        // `extern "system"` wnd_proc frame.
        let Some(tab) = state.shell.tabs.get(idx) else {
            break;
        };
        let label = tab_label_for(tab);
        let mut label_storage = label;
        let mut item = TCITEMW {
            mask: windows::Win32::UI::Controls::TCITEMHEADERA_MASK(0x0001), // TCIF_TEXT
            pszText: windows::core::PWSTR(label_storage.as_mut_ptr()),
            ..Default::default()
        };
        // SAFETY: `state.tab_hwnd` is a live HWND created in
        // `run`; `&mut item` and `label_storage` both stay live
        // for the duration of the synchronous SendMessageW call.
        // TCM_SETITEMW does not re-enter our wnd_proc.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_SETITEMW,
                Some(WPARAM(idx)),
                Some(LPARAM(&raw mut item as isize)),
            );
        }
    }

    // Reflect the active tab index on the visual control. Done
    // unconditionally so external switches (NPPM_SWITCHTOFILE,
    // future shortcut routing) keep the tab strip in lockstep.
    if let Some(active_idx) = state.shell.active_tab {
        // SAFETY: tab_hwnd is valid; the result is unused.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_SETCURSEL,
                Some(WPARAM(active_idx)),
                Some(LPARAM(0)),
            );
        }
    }
}

/// Build the wide-char tab label for `tab` — [`tab_display_name`]
/// wrapped for the Win32 tab-strip API, which needs a NUL-terminated
/// UTF-16 buffer. Sanitizing and length-capping already happened in
/// `tab_display_name`; this only re-encodes.
fn tab_label_for(tab: &Tab) -> Vec<u16> {
    tab_display_name(tab)
        .encode_utf16()
        .chain(std::iter::once(0))
        .collect()
}

/// Bundle of HMENUs the `wnd_proc` and `WindowState` need to keep
/// addressable after `build_main_menu` returns. The bar itself is
/// what `CreateWindowExW` consumes; the four named popups need
/// dynamic refresh on `WM_INITMENUPOPUP` (state-driven check marks
/// or rebuilt-on-open lists). The plugin submenu is exposed
/// separately because the plugin host's `NPPM_GETMENUHANDLE` ABI
/// hands it back as a stable handle, distinct from any other host
/// menu.
struct BuiltMenuBar {
    bar: HMENU,
    plugin_menu: HMENU,
    /// File submenu. Held addressable so `WM_INITMENUPOPUP` can
    /// match against it and refresh the state-driven entries
    /// (currently just `ID_FILE_OPEN_IN_DEFAULT_VIEWER`'s enabled
    /// state, driven by the active tab's on-disk path + extension
    /// association).
    file_menu: HMENU,
    view_menu: HMENU,
    encoding_menu: HMENU,
    language_menu: HMENU,
    window_menu: HMENU,
    /// Popup HMENU for the right-shortcuts `▼` dropdown — the open-
    /// tabs switcher pinned to the right edge of the menu bar.
    /// Rebuilt on `WM_INITMENUPOPUP` by the same `refresh_window_menu`
    /// helper as the regular Window menu, so its items use the same
    /// `ID_WINDOW_BASE + idx` cmd ids and existing tab-switch
    /// handler.
    right_shortcuts_menu: HMENU,
}

/// Construct the full N++-shaped main menu: File, Edit, Search,
/// View, Encoding, Language, Settings, Tools, Macro, Run, Plugins,
/// Window, ?. Items that already have a real handler attached
/// (Edit's clipboard ops, View's toggles, File's Save/Close/Exit)
/// are enabled; items whose feature lands later in Phase 4+ are
/// inserted as `MF_GRAYED` placeholders so the structure is
/// observable and the cmd ids are reserved.
///
/// # Safety
///
/// `CreateMenu` / `AppendMenuW` are pure heap operations; they
/// don't re-enter our `wnd_proc`. The returned handles are owned by
/// the host process for the window's lifetime.
fn build_main_menu() -> windows::core::Result<BuiltMenuBar> {
    unsafe {
        let bar = CreateMenu()?;

        // ----- File -----
        let file_menu = CreateMenu()?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_NEW as usize,
            w!("&New\tCtrl+N"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_OPEN as usize,
            w!("&Open...\tCtrl+O"),
        )?;
        // "Open Containing Folder ▸" submenu. Four entries, all
        // greyed on menu open when the active tab is untitled
        // (state-driven via `refresh_file_menu` on
        // WM_INITMENUPOPUP; MF_BYCOMMAND greying reaches items
        // inside nested submenus, so we don't need to track the
        // submenu HMENU separately). Each entry acts on the
        // parent directory of the active tab's on-disk path.
        let open_containing = CreateMenu()?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_EXPLORER as usize,
            w!("&Explorer"),
        )?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_CMD as usize,
            w!("&cmd"),
        )?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_POWERSHELL as usize,
            w!("&PowerShell"),
        )?;
        AppendMenuW(open_containing, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_WORKSPACE as usize,
            w!("Folder as &Workspace"),
        )?;
        AppendMenuW(
            file_menu,
            MF_POPUP,
            open_containing.0 as usize,
            w!("Open &Containing Folder"),
        )?;
        // Enable state is state-driven — see [`refresh_file_menu`]
        // fired from `WM_INITMENUPOPUP` for the File menu. Starts
        // greyed because no tab exists at startup; a fresh Ctrl+N
        // or Ctrl+O flips it appropriately on the next popup.
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_IN_DEFAULT_VIEWER as usize,
            w!("Open in &Default Viewer"),
        )?;
        // Workspace open-folder. Enabled from m2 onward — click
        // pops the folder picker and opens the panel rooted at
        // the chosen folder.
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_OPEN_FOLDER_AS_WORKSPACE as usize,
            w!("Open Folder as &Workspace..."),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_RELOAD as usize,
            w!("&Reload from Disk\tCtrl+R"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE as usize,
            w!("&Save\tCtrl+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_AS as usize,
            w!("Save &As...\tCtrl+Alt+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_ALL as usize,
            w!("Sav&e All\tCtrl+Shift+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_RENAME as usize,
            w!("Re&name...\tF2"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_CLOSE as usize,
            w!("&Close\tCtrl+W"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_CLOSE_ALL as usize,
            w!("Close A&ll\tCtrl+Shift+W"),
        )?;
        // "Close Multiple Documents ▸" submenu. Five variants,
        // each closing a specific subset of the open tabs. All
        // reuse the single-tab close path (dirty prompt + Cancel
        // shortcircuit) so a dirty buffer produces the same
        // Save/Don't Save/Cancel dialog as Ctrl+W. Per-entry
        // greying is driven by `refresh_file_menu` on
        // WM_INITMENUPOPUP.
        let close_multi = CreateMenu()?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_BUT_ACTIVE as usize,
            w!("Close All but &Active Document"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_BUT_PINNED as usize,
            w!("Close All but &Pinned Documents"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_TO_LEFT as usize,
            w!("Close All To the &Left"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_TO_RIGHT as usize,
            w!("Close All To the &Right"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_UNCHANGED as usize,
            w!("Close All &Unchanged"),
        )?;
        AppendMenuW(
            file_menu,
            MF_POPUP,
            close_multi.0 as usize,
            w!("Close &Multiple Documents"),
        )?;
        // Greyed for untitled buffers via `refresh_file_menu` —
        // MF_GRAYED here is the startup default (no tab yet
        // exists, so nothing is deletable). Matches Notepad++'s
        // File menu label + behaviour.
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_MOVE_TO_RECYCLE_BIN as usize,
            w!("Move to Recycle &Bin"),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Session interchange (Notepad++-shape XML). Enabled at all
        // times — Load prompts for a file regardless of what's open,
        // Save works even with zero tabs (writes an empty session).
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_LOAD_SESSION as usize,
            w!("&Load Session..."),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_SESSION as usize,
            w!("Save Sess&ion..."),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Print is greyed by `refresh_file_menu` when there's no
        // active tab or the active tab's document is empty; enabled
        // otherwise. The initial `MF_GRAYED` is a startup safe
        // default (no tab exists at menu-build time).
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_PRINT as usize,
            w!("&Print...\tCtrl+P"),
        )?;
        // Print Preview: same enable / disable discipline as
        // Print (both greyed at menu-build time; enabled by
        // `refresh_file_menu` when a tab is active).
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_PRINT_PREVIEW as usize,
            w!("Print Pre&view...\tCtrl+Shift+P"),
        )?;
        // Print Now: same enable discipline as Print. Placed last
        // in the print cluster because it's the "destructive" one
        // (fires straight to the printer with no confirmation) —
        // users looking for the safer "show me a dialog first"
        // options land on those first. No ellipsis in the label
        // since it never prompts — the "..." convention signals a
        // follow-up dialog, and this action deliberately skips one.
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_PRINT_NOW as usize,
            w!("Print &Now"),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(file_menu, MF_STRING, ID_FILE_EXIT as usize, w!("E&xit"))?;
        AppendMenuW(bar, MF_POPUP, file_menu.0 as usize, w!("&File"))?;

        // ----- Edit ----- (Scintilla-backed; all enabled.)
        let edit_menu = CreateMenu()?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_UNDO as usize,
            w!("&Undo\tCtrl+Z"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_REDO as usize,
            w!("&Redo\tCtrl+Y"),
        )?;
        AppendMenuW(edit_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_CUT as usize,
            w!("Cu&t\tCtrl+X"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_COPY as usize,
            w!("&Copy\tCtrl+C"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_PASTE as usize,
            w!("&Paste\tCtrl+V"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_DELETE as usize,
            w!("&Delete\tDel"),
        )?;
        AppendMenuW(edit_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_SELECTALL as usize,
            w!("Select &All\tCtrl+A"),
        )?;
        AppendMenuW(bar, MF_POPUP, edit_menu.0 as usize, w!("&Edit"))?;

        // ----- Search ----- (Find/Replace wired in m3b2.)
        let search_menu = CreateMenu()?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FIND as usize,
            w!("&Find...\tCtrl+F"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDNEXT as usize,
            w!("Find &Next\tF3"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDPREV as usize,
            w!("Find Pre&vious\tShift+F3"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_REPLACE as usize,
            w!("&Replace...\tCtrl+H"),
        )?;
        AppendMenuW(search_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Find in Files — m4 step 4a opens the FIF tab in the
        // Find/Replace dialog. Step 4b will wire the Find All
        // button to actually drive `Shell::start_fif`.
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDINFILES as usize,
            w!("Find in Fi&les...\tCtrl+Shift+F"),
        )?;
        AppendMenuW(search_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_GOTOLINE as usize,
            w!("&Go to...\tCtrl+G"),
        )?;
        AppendMenuW(bar, MF_POPUP, search_menu.0 as usize, w!("&Search"))?;

        // ----- View ----- (toggles refreshed in WM_INITMENUPOPUP.)
        let view_menu = CreateMenu()?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_WORDWRAP as usize,
            w!("&Word Wrap"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_SHOWWS as usize,
            w!("Show White&space"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_SHOWEOL as usize,
            w!("Show End of &Line"),
        )?;
        AppendMenuW(view_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMIN as usize,
            w!("Zoom &In\tCtrl++"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMOUT as usize,
            w!("Zoom &Out\tCtrl+-"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMRESET as usize,
            w!("&Restore Zoom\tCtrl+0"),
        )?;
        AppendMenuW(view_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Toggle — check state syncs to `WindowState.workspace_visible`
        // via `refresh_view_menu` (fired from `WM_INITMENUPOPUP`).
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_FOLDER_AS_WORKSPACE as usize,
            w!("&Folder as Workspace"),
        )?;
        // Document Map — right-column mirror of the workspace
        // panel. Check state syncs to `WindowState.docmap_visible`
        // via `refresh_view_menu`.
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_DOCMAP as usize,
            w!("&Document Map"),
        )?;
        AppendMenuW(bar, MF_POPUP, view_menu.0 as usize, w!("&View"))?;

        // ----- Encoding ----- (radio refreshed in WM_INITMENUPOPUP;
        // ANSI grayed pending the system-codepage detection path —
        // see the WM_COMMAND handler comment for the deferral.)
        let encoding_menu = CreateMenu()?;
        AppendMenuW(
            encoding_menu,
            MF_STRING | MF_GRAYED,
            ID_ENCODING_ANSI as usize,
            w!("&ANSI"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF8 as usize,
            w!("UTF-&8 (no BOM)"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF8_BOM as usize,
            w!("UTF-8 with &BOM"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF16_LE as usize,
            w!("UTF-16 &LE BOM"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF16_BE as usize,
            w!("UTF-16 B&E BOM"),
        )?;
        AppendMenuW(bar, MF_POPUP, encoding_menu.0 as usize, w!("E&ncoding"))?;

        // ----- Language ----- (built from `core::lang::LANG_TABLE`.
        // cmd id = ID_LANGUAGE_BASE + lang.0. Radio refreshed in
        // WM_INITMENUPOPUP based on the active tab's lang.)
        //
        // Layout (matches Notepad++):
        //   1. "Normal Text" — always at top, single entry.
        //   2. Separator.
        //   3. Alphabetical block. Same-first-letter groups of 2+
        //      collapse into a submenu titled by the letter;
        //      single-entry letters stay at the top level.
        //   4. Separator.
        //   5. "User-Defined language" submenu — greyed pending the
        //      Phase 5 user-defined-language work.
        let language_menu = build_language_menu()?;
        AppendMenuW(bar, MF_POPUP, language_menu.0 as usize, w!("&Language"))?;

        // ----- Settings -----
        let settings_menu = CreateMenu()?;
        AppendMenuW(
            settings_menu,
            MF_STRING,
            ID_SETTINGS_PREFERENCES as usize,
            w!("&Preferences..."),
        )?;
        AppendMenuW(
            settings_menu,
            MF_STRING,
            ID_SETTINGS_STYLECONFIGURATOR as usize,
            w!("&Style Configurator..."),
        )?;
        AppendMenuW(bar, MF_POPUP, settings_menu.0 as usize, w!("Se&ttings"))?;

        // ----- Tools / Macro / Run ----- (placeholder submenus —
        // the menu *items* land alongside the features in later
        // phases; for now the top-level entries reserve the slots
        // and show as empty grayed popups.)
        let tools_menu = CreateMenu()?;
        AppendMenuW(
            tools_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(no tools wired yet)"),
        )?;
        AppendMenuW(bar, MF_POPUP, tools_menu.0 as usize, w!("&Tools"))?;

        let macro_menu = CreateMenu()?;
        AppendMenuW(
            macro_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(macro recording lands later)"),
        )?;
        AppendMenuW(bar, MF_POPUP, macro_menu.0 as usize, w!("&Macro"))?;

        let run_menu = CreateMenu()?;
        AppendMenuW(
            run_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(run-command lands later)"),
        )?;
        AppendMenuW(bar, MF_POPUP, run_menu.0 as usize, w!("R&un"))?;

        // ----- Plugins ----- (populated lazily by `populate_plugin_menu`
        // on first WM_INITMENUPOPUP; the HMENU is alive from now on
        // so plugins that query NPPM_GETMENUHANDLE before the popup
        // get a real handle.)
        let plugin_menu = CreateMenu()?;
        AppendMenuW(bar, MF_POPUP, plugin_menu.0 as usize, w!("&Plugins"))?;

        // ----- Window ----- (rebuilt every WM_INITMENUPOPUP from
        // Shell.tabs; cmd id = ID_WINDOW_BASE + tab idx.)
        let window_menu = CreateMenu()?;
        AppendMenuW(
            window_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(no open windows)"),
        )?;
        AppendMenuW(bar, MF_POPUP, window_menu.0 as usize, w!("&Window"))?;

        // ----- ? (Help) -----
        // Order: external links first, then Update (greyed),
        // then About. Two separators split the three logical
        // groups (info-and-community, self-update, app-info).
        // The two greyed entries (`ID_HELP_MANUAL`,
        // `ID_HELP_UPDATE`) are placeholders — their command ids
        // are reserved so the menu layout is stable across builds
        // even while the targets aren't wired.
        let help_menu = CreateMenu()?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_HOME as usize,
            w!("Code++ &Home"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_PROJECT as usize,
            w!("Code++ &Project Page"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING | MF_GRAYED,
            ID_HELP_MANUAL as usize,
            w!("Code++ Online User &Manual"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_COMMUNITY as usize,
            w!("Code++ &Community (Forum)"),
        )?;
        AppendMenuW(help_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            help_menu,
            MF_STRING | MF_GRAYED,
            ID_HELP_UPDATE as usize,
            w!("&Update Code++"),
        )?;
        AppendMenuW(help_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_ABOUT as usize,
            w!("&About Code++\tF1"),
        )?;
        AppendMenuW(bar, MF_POPUP, help_menu.0 as usize, w!("&?"))?;

        // ----- Right shortcuts -----
        // Three single-glyph top-level entries pinned to the right
        // edge of the menu bar: `+` (new untitled), `▼` (open-tabs
        // switcher), `X` (close active tab). They form the "right
        // shortcuts" UI group; a future Settings toggle will hide
        // the group as a whole, but for now it's always shown.
        //
        // `+` and `X` reuse `ID_FILE_NEW` / `ID_FILE_CLOSE` so the
        // existing WM_COMMAND handlers light up unchanged. `▼` is a
        // popup populated on `WM_INITMENUPOPUP` by the same
        // `refresh_window_menu` helper as the regular Window menu,
        // so the entries use the same `ID_WINDOW_BASE + idx` cmd
        // ids and the same tab-switch handler.
        //
        // Right-justification: `MFT_RIGHTJUSTIFY` on the first of
        // the three items right-aligns it and every subsequent
        // top-level item — so the three appear `+ ▼ X` left-to-right
        // hugging the menu bar's right edge.
        // U+FF0B FULLWIDTH PLUS SIGN — drawn at the menu font's full
        // em-square height, so the cross visually matches the `X`
        // letter to its right. ASCII `+` sits at x-height and looks
        // half the size of the neighbouring glyphs.
        AppendMenuW(bar, MF_STRING, ID_FILE_NEW as usize, w!("\u{FF0B}"))?;
        // RAII-wrap the freshly-allocated popup so a `?`-propagated
        // failure on the upcoming attach `AppendMenuW(MF_POPUP)` —
        // before Win32 takes ownership — frees the orphan instead
        // of leaking a kernel object. The same pattern is used in
        // `build_language_menu`. No construction-time placeholder
        // item is needed: `refresh_window_menu` clears and rebuilds
        // the popup's contents on every `WM_INITMENUPOPUP`.
        let right_shortcuts_guard = MenuGuard::wrap(CreateMenu()?);
        AppendMenuW(
            bar,
            MF_POPUP,
            right_shortcuts_guard.handle().0 as usize,
            w!("\u{25BC}"),
        )?;
        // Attach succeeded — defuse the guard so the bar's destroy
        // cascade becomes the sole owner of the popup HMENU.
        let right_shortcuts_menu = right_shortcuts_guard.take();
        AppendMenuW(bar, MF_STRING, ID_FILE_CLOSE as usize, w!("X"))?;

        // Flip the `+` item to right-justified. `GetMenuItemCount`
        // returns the post-append total; the `+` we just appended is
        // at position `count - 3`. A failure here only affects
        // alignment (the three entries still work, they just appear
        // mixed with the left-justified menu items) — log and carry
        // on rather than failing the menu build.
        let item_count = GetMenuItemCount(Some(bar));
        if item_count >= 3 {
            let plus_pos = (item_count - 3) as u32;
            let mut mii = MENUITEMINFOW {
                cbSize: std::mem::size_of::<MENUITEMINFOW>() as u32,
                fMask: MIIM_FTYPE,
                fType: MFT_RIGHTJUSTIFY,
                ..Default::default()
            };
            if let Err(e) = SetMenuItemInfoW(bar, plus_pos, true, &raw mut mii) {
                tracing::warn!(error = ?e, "SetMenuItemInfoW(MFT_RIGHTJUSTIFY) failed");
            }
        }

        Ok(BuiltMenuBar {
            bar,
            plugin_menu,
            file_menu,
            view_menu,
            encoding_menu,
            language_menu,
            window_menu,
            right_shortcuts_menu,
        })
    }
}

/// Refresh check marks on the View menu so they reflect the live
/// Scintilla state (`SCI_GETWRAPMODE`, `SCI_GETVIEWWS`,
/// `SCI_GETVIEWEOL`). Cheap to call on every `WM_INITMENUPOPUP` —
/// three direct-call queries plus three `CheckMenuItem` calls.
///
/// # Safety
///
/// `view_menu` must be a live HMENU (the one built by
/// `build_main_menu`); caller must run on the UI thread.
unsafe fn refresh_view_menu(
    view_menu: HMENU,
    editor: &EditorHandle,
    workspace_visible: bool,
    docmap_visible: bool,
) {
    let wrap_on = editor.send(SCI_GETWRAPMODE, 0, 0) != 0;
    let ws_on = editor.send(SCI_GETVIEWWS, 0, 0) != 0;
    let eol_on = editor.send(SCI_GETVIEWEOL, 0, 0) != 0;
    let mark = |id: u16, on: bool| {
        let flags = MF_BYCOMMAND.0 | if on { MF_CHECKED.0 } else { MF_UNCHECKED.0 };
        // CheckMenuItem returns the previous state on success or
        // -1u32 on failure; we treat both as fire-and-forget — a
        // failure here just means the check mark is wrong on this
        // open, never a process-stability issue.
        unsafe {
            let _ = CheckMenuItem(view_menu, u32::from(id), flags);
        }
    };
    mark(ID_VIEW_WORDWRAP, wrap_on);
    mark(ID_VIEW_SHOWWS, ws_on);
    mark(ID_VIEW_SHOWEOL, eol_on);
    // Workspace toggle — reads the cached `workspace_visible` bit
    // rather than probing the panel HWND, so the check state
    // stays in lockstep with the layout code that also gates on
    // this bit.
    mark(ID_VIEW_FOLDER_AS_WORKSPACE, workspace_visible);
    // Docmap toggle — same cached-bit discipline.
    mark(ID_VIEW_DOCMAP, docmap_visible);
}

/// Radio-mark the menu item matching `lang` in the Language menu.
/// `CheckMenuRadioItem` ensures only one item in the range carries
/// the radio glyph at a time. Phase 4 m1 wires four langs (Normal
/// Text, C, C++, Rust); cmd ids run from `ID_LANGUAGE_BASE` upward.
///
/// # Safety
///
/// `language_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_language_menu(language_menu: HMENU, lang: LangType) {
    // CheckMenuRadioItem(menu, first_id, last_id, check_id, MF_BYCOMMAND).
    // The range is closed [first, last]; we use the full reserved
    // band so future `Lang` additions don't need an off-by-one
    // here. `check_id` outside the range is a no-op which keeps an
    // unrecognised lang from clearing all marks.
    //
    // `lang.as_npp_id()` is whatever i32 the plugin ABI handed us,
    // including i32::MAX from a hostile NPPM_SETBUFFERLANGTYPE.
    // Bound the value before the addition to avoid overflow on the
    // intermediate i32 stage and to keep the resulting target id
    // inside the cmd-id range Win32 will accept.
    let lang_id = lang.as_npp_id();
    // Unified pre-clear: wipe every existing bullet in BOTH the
    // built-in language range AND the UDL item range from every
    // top-level submenu (letter submenus and the "User-Defined
    // language" submenu) and every corresponding parent popup
    // entry. Without this, switching between a built-in language
    // and a UDL leaves the previous side's bullet in place — the
    // sweep below only touches the built-in side, and
    // `refresh_udl_radio_mark` only touches the UDL side, so
    // neither reliably clears the other. The clear is idempotent
    // and cheap (one SetMenuItemInfoW per top-level submenu +
    // one inner CheckMenuItem per previously-marked item).
    unsafe { clear_all_language_menu_marks(language_menu) };
    // UDL languages live in a disjoint id space (>= 1024) that
    // maps to `ID_UDL_ITEM_BASE + offset` menu ids, not
    // `ID_LANGUAGE_BASE + id`. Route them through
    // `refresh_udl_radio_mark` so the bullet lands on the correct
    // item inside the "User-Defined language" submenu. Non-UDL
    // out-of-range values (negative or >= ID_LANGUAGE_CAP but not
    // a valid UDL id) fall through to the early return below.
    if codepp_udl::is_udl_lang_id(lang_id) {
        unsafe { set_udl_radio_mark(language_menu, lang_id) };
        return;
    }
    if lang_id < 0 || lang_id as usize >= ID_LANGUAGE_CAP {
        return;
    }
    let target = u32::from(ID_LANGUAGE_BASE) + lang_id as u32;
    // CheckMenuRadioItem only marks items in the menu it's called
    // on. With m6's first-letter submenus the active item may live
    // inside a child popup, so we apply the call to the top-level
    // menu *and* every immediate-child submenu. CheckMenuRadioItem
    // is a no-op on a menu that doesn't contain `target`, so the
    // sweep is harmless on unrelated submenus and idempotent on
    // re-application.
    //
    // **Two-level visibility:** when the active language lives
    // inside a letter submenu (e.g. Perl inside the "P" submenu),
    // `CheckMenuRadioItem` on the submenu marks the language item
    // — but the user only sees that bullet after hovering into the
    // submenu. To indicate the active language at the **top level**
    // too, we ALSO set `MFT_RADIOCHECK | MFS_CHECKED` on the parent
    // letter submenu item by position. Letter submenu items have no
    // command id (they carry an HMENU pointer instead), so
    // `CheckMenuRadioItem`'s by-command sweep can't reach them —
    // `SetMenuItemInfoW` by position is the only way. Other letter
    // submenus get `MFS_UNCHECKED` so a previously-active letter's
    // mark clears on language switch.
    //
    // The `MIIM_FTYPE | MIIM_STATE` mask only modifies fType / fState;
    // the submenu's HMENU pointer (`hSubMenu` under `MIIM_SUBMENU`)
    // is preserved, so the letter submenu still opens correctly.
    unsafe {
        let _ = CheckMenuRadioItem(
            language_menu,
            u32::from(ID_LANGUAGE_BASE),
            u32::from(ID_LANGUAGE_END),
            target,
            MF_BYCOMMAND.0,
        );
        let count = GetMenuItemCount(Some(language_menu));
        for i in 0..count {
            let sub = GetSubMenu(language_menu, i);
            if sub.is_invalid() {
                continue;
            }
            // Mark items inside the submenu (the inner bullet, visible
            // when the user opens the letter submenu).
            let _ = CheckMenuRadioItem(
                sub,
                u32::from(ID_LANGUAGE_BASE),
                u32::from(ID_LANGUAGE_END),
                target,
                MF_BYCOMMAND.0,
            );
            // Walk the submenu's items by position. Track two things:
            //   * `contains_target` — does this submenu contain the
            //     active language? (drives the bullet mark)
            //   * `in_lang_band` — does this submenu hold items with
            //     ids inside the `ID_LANGUAGE_BASE..=ID_LANGUAGE_END`
            //     (1500..=1599) range at all? Letter submenus
            //     (A / B / C / ...) yield `true`; the "User-Defined
            //     language" submenu yields `false` because its
            //     entries live in the disjoint 2100..=2102 UDL-
            //     action range and the reserved 2200..=3099 UDL-
            //     item range (Phase 4.6 m2 / m1d) — both outside
            //     the language band.
            // The `in_lang_band` discriminator is load-bearing: we
            // ONLY apply `SetMenuItemInfoW` to letter submenus.
            // Touching the UDL submenu would replace the greyed
            // "Define your language…" entry's `MFS_GRAYED` state
            // with `MFS_UNCHECKED` (`MIIM_STATE` overwrites fState
            // wholesale), silently re-enabling the deliberately
            // disabled item.
            let inner_count = GetMenuItemCount(Some(sub));
            let mut contains_target = false;
            let mut in_lang_band = false;
            for j in 0..inner_count {
                let id = GetMenuItemID(sub, j);
                if id == target {
                    contains_target = true;
                    in_lang_band = true;
                    break;
                }
                if id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END) {
                    in_lang_band = true;
                    // Don't break — still scanning for `target`.
                }
            }
            if !in_lang_band {
                continue;
            }
            // Mark / unmark the parent letter submenu item (top-level
            // entry at position `i`) with MFT_RADIOCHECK + MFS_*.
            let mut mii = MENUITEMINFOW {
                cbSize: u32::try_from(core::mem::size_of::<MENUITEMINFOW>()).unwrap_or(0),
                fMask: MIIM_FTYPE | MIIM_STATE,
                fType: MFT_RADIOCHECK,
                fState: if contains_target {
                    MFS_CHECKED
                } else {
                    MFS_UNCHECKED
                },
                ..Default::default()
            };
            // `i` cast safe — GetMenuItemCount returns i32 >= 0 and
            // we're iterating that exact range.
            #[allow(
                clippy::cast_sign_loss,
                reason = "loop bound from GetMenuItemCount is non-negative"
            )]
            let pos = i as u32;
            let _ = SetMenuItemInfoW(language_menu, pos, true, &raw mut mii);
        }
    }
}

/// Clear every existing radio-mark bullet in the Language menu
/// — both in the built-in `ID_LANGUAGE_BASE..=ID_LANGUAGE_END`
/// range and the UDL `ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END` range,
/// on every top-level letter submenu AND the "User-Defined
/// language" submenu, AND on the top-level parent popup entries
/// themselves. Called at the top of `refresh_language_menu`
/// before either the built-in or UDL set-mark path applies its
/// own bullet, so switching *between* the two sides doesn't
/// leave a stale bullet behind on the side that just lost focus.
///
/// This is not the same as calling `CheckMenuRadioItem` with an
/// out-of-range target — `CheckMenuRadioItem` requires
/// `check_id` to fall within the passed `[first, last]` range or
/// it fails and changes nothing. To clear, we iterate submenu
/// items by position, read each item's cmd id via
/// `GetMenuItemID`, and unmark any that fall into either
/// language range via `CheckMenuItem(sub, id, MF_BYCOMMAND |
/// MF_UNCHECKED)`. Top-level popup entries (which have no cmd
/// id — they carry an HMENU pointer instead) are cleared by
/// `SetMenuItemInfoW(MIIM_FTYPE | MIIM_STATE)` with
/// `MFT_RADIOCHECK | MFS_UNCHECKED`.
///
/// # Safety
///
/// `language_menu` must be a live HMENU (top-level Language menu
/// from `build_language_menu`). Caller on the UI thread.
unsafe fn clear_all_language_menu_marks(language_menu: HMENU) {
    unsafe {
        let count = GetMenuItemCount(Some(language_menu));
        if count <= 0 {
            return;
        }
        for i in 0..count {
            let sub = GetSubMenu(language_menu, i);
            if sub.is_invalid() {
                // Direct top-level command item (no child popup):
                //   * "Normal Text" at position 0.
                //   * Any letter with exactly one `LANG_TABLE`
                //     entry (single-run letters aren't wrapped
                //     in a letter submenu).
                //   * Every loaded UDL — appended flat at the
                //     bottom of the Language menu by
                //     `append_udls_to_menu` so a UDL click is
                //     one hover-and-click, matching N++'s
                //     layout.
                //
                // Read the cmd id and clear the bullet if it's
                // in either the built-in language range or the
                // UDL item range. Both `refresh_language_menu`'s
                // built-in sweep and `set_udl_radio_mark` set
                // bullets on `language_menu` directly for these
                // ids, so this clear path must handle both
                // ranges to keep cross-boundary switches from
                // leaving a stale bullet behind.
                let id = GetMenuItemID(language_menu, i);
                let in_lang_range =
                    id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END);
                let in_udl_range =
                    id >= u32::from(ID_UDL_ITEM_BASE) && id <= u32::from(ID_UDL_ITEM_END);
                if in_lang_range || in_udl_range {
                    let _ = CheckMenuItem(language_menu, id, MF_BYCOMMAND.0 | MF_UNCHECKED.0);
                }
                continue;
            }
            let inner_count = GetMenuItemCount(Some(sub));
            let mut touched = false;
            for j in 0..inner_count {
                let id = GetMenuItemID(sub, j);
                let in_lang_range =
                    id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END);
                let in_udl_range =
                    id >= u32::from(ID_UDL_ITEM_BASE) && id <= u32::from(ID_UDL_ITEM_END);
                if in_lang_range || in_udl_range {
                    let _ = CheckMenuItem(sub, id, MF_BYCOMMAND.0 | MF_UNCHECKED.0);
                    touched = true;
                }
            }
            if !touched {
                continue;
            }
            let mut mii = MENUITEMINFOW {
                cbSize: u32::try_from(core::mem::size_of::<MENUITEMINFOW>()).unwrap_or(0),
                fMask: MIIM_FTYPE | MIIM_STATE,
                fType: MFT_RADIOCHECK,
                fState: MFS_UNCHECKED,
                ..Default::default()
            };
            #[allow(
                clippy::cast_sign_loss,
                reason = "loop bound from GetMenuItemCount is non-negative"
            )]
            let pos = i as u32;
            let _ = SetMenuItemInfoW(language_menu, pos, true, &raw mut mii);
        }
    }
}

/// Apply the radio-mark bullet for a UDL language. UDL menu
/// items live as flat top-level entries directly on
/// `language_menu`, with cmd ids in
/// `ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END`, disjoint from the
/// letter-submenus' `ID_LANGUAGE_BASE..=ID_LANGUAGE_END` band.
/// Because the target is a direct child of `language_menu`, one
/// `CheckMenuRadioItem` call on `language_menu` with the UDL id
/// range is sufficient — no submenu walk, no companion parent-
/// popup bullet to mirror (there is no popup wrapping UDL
/// entries any more).
///
/// Assumes the caller has already invoked
/// [`clear_all_language_menu_marks`] so no stale bullets remain
/// on either side of the built-in / UDL boundary.
///
/// # Safety
///
/// `language_menu` must be a live HMENU (top-level Language menu
/// from `build_language_menu`). Caller on the UI thread.
unsafe fn set_udl_radio_mark(language_menu: HMENU, lang_id: i32) {
    unsafe {
        // Compute the target cmd id from the lang id — inverse
        // of `append_udls_to_menu`'s encoding.
        let offset = lang_id - codepp_udl::UDL_LANG_TYPE_BASE;
        if offset < 0 || offset > i32::from(ID_UDL_ITEM_END - ID_UDL_ITEM_BASE) {
            return;
        }
        // `offset` is bounded in
        // `0..=(ID_UDL_ITEM_END-ID_UDL_ITEM_BASE)` (~900), well
        // inside `u32` range.
        #[allow(clippy::cast_sign_loss, reason = "offset guarded to be non-negative")]
        let target = u32::from(ID_UDL_ITEM_BASE) + offset as u32;
        let _ = CheckMenuRadioItem(
            language_menu,
            u32::from(ID_UDL_ITEM_BASE),
            u32::from(ID_UDL_ITEM_END),
            target,
            MF_BYCOMMAND.0,
        );
    }
}

/// Build the Language menu from `core::lang::LANG_TABLE`. Returns
/// the top-level HMENU, ready to be appended to the menu bar.
///
/// Layout matches Notepad++:
///
///  1. "Normal Text" — always at the top, single entry, mapped to
///     `L_TEXT` (cmd id `ID_LANGUAGE_BASE + 0`).
///  2. Separator.
///  3. Alphabetical block of every other `LANG_TABLE` entry. Same-
///     first-letter groups of 2 or more collapse into a submenu
///     titled by the letter; single-entry letters stay at the top
///     level.
///  4. Separator.
///  5. "User-Defined language" submenu (Phase 4.6 m2):
///     - "Define your language…" — greyed until the m3 editor
///       modal lands.
///     - "Open User Defined Language folder…" — opens the OS
///       file explorer at `<config_dir>/userDefineLangs/`,
///       creating the directory first if it doesn't yet exist.
///     - "Notepad++ User Defined Languages Collection" — opens
///       [`UDL_COLLECTION_URL`] in the user's default browser.
///  6. The dynamic list of loaded UDLs, appended at the *top
///     level* (below the "User-Defined language" submenu entry,
///     matching N++'s layout — one hover-and-click per UDL, not
///     two). That extension happens later in `Win32Ui::run` via
///     `append_udls_to_menu` because the registry isn't
///     populated until `Shell::new` scans
///     `<config_dir>/userDefineLangs/`.
///
/// `LANG_TABLE` is asserted to be alphabetical in `core::lang`'s
/// tests, so the iteration walks adjacent same-letter rows
/// directly without sorting here.
fn build_language_menu() -> Result<HMENU> {
    use codepp_core::lang::LANG_TABLE;

    // Top-level menu, RAII-wrapped: any `?`-propagated failure
    // below destroys the kernel HMENU before the function unwinds,
    // so a partially-built menu never leaks. `take()` defuses the
    // guard right before the successful return.
    let menu = MenuGuard::wrap(unsafe { CreateMenu()? });

    // 1. "Normal Text" at the top. The L_TEXT row sits at index 0
    //    of LANG_TABLE by construction (pinned in
    //    `lang_table_first_entry_is_normal_text`).
    let text_label = wide_terminated("Normal Text");
    unsafe {
        AppendMenuW(
            menu.handle(),
            MF_STRING,
            (i32::from(ID_LANGUAGE_BASE) + LANG_TABLE[0].lang.as_npp_id()) as usize,
            PCWSTR(text_label.as_ptr()),
        )?;
        AppendMenuW(menu.handle(), MF_SEPARATOR, 0, PCWSTR::null())?;
    }

    // 3. Alphabetical block. Walk adjacent same-first-letter rows
    //    and decide submenu vs. top-level by run length.
    let entries = &LANG_TABLE[1..];
    let mut i = 0;
    while i < entries.len() {
        let first_letter = entries[i]
            .menu_label
            .chars()
            .next()
            .map(|c| c.to_ascii_uppercase());
        // Find the run of entries that share `first_letter`.
        let mut j = i + 1;
        while j < entries.len()
            && entries[j]
                .menu_label
                .chars()
                .next()
                .map(|c| c.to_ascii_uppercase())
                == first_letter
        {
            j += 1;
        }
        let run = &entries[i..j];

        if run.len() == 1 {
            // Single entry — append directly at top level.
            let label = wide_terminated(run[0].menu_label);
            unsafe {
                AppendMenuW(
                    menu.handle(),
                    MF_STRING,
                    (i32::from(ID_LANGUAGE_BASE) + run[0].lang.as_npp_id()) as usize,
                    PCWSTR(label.as_ptr()),
                )?;
            }
        } else {
            // Multiple entries — create a submenu titled by the
            // letter, append each entry to it, then attach the
            // submenu to the top-level menu. Same RAII guard
            // covers a `?`-failure inside the inner loop or on
            // the attach call below.
            let sub = MenuGuard::wrap(unsafe { CreatePopupMenu()? });
            for entry in run {
                let label = wide_terminated(entry.menu_label);
                unsafe {
                    AppendMenuW(
                        sub.handle(),
                        MF_STRING,
                        (i32::from(ID_LANGUAGE_BASE) + entry.lang.as_npp_id()) as usize,
                        PCWSTR(label.as_ptr()),
                    )?;
                }
            }
            let letter = first_letter.map_or_else(|| "?".to_string(), |c| c.to_string());
            let letter_w = wide_terminated(&letter);
            // Attach: ownership of the submenu transfers to `menu`
            // on success. Defuse the submenu guard *only* after
            // the attach call returns Ok — a `?` failure here
            // still drops `sub` and frees the orphan.
            let sub_handle = sub.handle();
            unsafe {
                AppendMenuW(
                    menu.handle(),
                    MF_POPUP,
                    sub_handle.0 as usize,
                    PCWSTR(letter_w.as_ptr()),
                )?;
            }
            let _ = sub.take();
        }

        i = j;
    }

    // 4 + 5. User-Defined section (Phase 4.6 m2).
    //
    // Layout follows Notepad++:
    //   ├─ Define your language…            (greyed — m3 wires the modal)
    //   ├─ Open User Defined Language folder…
    //   ├─ Notepad++ User Defined Languages Collection
    //   ├─ ──────── (separator, only present once loaded UDLs exist)
    //   └─ <loaded UDL list>                (m1d populates)
    //
    // The two `OPEN_*` entries are enabled today and route to
    // `ShellExecuteW("open", ...)` in the `WM_COMMAND` handler.
    // The loaded-UDL list is empty until m1b's startup scan lands;
    // the separator that would visually divide the actions from
    // the list is deliberately omitted here (would render as a
    // trailing separator otherwise, which reads as broken layout).
    unsafe {
        AppendMenuW(menu.handle(), MF_SEPARATOR, 0, PCWSTR::null())?;
    }

    let udl_sub = MenuGuard::wrap(unsafe { CreatePopupMenu()? });
    let define_label = wide_terminated("Define your language...");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_DEFINE_LANGUAGE),
            PCWSTR(define_label.as_ptr()),
        )?;
    }
    let open_folder_label = wide_terminated("Open User Defined Language folder...");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_OPEN_FOLDER),
            PCWSTR(open_folder_label.as_ptr()),
        )?;
    }
    let collection_label = wide_terminated("Notepad++ User Defined Languages Collection");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_OPEN_COLLECTION),
            PCWSTR(collection_label.as_ptr()),
        )?;
    }
    let udl_label = wide_terminated("User-Defined language");
    let udl_handle = udl_sub.handle();
    unsafe {
        AppendMenuW(
            menu.handle(),
            MF_POPUP,
            udl_handle.0 as usize,
            PCWSTR(udl_label.as_ptr()),
        )?;
    }
    let _ = udl_sub.take();

    Ok(menu.take())
}

/// Append the loaded UDL entries as flat top-level items on the
/// Language menu, directly below the "User-Defined language"
/// submenu entry. Called from `Win32Ui::run` AFTER `Shell::new`
/// has populated `Shell.udl_registry` (the top-level menu is
/// built with only the built-in languages + the fixed UDL-
/// action submenu during window creation because Shell doesn't
/// exist yet at that point).
///
/// Layout matches Notepad++'s Language menu: the fixed UDL
/// actions ("Define your language…" etc.) live inside the
/// "User-Defined language" submenu; the loaded UDLs themselves
/// appear as flat, top-level `MF_STRING` items at the very
/// bottom of the Language menu, so a click on Language →
/// "Markdown (preinstalled)" is one hover-and-click rather than
/// two.
///
/// Each loaded UDL gets one menu item with command id
/// `ID_UDL_ITEM_BASE + (lang_type_id - UDL_LANG_TYPE_BASE)`.
/// The `WM_COMMAND` dispatcher inverts this: `menu_id -
/// ID_UDL_ITEM_BASE + UDL_LANG_TYPE_BASE = lang_type_id`, then
/// applies the language via `apply_lang(LangType(id))` — the
/// same path built-in-lexer menu items already take.
///
/// A separator is inserted before the first UDL entry (only if
/// there's at least one loaded UDL) so the "User-Defined
/// language" submenu entry is visually distinct from the
/// dynamic flat list.
///
/// # Safety
///
/// `language_menu` must be the live top-level HMENU returned by
/// `build_language_menu`, still owned by the top-level menu bar
/// (not detached). Caller runs on the UI thread.
unsafe fn append_udls_to_menu(language_menu: HMENU, registry: &codepp_udl::UdlRegistry) {
    unsafe {
        let entries = registry.entries();
        if entries.is_empty() {
            return;
        }
        // Separator between the "User-Defined language" submenu
        // entry (the last thing `build_language_menu` appended)
        // and the flat loaded-UDL list that follows. Errors
        // from AppendMenuW here are non-critical — the menu
        // still functions with the entries appended sans
        // separator, and the failure mode is a Win32
        // out-of-resources which would break far more than this
        // one call.
        let _ = AppendMenuW(language_menu, MF_SEPARATOR, 0, PCWSTR::null());
        for entry in entries {
            let offset = entry.lang_type_id - codepp_udl::UDL_LANG_TYPE_BASE;
            // Bound-check: skip any entry outside the reserved
            // menu range. `MAX_UDL_SCAN_ENTRIES` (1024) is
            // larger than the menu-id range (900 slots between
            // `ID_UDL_ITEM_BASE` and `ID_UDL_ITEM_END`), so a
            // config directory with >900 UDL files can produce
            // entries here that we log-and-drop from the menu
            // — the UDL still loads and can be applied via
            // extension detection or plugin API, it just has no
            // Language-menu entry. See DESIGN.md §7.2 Phase 4.6
            // for the reserved-id-range rationale.
            if offset < 0 || offset > i32::from(ID_UDL_ITEM_END - ID_UDL_ITEM_BASE) {
                tracing::warn!(
                    lang_type_id = entry.lang_type_id,
                    "UDL entry outside ID_UDL_ITEM_BASE..=END range; skipping menu entry"
                );
                continue;
            }
            #[allow(clippy::cast_sign_loss, reason = "offset guarded to be non-negative")]
            let menu_id = usize::from(ID_UDL_ITEM_BASE) + offset as usize;
            let sanitized = sanitize_udl_name_for_menu(&entry.definition.name);
            let label = wide_terminated(&sanitized);
            let _ = AppendMenuW(language_menu, MF_STRING, menu_id, PCWSTR(label.as_ptr()));
        }
    }
}

/// Refresh the loaded UDL registry from disk after the user
/// saves a UDL via the m3 editor. Rebuilds the Language menu's
/// dynamic UDL section so the newly-saved UDL becomes
/// selectable without a restart.
///
/// Contract: called on the UI thread from the main `WndProc`'s
/// `WM_APP_UDL_REFRESH` arm ONLY. Not re-entrant with plugin
/// dispatch — the registry mutation must happen inside the
/// `&mut WindowState` borrow so a plugin-thread read never
/// races.
unsafe fn refresh_udl_registry(main_hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
        return;
    };
    let Some(dir) = codepp_platform::user_define_langs_dir() else {
        tracing::warn!("cannot refresh UDL registry: user_define_langs_dir unavailable");
        return;
    };
    // Re-scan from disk. Same call `Shell::new` uses at startup.
    state.shell.udl_registry = codepp_udl::UdlRegistry::scan_dir(&dir);

    // Clear the previously-appended dynamic UDL entries from the
    // Language menu. Walk from the end and delete every trailing
    // item whose command id sits in the UDL range, plus a
    // trailing separator if present. This mirrors what
    // `append_udls_to_menu` inserts:
    //   1. one MFT_SEPARATOR
    //   2. one MF_STRING per loaded UDL, cmd id in
    //      ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END.
    // Removing by-cmd on the strings and by-position on the
    // trailing separator handles both.
    let language_menu = state.language_menu;
    unsafe {
        // First pass: remove every UDL-range command entry.
        // `RemoveMenu(..., MF_BYCOMMAND)` doesn't care about
        // position; iterating until it fails clears them all.
        for id in u32::from(ID_UDL_ITEM_BASE)..=u32::from(ID_UDL_ITEM_END) {
            let _ = RemoveMenu(language_menu, id, MF_BYCOMMAND);
        }
        // Second pass: peel off a trailing separator if present.
        // `GetMenuItemCount` returns -1 on error; treat that as
        // "no menu" and stop.
        let count = GetMenuItemCount(Some(language_menu));
        if count > 0 {
            let last_idx = (count - 1) as u32;
            let mut info = MENUITEMINFOW {
                cbSize: std::mem::size_of::<MENUITEMINFOW>() as u32,
                fMask: MIIM_FTYPE,
                ..Default::default()
            };
            if GetMenuItemInfoW(language_menu, last_idx, true, &raw mut info).is_ok()
                && (info.fType.0 & MFT_SEPARATOR.0) != 0
            {
                let _ = RemoveMenu(language_menu, last_idx, MF_BYPOSITION);
            }
        }
        // Re-append the dynamic UDL entries + their separator.
        append_udls_to_menu(language_menu, &state.shell.udl_registry);
        // Repaint the menu bar so the change is visible.
        let _ = DrawMenuBar(main_hwnd);
    }
}

/// Sanitize a UDL `<UserLang name="...">` attribute for use as
/// a Win32 menu label. Attacker-controlled (UDL XML is authored
/// by third parties — the "User-Defined language" submenu even
/// links users to a public GitHub collection to download them),
/// so we treat it exactly like tab-title chrome:
///
/// 1. Replace display-hostile characters — C0 controls (incl.
///    `\0`, `\r`, `\n`, `\t`), DEL/C1, zero-widths, bidi
///    overrides, line/paragraph separators — with U+FFFD via
///    [`sanitize_filename_for_display`], and cap length. Without
///    the `\t` replacement a UDL name like `Reload File\tCtrl+R`
///    would produce a spoofed right-aligned "shortcut" column in
///    the menu (Win32 uses `\t` as the label/accelerator
///    separator), impersonating a menu item with a specific
///    hotkey binding. Substitution beats deletion for exactly
///    the reason the shared sanitizer picked it — see the
///    `DISPLAY_REPLACEMENT` docstring in `codepp_shell`.
///    Deletion would let a hostile name collapse onto a
///    legitimate one (a UDL named `A\tB` renders identically to
///    a real `AB` under stripping), manufacturing the collision
///    this sanitizer is supposed to prevent. Substitution does
///    not distinguish two hostile inputs from each other —
///    `A\tB` and `A\nB` both become `A\u{FFFD}B` — but that is
///    not a property the threat model requires.
/// 2. Escape ampersands as `&&`. Win32 treats a single `&` as
///    the mnemonic-underline marker, so `Save & Continue` would
///    render as `Save _C_ontinue` with `C` underlined. Doubling
///    to `&&` renders a literal ampersand. Without the escape,
///    a UDL name could inject or collide with a mnemonic —
///    e.g. `&File Utils` would put a mnemonic on `F`, giving
///    the malicious UDL the same access key as the top-level
///    `&File` menu.
///
/// Returns a new `String`; caller wraps in `wide_terminated`.
fn sanitize_udl_name_for_menu(name: &str) -> String {
    let sanitized_and_capped = sanitize_filename_for_display(name);
    let mut escaped = String::with_capacity(sanitized_and_capped.len());
    for c in sanitized_and_capped.chars() {
        if c == '&' {
            escaped.push_str("&&");
        } else {
            escaped.push(c);
        }
    }
    escaped
}

/// RAII wrapper around an HMENU that calls `DestroyMenu` on drop
/// unless ownership is taken via [`Self::take`]. Used by
/// [`build_language_menu`] so a `?`-propagated failure during
/// menu construction doesn't leak the in-flight kernel object.
///
/// The guard is dropped (and the menu destroyed) on every error
/// path; on success the caller pulls the HMENU out via `take`,
/// which sets the wrapped handle to null and converts the Drop
/// into a no-op.
struct MenuGuard {
    menu: HMENU,
}

impl MenuGuard {
    fn wrap(menu: HMENU) -> Self {
        Self { menu }
    }
    fn handle(&self) -> HMENU {
        self.menu
    }
    /// Defuse the guard, returning the contained HMENU. After
    /// `take`, `Drop` is a no-op — the caller has assumed ownership.
    fn take(mut self) -> HMENU {
        let m = self.menu;
        self.menu = HMENU(core::ptr::null_mut());
        m
    }
}

impl Drop for MenuGuard {
    fn drop(&mut self) {
        if !self.menu.is_invalid() {
            // SAFETY: `self.menu` was returned from CreateMenu /
            // CreatePopupMenu and has not been attached to a
            // parent menu (the `take()` defuse runs only after a
            // successful attach). DestroyMenu on an unattached
            // HMENU is the documented release path.
            let _ = unsafe { DestroyMenu(self.menu) };
        }
    }
}

/// Build a UTF-16 `Vec<u16>` with a trailing null. Caller pulls
/// the raw pointer via `.as_ptr()`; the buffer must out-live the
/// `PCWSTR` use. `AppendMenuW` copies the string immediately, so
/// per-call locals are sufficient.
pub(crate) fn wide_terminated(s: &str) -> Vec<u16> {
    s.encode_utf16().chain(std::iter::once(0)).collect()
}

/// Radio-mark the Encoding menu's active item. Encoding values
/// don't yet have a numeric ABI to share with plugins, so the
/// match is on a small inline table — extended alongside the
/// `core::encoding` set as new variants land.
///
/// # Safety
///
/// `encoding_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_encoding_menu(encoding_menu: HMENU, encoding: &Encoding) {
    // The Phase 3 status-bar label is the most stable identity we
    // have for an `Encoding`; matching on it avoids exporting more
    // surface from `core::encoding` than the menu actually needs.
    // Anything not in the table leaves no radio mark — a
    // user-visible "no encoding selected" cue that an unfamiliar
    // encoding is current.
    let target = match encoding.label() {
        "ANSI" => Some(ID_ENCODING_ANSI),
        "UTF-8" => Some(ID_ENCODING_UTF8),
        "UTF-8 BOM" => Some(ID_ENCODING_UTF8_BOM),
        // The Encoding menu's "UTF-16 LE/BE BOM" items map to
        // `Utf16LeBom` / `Utf16BeBom` (the BOM variants are the
        // canonical save targets — the no-BOM variants are
        // detection-only). Both label strings — with and without
        // the trailing " BOM" — point at the same radio item so
        // a heuristic-detected no-BOM file still highlights the
        // matching menu entry.
        "UTF-16 LE" | "UTF-16 LE BOM" => Some(ID_ENCODING_UTF16_LE),
        "UTF-16 BE" | "UTF-16 BE BOM" => Some(ID_ENCODING_UTF16_BE),
        _ => None,
    };
    if let Some(id) = target {
        unsafe {
            let _ = CheckMenuRadioItem(
                encoding_menu,
                u32::from(ID_ENCODING_ANSI),
                u32::from(ID_ENCODING_UTF16_BE),
                u32::from(id),
                MF_BYCOMMAND.0,
            );
        }
    }
}

/// Rebuild the Window menu from the current tab list. Each tab gets
/// one entry (`<idx>: <filename>`); the active tab is check-marked.
/// Cmd id = `ID_WINDOW_BASE + idx`.
///
/// The submenu is fully torn down and rebuilt on every popup — the
/// tab set is small (≤ 100 capped by the cmd-id range), so a per-
/// open rebuild is far simpler than tracking deltas.
///
/// # Safety
///
/// `window_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_window_menu(window_menu: HMENU, shell: &Shell) {
    // Clear by deleting every existing item by position. Iterate
    // backward so deletion of item N doesn't shift item N+1 into
    // the just-cleared slot.
    let count = unsafe { GetMenuItemCount(Some(window_menu)) };
    if count > 0 {
        for i in (0..count).rev() {
            unsafe {
                let _ = DeleteMenu(window_menu, i as u32, MF_BYPOSITION);
            }
        }
    }

    if shell.tabs.is_empty() {
        unsafe {
            let _ = AppendMenuW(
                window_menu,
                MF_STRING | MF_GRAYED,
                0,
                w!("(no open windows)"),
            );
        }
        return;
    }

    for (idx, tab) in shell.tabs.iter().enumerate() {
        if idx >= ID_WINDOW_CAP {
            // Cap the visible list at the cmd-id window. The
            // remainder is reachable through tab-strip clicks; the
            // menu just shows the first ID_WINDOW_CAP entries.
            break;
        }
        // Same filename-extraction rule as the tab strip: prefer
        // `path.file_name()`, fall back to "Untitled" for buffers
        // that haven't been saved yet, sanitize for control chars.
        let raw = tab
            .path
            .as_ref()
            .and_then(|p| p.file_name().and_then(|s| s.to_str()))
            .unwrap_or("Untitled");
        let cleaned = sanitize_filename_for_display(raw);
        // Prefix with "<idx+1> " for keyboard-friendly mnemonic
        // (matches N++ which uses 1-based numbering in this menu).
        let display = format!("{} {}", idx + 1, cleaned);
        let display_w: Vec<u16> = display.encode_utf16().chain(std::iter::once(0)).collect();
        let id = (ID_WINDOW_BASE as usize) + idx;
        unsafe {
            let _ = AppendMenuW(window_menu, MF_STRING, id, PCWSTR(display_w.as_ptr()));
        }
    }

    if let Some(active) = shell.active_tab {
        // Defense in depth: only mark the active tab if it's in the
        // visible-cmd-id window. A future `active_tab` outside the
        // 0..ID_WINDOW_CAP range would silently overflow the u32
        // addition; bounded check keeps the target id well-formed.
        if active < ID_WINDOW_CAP {
            let id = u32::from(ID_WINDOW_BASE) + active as u32;
            unsafe {
                let _ = CheckMenuItem(window_menu, id, MF_BYCOMMAND.0 | MF_CHECKED.0);
            }
        }
    }
}

/// Append loaded-plugin `FuncItems` onto the per-plugin submenu after
/// a successful lazy-load round. Each plugin gets its own popup
/// submenu under the top-level "Plugins" entry, with the plugin's
/// own getName output as the label.
///
/// # Safety
///
/// Caller must invoke this on the UI thread that owns `plugin_menu`.
/// `CreateMenu`/`AppendMenuW` do not re-enter our `wnd_proc`.
unsafe fn populate_plugin_menu(plugin_menu: HMENU, shell: &Shell) {
    for (plugin_name, funcs) in shell.loaded_plugin_funcs() {
        // One popup submenu per plugin so users see "Plugins → MyPlugin
        // → Item". Matches Notepad++'s layout.
        // SAFETY: CreateMenu just allocates a new HMENU; no aliasing
        // concerns.
        let submenu = match unsafe { CreateMenu() } {
            Ok(m) => m,
            Err(e) => {
                tracing::warn!(plugin = ?plugin_name, error = ?e, "CreateMenu failed");
                continue;
            }
        };
        for func in funcs {
            // N++ FuncItem ABI convention: a NULL `_pFunc` marks a menu
            // separator. The item_name for such an entry is a
            // placeholder the plugin does not expect to see rendered
            // (mimeTools, for example, writes a sentinel string there);
            // dispatching MF_STRING with that label is the visible bug.
            if func.p_func.is_none() {
                if let Err(e) = unsafe { AppendMenuW(submenu, MF_SEPARATOR, 0, PCWSTR::null()) } {
                    tracing::warn!(plugin = ?plugin_name, error = ?e, "AppendMenuW (separator) failed");
                }
                continue;
            }
            // FuncItem.item_name is a fixed-length null-terminated UTF-16
            // array; pass its pointer directly to AppendMenuW.
            let label = PCWSTR(func.item_name.as_ptr());
            // `cmd_id` is i32 (signed) but AppendMenuW expects usize.
            // Plugin cmd_ids are always positive (assigned from
            // PLUGIN_CMD_ID_BASE = 50000), so the cast is value-preserving.
            let id = func.cmd_id as usize;
            // SAFETY: `submenu` is the HMENU we just created; `label`
            // points into a static null-terminated wide string the
            // plugin owns for its lifetime.
            if let Err(e) = unsafe { AppendMenuW(submenu, MF_STRING, id, label) } {
                tracing::warn!(plugin = ?plugin_name, error = ?e, "AppendMenuW (item) failed");
            }
        }
        // Attach the submenu to the parent "Plugins" popup.
        let plugin_label_w: Vec<u16> = plugin_name
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        // SAFETY: `plugin_menu` is the parent HMENU passed in;
        // `plugin_label_w` is a local wide string that lives for the
        // duration of this call (AppendMenuW copies the label).
        if let Err(e) = unsafe {
            AppendMenuW(
                plugin_menu,
                MF_POPUP,
                submenu.0 as usize,
                PCWSTR(plugin_label_w.as_ptr()),
            )
        } {
            tracing::warn!(plugin = ?plugin_name, error = ?e, "AppendMenuW (popup) failed");
        }
    }
    // Append the Plugin Manager entry at the bottom of the menu,
    // separated from the per-plugin submenus by a divider —
    // matches Notepad++'s layout (per-plugin entries on top, then
    // separator, then "Plugin Admin..."). Always appended, even
    // when no plugins are loaded, so the user can reach the
    // manager to re-enable plugins they previously disabled.
    let _ = unsafe { AppendMenuW(plugin_menu, MF_SEPARATOR, 0, PCWSTR::null()) };
    let _ = unsafe {
        AppendMenuW(
            plugin_menu,
            MF_STRING,
            ID_PLUGINS_ADMIN as usize,
            w!("&Plugin Manager..."),
        )
    };
}

/// Write `text` into status-bar part `part_index`. Centralizes the
/// `SB_SETTEXTW` idiom so the regular status updates (encoding/EOL/size)
/// and the plugin-driven `NPPM_SETSTATUSBAR` overrides share one
/// implementation — the only thing that varies is the source string.
/// Trigger a relayout of the main window by posting a `WM_SIZE`
/// to it with its current client rect. Used by every chrome-toggle
/// path (`set_tabbar_hidden`, `set_toolbar_hidden`,
/// `set_menu_hidden`, `set_statusbar_hidden`) so the editor area
/// expands / shrinks to fill the freed / regained band.
///
/// Posts (via `PostMessageW`) rather than sends synchronously: the
/// chrome-toggle messages can be dispatched from inside a plugin's
/// `messageProc`, which is already running under `PluginCallGuard`.
/// A synchronous `SendMessage` would re-enter the main `wnd_proc` on
/// this thread, and `state_from_hwnd` would refuse the re-borrow
/// because the guard is held — the layout would silently no-op.
/// Posting queues the size message until after the guard drops,
/// at which point the normal message-pump dequeue can run `WM_SIZE`
/// with full state access.
///
/// `child_hwnd` is any descendant of the main window — typically
/// the chrome control we just toggled. The function derives the
/// main window from `GetParent`. The handle is read-only.
///
/// # Safety
///
/// `child_hwnd` must be a valid HWND owned by the same window
/// hierarchy `Win32Ui` was constructed against. UI-thread-only:
/// `GetParent` and `GetClientRect` are not documented as
/// thread-safe with concurrent window-style mutations.
unsafe fn relayout_main_window_via_post(child_hwnd: HWND) {
    // SAFETY: `GetParent` is a cheap UI-thread read with no
    // message pump; the caller's contract guarantees `child_hwnd`
    // is valid.
    unsafe {
        let Ok(parent) = GetParent(child_hwnd) else {
            return;
        };
        let mut rect = RECT::default();
        if GetClientRect(parent, &raw mut rect).is_err() {
            return;
        }
        let w = (rect.right - rect.left).max(0);
        let h = (rect.bottom - rect.top).max(0);
        // WM_SIZE's lparam packs (height << 16 | width). Width
        // and height fit in u16 by the Win32 contract on a single
        // screen; clamp explicitly so a future multi-monitor
        // edge case doesn't produce a garbage lparam.
        let w16 = (w as u32 & 0xFFFF) as isize;
        let h16 = ((h as u32 & 0xFFFF) << 16) as isize;
        // `wparam = 0` synthesizes `SIZE_RESTORED`. The main
        // wnd_proc's WM_SIZE handler ignores wparam today; if it
        // ever branches on the value (e.g. to skip layout on
        // `SIZE_MINIMIZED`), revisit each caller so a chrome
        // toggle doesn't produce a spurious "restored" event.
        let _ = PostMessageW(Some(parent), WM_SIZE, WPARAM(0), LPARAM(h16 | w16));
    }
}

/// Resolve the display label for the Language slot of the
/// status bar. Built-in languages route through
/// `LangType::language_name()` (which walks `core::lang::
/// LANG_TABLE`); dynamically-registered UDLs use the
/// `<UserLang name="...">` string from the parsed
/// [`codepp_udl::UdlDefinition`] in `udl_registry`. Falls back
/// to `"Normal Text"` when the id doesn't resolve in either
/// direction — same fallback the pre-Phase-4.6 code used, so a
/// hostile / stale `LangType` produces the same visible label as
/// an actual `L_TEXT` buffer.
///
/// **UDL-name sanitisation.** The UDL branch runs the name
/// through [`sanitize_filename_for_display`] before returning
/// — the string comes from third-party XML the user may have
/// downloaded, so display-hostile characters (C0 controls incl.
/// `\0`/`\r`/`\n`/`\t`, DEL, C1, zero-widths, bidi overrides,
/// line/paragraph separators) that would garble the status bar
/// are replaced with U+FFFD and the length is capped so an
/// oversized name can't visually push the adjacent EOL /
/// encoding / caret slots. Consistent with the same discipline
/// the menu-label path applies via `sanitize_udl_name_for_menu`;
/// the `&`-doubling done there is menu-specific (mnemonic
/// marker) and doesn't apply here since the status bar renders
/// `&` literally.
///
/// Extracted into a free function so the branching can be unit-
/// tested without a live `Win32Ui` or `HWND`. The single caller
/// (`Win32Ui::update_status`) wraps the raw-pointer dereference
/// for the registry itself, matching the safety discipline the
/// rest of the file uses for `udl_registry` access.
fn resolve_lang_label(lang: LangType, udl_registry: &codepp_udl::UdlRegistry) -> String {
    if codepp_udl::is_udl_lang_id(lang.as_npp_id()) {
        udl_registry
            .find_by_lang_type_id(lang.as_npp_id())
            .map_or_else(
                || "Normal Text".to_string(),
                |entry| sanitize_filename_for_display(&entry.definition.name),
            )
    } else {
        lang.language_name().unwrap_or("Normal Text").to_string()
    }
}

fn write_status_part(status_hwnd: HWND, part_index: usize, text: &str) {
    // Callers reach this via either static/formatted strings or
    // `Shell::set_status_bar`, which runs plugin-supplied text
    // through `sanitize_str_for_display` first — U+0000 (which
    // would otherwise truncate `SB_SETTEXTW` mid-glyph, since the
    // control reads up to the first zero UTF-16 unit) is
    // substituted with U+FFFD upstream, along with every other
    // display-hostile character. Do not reintroduce a local strip
    // here: the whole point of the consolidation is one place
    // that owns the policy. A new caller that needs its own
    // sanitization should route through the shared helper too.
    // Null-terminated UTF-16 buffer — Vec<u16> over HSTRING so the
    // layout is unambiguous; HSTRING has its own refcounted header.
    let wide: Vec<u16> = text.encode_utf16().chain(std::iter::once(0)).collect();
    // SB_SETTEXTW = 0x040B (wide variant; 0x0401 is the ANSI
    // SB_SETTEXTA, which the SendMessageW call would mismatch).
    // wparam packs `(part_index | drawing_type << 8)`; drawing type 0
    // gives the default sunken inner edge.
    const SB_SETTEXTW: u32 = 0x040B;
    unsafe {
        SendMessageW(
            status_hwnd,
            SB_SETTEXTW,
            Some(WPARAM(part_index)),
            Some(LPARAM(wide.as_ptr() as isize)),
        );
    }
}

// Status bar part layout. Seven slots, plus the size-grip the
// status-bar control draws on its own at the right edge:
//
//   0: language label         ("Normal Text", "C++", ...)
//   1: spring                  (empty; absorbs window-resize delta)
//   2: length / lines          ("length: 1,819   lines: 116")
//   3: caret position          ("Ln: 104   Col: 9   Pos: 1,539")
//   4: EOL                     ("Windows (CR LF)" / "Unix (LF)" / ...)
//   5: encoding                ("UTF-8")
//   6: INS / OVR               ("INS" / "OVR")
//
// Widths are 96-DPI defaults; the size-grip is system-rendered. A
// future polish item will measure the language label and switch part
// 0 to auto-fit; the fixed width below comfortably fits the longest
// `LANG_TABLE.menu_label` plus padding.
const STATUS_PART_LANG_W: i32 = 220;
// Wide enough for "length: 99,999,999   lines: 999,999" (the
// realistic upper bound at Scintilla's ~2 GiB document ceiling)
// without truncating the line count when six- or seven-digit
// numbers appear. Picked empirically — a 6,290-line file with
// 201k bytes already fills ~180 px in the system font. Total
// fixed-right-side parts (length 230 + cursor 220 + EOL 150 +
// encoding 130 + ins/ovr 45) sum to 775 px; combined with the
// `STATUS_PART_LANG_W = 220` minimum on the left, the layout
// collapses on windows narrower than ~995 px client width
// (`setup_status_parts`'s `.max(STATUS_PART_LANG_W)` clamp keeps
// it sound — the right-side parts spill off-screen rather than
// crashing).
const STATUS_PART_LENGTH_W: i32 = 230;
const STATUS_PART_CURSOR_W: i32 = 220;
const STATUS_PART_EOL_W: i32 = 150;
// 130px fits the longest non-`Other` `Encoding::label` —
// `"UTF-16 LE BOM"` plus the leading two-space pad (~110px at
// 96 DPI in the system font); the extra 20px is breathing room
// for high-DPI rendering and locale label growth.
const STATUS_PART_ENCODING_W: i32 = 130;
const STATUS_PART_INSOVR_W: i32 = 45;

const STATUS_PART_LANG: usize = 0;
#[allow(dead_code)]
const STATUS_PART_SPRING: usize = 1;
const STATUS_PART_LENGTH: usize = 2;
const STATUS_PART_CURSOR: usize = 3;
const STATUS_PART_EOL: usize = 4;
const STATUS_PART_ENCODING: usize = 5;
const STATUS_PART_INSOVR: usize = 6;

const SB_SETPARTS: u32 = 0x0404;

/// Compute right-edge x-coordinates for the 7-part status bar
/// layout and apply them via `SB_SETPARTS`. Called at status-bar
/// creation time and from every `WM_SIZE` so the spring (part 1)
/// absorbs the width delta while every other part keeps its
/// designed width.
///
/// The right edges are cumulative pixel offsets from the
/// status-bar's left edge. The last entry must be `-1` so the
/// final part extends to the control's right edge (which the
/// status bar naturally accounts for the system size-grip in).
fn setup_status_parts(status_hwnd: HWND, client_width: i32) {
    // Sum of fixed-width parts on the right side of the spring.
    let right_total = STATUS_PART_LENGTH_W
        + STATUS_PART_CURSOR_W
        + STATUS_PART_EOL_W
        + STATUS_PART_ENCODING_W
        + STATUS_PART_INSOVR_W;
    // Spring's right edge: window width minus the right-side
    // fixed parts. Clamp to >= STATUS_PART_LANG_W so the spring
    // doesn't collapse below the language slot when the window is
    // narrower than the sum of fixed widths.
    let spring_right = (client_width - right_total).max(STATUS_PART_LANG_W);
    let edges: [i32; 7] = [
        STATUS_PART_LANG_W,
        spring_right,
        spring_right + STATUS_PART_LENGTH_W,
        spring_right + STATUS_PART_LENGTH_W + STATUS_PART_CURSOR_W,
        spring_right + STATUS_PART_LENGTH_W + STATUS_PART_CURSOR_W + STATUS_PART_EOL_W,
        spring_right
            + STATUS_PART_LENGTH_W
            + STATUS_PART_CURSOR_W
            + STATUS_PART_EOL_W
            + STATUS_PART_ENCODING_W,
        // Last part extends to the right edge of the status bar
        // (the control reserves space for the system size-grip
        // automatically).
        -1,
    ];
    unsafe {
        SendMessageW(
            status_hwnd,
            SB_SETPARTS,
            Some(WPARAM(edges.len())),
            Some(LPARAM(edges.as_ptr() as isize)),
        );
    }
}

/// Format an integer with comma thousand-separators (e.g. `1819`
/// → `"1,819"`). Used for the byte-count and caret-position
/// fields in the status bar so a 50k-line file's `Pos: 412,683`
/// stays scannable. Locale-agnostic — Code++ doesn't carry a
/// locale layer yet, so the comma matches the most common
/// English-installation convention.
fn format_thousands(n: u64) -> String {
    let s = n.to_string();
    let bytes = s.as_bytes();
    let mut out = String::with_capacity(s.len() + s.len() / 3);
    for (i, b) in bytes.iter().enumerate() {
        if i > 0 && (bytes.len() - i).is_multiple_of(3) {
            out.push(',');
        }
        // `char::from(u8)` is the unambiguous "interpret this byte
        // as a Latin-1 / 7-bit-ASCII codepoint" conversion. The
        // `as char` cast does the same thing but reads as a wider
        // operation than what's actually needed; if a future
        // refactor ever passes non-digit bytes here the explicit
        // form makes the Latin-1 reinterpretation visible.
        out.push(char::from(*b));
    }
    out
}

/// Refresh the Scintilla-driven parts of the status bar (parts 2,
/// 3, 6 — length/lines, cursor, INS/OVR). Reads from the editor
/// view directly so the values reflect the live caret state. The
/// shell-driven parts (lang, encoding, EOL) are left untouched
/// here; they're written by [`UiPlatform::update_status`] when
/// the underlying metadata changes.
///
/// Called from:
///  - `Win32Ui::update_status` (full refresh on metadata change)
///  - `main_wnd_proc::WM_NOTIFY/SCN_UPDATEUI` (caret movement)
fn refresh_status_dynamic_parts(status_hwnd: HWND, editor: &EditorHandle) {
    let length = editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
    let lines = editor.send(SCI_GETLINECOUNT, 0, 0).max(0) as u64;
    let pos = editor.send(SCI_GETCURRENTPOS, 0, 0).max(0) as u64;
    // SCI_LINEFROMPOSITION returns 0-based line; the status bar
    // shows 1-based per N++ convention.
    let line0 = editor.send(SCI_LINEFROMPOSITION, pos as usize, 0).max(0) as u64;
    // SCI_GETCOLUMN returns 0-based column (virtual-space-aware,
    // tab-expanded); same +1 for display.
    let col0 = editor.send(SCI_GETCOLUMN, pos as usize, 0).max(0) as u64;
    let overtype = editor.send(SCI_GETOVERTYPE, 0, 0) != 0;

    let length_text = format!(
        "  length: {}   lines: {}",
        format_thousands(length),
        format_thousands(lines)
    );
    // Ln / Col are 1-based for display (caret on the first line
    // shows `Ln: 1`); Pos is 0-based (caret at start-of-file
    // shows `Pos: 0`) — this matches Notepad++'s status-bar
    // convention exactly. `saturating_add` over plain `+ 1` so
    // the +1 path stays sound even on the unreachable-by-
    // construction edge case where Scintilla returns `u64::MAX`
    // (bytes are bounded at INT_MAX ≈ 2 GiB by Scintilla's own
    // document model, so overflow is impossible in practice; the
    // explicit saturation makes the intent visible to a reviewer).
    let cursor_text = format!(
        "  Ln: {}   Col: {}   Pos: {}",
        line0.saturating_add(1),
        col0.saturating_add(1),
        format_thousands(pos)
    );
    let insovr_text = if overtype { "  OVR" } else { "  INS" };

    write_status_part(status_hwnd, STATUS_PART_LENGTH, &length_text);
    write_status_part(status_hwnd, STATUS_PART_CURSOR, &cursor_text);
    write_status_part(status_hwnd, STATUS_PART_INSOVR, insovr_text);
}

/// Show a "file changed externally — reload?" dialog. Standalone so
/// no `&mut WindowState` borrow is held while the modal pump runs.
fn show_reload_dialog(main_hwnd: HWND, path: &Path) -> bool {
    let prompt = HSTRING::from(format!(
        "{}\n\nThis file changed on disk. Reload from disk and discard any unsaved edits?",
        sanitize_path_for_display(path)
    ));
    let title = w!("Code++: file changed externally");
    let response =
        unsafe { MessageBoxW(Some(main_hwnd), &prompt, title, MB_YESNO | MB_ICONQUESTION) };
    response == IDYES
}

/// Generic Yes/No prompt — returns `true` for Yes, `false` for No
/// (or any other dismissal). Modal, so the caller must drop any
/// `&mut WindowState` borrow before calling.
fn show_yes_no_dialog(main_hwnd: HWND, title: &str, message: &str) -> bool {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &msg_w,
            &title_w,
            MB_YESNO | MB_ICONQUESTION,
        )
    };
    response == IDYES
}

/// Simple modal OK / Cancel prompt. Returns `true` for OK,
/// `false` for Cancel (or any other dismissal — X in the title
/// bar, Esc). Warning icon (matches the "you're about to lose
/// something" tone the OK / Cancel pattern usually indicates —
/// used by "Move to Recycle Bin" today, applicable to any
/// destructive-but-recoverable confirmation).
///
/// Modal, so the caller MUST drop any `&mut WindowState` borrow
/// before calling — same UB rule as [`show_yes_no_dialog`].
fn show_ok_cancel_dialog(main_hwnd: HWND, title: &str, message: &str) -> bool {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &msg_w,
            &title_w,
            MB_OKCANCEL | MB_ICONWARNING,
        )
    };
    response == IDOK
}

/// Format the "Move to Recycle Bin" confirmation dialog's body
/// text. Pure function so the exact wording is unit-testable.
/// Matches the wording the user requested verbatim:
///
/// > The file "C:\path\to\file.rb"
/// > will be moved to your Recycle Bin and this document will
/// > be closed.
/// > Continue?
fn move_to_recycle_bin_prompt_for(path: &Path) -> String {
    format!(
        "The file \"{}\"\nwill be moved to your Recycle Bin and this document will be closed.\nContinue?",
        sanitize_path_for_display(path)
    )
}

/// Outcome of a [`show_save_confirm_dialog`] modal — Notepad++'s
/// "Save file 'X' ?" three-way prompt.
///
///   * `Yes` — save before proceeding (with the close).
///   * `No` — discard changes and proceed.
///   * `Cancel` — abort the operation; the buffer stays open.
///
/// Anything other than the three explicit buttons (Esc, Alt-F4 on
/// the dialog, the X in the title bar) maps to `Cancel` — that's
/// the safe default: the user did not affirm a destructive action,
/// so we treat the dismissal as "abort." Matches what N++ does.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum SaveConfirmResult {
    Yes,
    No,
    Cancel,
}

/// Map the `MessageBoxW` return value (`MESSAGEBOX_RESULT`) to a
/// [`SaveConfirmResult`]. Centralised so the unit tests can
/// exercise the mapping without spinning up a real Win32 modal.
fn save_confirm_from_message_box(
    response: windows::Win32::UI::WindowsAndMessaging::MESSAGEBOX_RESULT,
) -> SaveConfirmResult {
    if response == IDYES {
        SaveConfirmResult::Yes
    } else if response == IDNO {
        SaveConfirmResult::No
    } else {
        // IDCANCEL, IDABORT, or any unexpected dismissal
        // (Esc, Alt-F4, dialog-X) — all map to "abort the
        // close." Safe default; matches Notepad++.
        SaveConfirmResult::Cancel
    }
}

/// Format the "Save file 'NAME' ?" prompt body for
/// [`show_save_confirm_dialog`]. Extracted so the unit-test
/// suite can pin the exact spec wording without spinning up a
/// real Win32 modal — the test calls this fn and asserts the
/// returned string against the verbatim spec, which means a
/// stray edit to either the format string or the test trips
/// the assertion.
fn save_confirm_prompt_for(display_name: &str) -> String {
    format!("Save file '{display_name}' ?")
}

/// "Save file 'NAME' ?" three-way confirmation — shown when the
/// user closes a tab whose buffer has unsaved changes. Title:
/// `Save`. Question-mark icon (matches `show_yes_no_dialog`'s
/// styling). Buttons: Yes / No / Cancel.
///
/// `display_name` is the tab strip name as rendered by
/// [`tab_display_name`] — the same "FILENAME" the user already
/// sees. The single-quote wrapping in the prompt matches N++'s
/// formatting verbatim so muscle-memory carries over.
///
/// Modal: caller MUST drop any `&mut WindowState` borrow before
/// invoking, same UB rule as [`show_yes_no_dialog`].
fn show_save_confirm_dialog(main_hwnd: HWND, display_name: &str) -> SaveConfirmResult {
    let title = w!("Save");
    let prompt = HSTRING::from(save_confirm_prompt_for(display_name));
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &prompt,
            title,
            MB_YESNOCANCEL | MB_ICONQUESTION,
        )
    };
    save_confirm_from_message_box(response)
}

/// Show a non-fatal error dialog. Standalone for the same reason as
/// `show_reload_dialog`.
pub(crate) fn show_error_dialog(main_hwnd: HWND, title: &str, message: &str) {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    unsafe {
        MessageBoxW(Some(main_hwnd), &msg_w, &title_w, MB_OK | MB_ICONWARNING);
    }
}

/// File-open / file-save filter strings the OS dialog displays in
/// the "Files of type" combo box. Win32 expects pairs of
/// NUL-terminated wide strings (display label, glob) terminated
/// by an extra empty NUL — i.e. the trailing `\0\0` below isn't a
/// typo, it's how the API knows the list ended.
///
/// Kept generic `*.*` for now; lexer-specific filters (e.g. `*.rs;
/// *.toml` for Rust projects) would require knowing the active
/// language at dialog-show time, which the Phase 5 cross-platform
/// dialog abstraction can layer in.
fn build_dialog_filter() -> Vec<u16> {
    "All Files (*.*)\0*.*\0Text Files (*.txt)\0*.txt\0\0"
        .encode_utf16()
        .collect()
}

/// Show the standard "Open" dialog and return every path the user
/// selected. Returns an empty `Vec` if the user cancelled. Owner
/// is the main Code++ HWND so the dialog is modal-relative and
/// the user can't hit the file menu twice.
///
/// **Multi-select.** `OFN_ALLOWMULTISELECT` is set so the user
/// can Ctrl+click / Shift+click to open several files in one
/// dialog. With `OFN_EXPLORER`, Windows fills `lpstrFile` with a
/// double-NUL-terminated sequence: for a single selection it's
/// just the full path followed by two NULs; for multiple
/// selections it's the directory, then each filename (basename
/// only), then two NULs. `parse_ofn_multi_select_buffer` handles
/// both shapes and returns absolute `PathBuf`s.
///
/// Buffer size: 32 KiB wide-chars (~ 64 KB). Windows recommends
/// a large buffer for multi-select because the entire selection
/// (directory + every filename + separators) has to fit or the
/// dialog fails with `ERROR_INSUFFICIENT_BUFFER`. `MAX_PATH`
/// (260) would silently truncate on a user picking a dozen files
/// from a deep directory; 32 KiB accommodates hundreds of typical
/// filenames without any practical constraint on the user's
/// selection count.
///
/// The returned `PathBuf`s decode via `from_utf16_lossy` — paths
/// containing surrogate halves (extremely rare on real filesystems)
/// degrade to a U+FFFD-substituted path that `std::fs::open` will
/// then refuse, surfacing as an Open error rather than silent
/// corruption.
fn prompt_open_paths(owner: HWND) -> Vec<PathBuf> {
    let filter = build_dialog_filter();
    // 32 KiB wide-chars — see the doc comment for why the
    // `MAX_PATH + 1` used by the save-side dialog doesn't work
    // for multi-select.
    const MULTISELECT_BUFFER_CHARS: usize = 32 * 1024;
    let mut buf = vec![0u16; MULTISELECT_BUFFER_CHARS];

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(buf.as_mut_ptr()),
        nMaxFile: buf.len() as u32,
        nFilterIndex: 1,
        // OFN_NOCHANGEDIR: without it, the dialog silently mutates the
        // process working directory as a side effect of the user
        // navigating around. That would corrupt every later relative
        // path the app resolves (including save_buffer_as's `Path::new(".")`
        // fallback when the chosen file has no parent component).
        //
        // OFN_ALLOWMULTISELECT: Ctrl/Shift-click accumulates a
        // multi-file selection. Requires OFN_EXPLORER for the
        // NUL-separated result format used here; the old
        // space-separated short-name format (without EXPLORER)
        // is unusable — filenames with spaces would be silently
        // corrupted.
        Flags: OFN_FILEMUSTEXIST
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_ALLOWMULTISELECT
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };

    // SAFETY: `&mut ofn` is a valid pointer to a fully-initialised
    // `OPENFILENAMEW` struct. `filter` and `buf` outlive the call
    // (both are local Vecs held until function return). The
    // dialog blocks until the user clicks OK or Cancel; on
    // success Windows writes the double-NUL-terminated selection
    // list into `buf`.
    let ok = unsafe { GetOpenFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        // Disambiguate Cancel (returns 0 from CommDlgExtendedError)
        // from a real failure. FNERR_BUFFERTOOSMALL fires when the
        // user's selection wouldn't fit in the 32 KiB buffer above
        // — surface it to the user rather than looking like a
        // mis-click cancel. Any other error code is unusual (the
        // OFN struct itself is fully-init) but still warrants a
        // log so the ambient failure is diagnosable.
        let err = unsafe { CommDlgExtendedError() };
        if err == FNERR_BUFFERTOOSMALL {
            show_error_dialog(
                owner,
                "Open — too many files",
                "The dialog can't return this many files in one selection. \
                 Please open fewer files at once (or open the folder as a workspace).",
            );
        } else if err.0 != 0 {
            tracing::warn!(
                code = err.0,
                "GetOpenFileNameW failed with a non-cancel error code"
            );
        }
        return Vec::new();
    }
    parse_ofn_multi_select_buffer(&buf)
}

/// Parse the double-NUL-terminated wide-char buffer that
/// `GetOpenFileNameW(OFN_ALLOWMULTISELECT | OFN_EXPLORER)` fills
/// in on success. Two shapes to handle:
///
///   * **Single file selected:** the buffer contains one
///     full path followed by two NULs. Return a one-element
///     `Vec` with that path.
///   * **Multiple files selected:** the buffer contains the
///     directory, then each filename (basename only, no
///     separator prefix), each entry NUL-terminated, and the
///     whole list ends with an additional NUL (so the buffer
///     is double-NUL-terminated). Return one `PathBuf` per
///     filename, each joined onto the directory.
///
/// Disambiguation: if the first NUL-terminated entry is followed
/// by more non-NUL bytes, we're in the multi-file shape. If not,
/// we're in the single-file shape.
///
/// Broken out as a pure function so it can be unit-tested
/// without invoking the actual Win32 dialog.
fn parse_ofn_multi_select_buffer(buf: &[u16]) -> Vec<PathBuf> {
    // Split the wide buffer into NUL-terminated fields. Windows
    // pads the buffer with zeros beyond the double-NUL terminator,
    // so `split(|&c| c == 0)` yields empty strings at the tail;
    // we filter those out.
    let mut fields = buf
        .split(|&c| c == 0)
        .take_while(|slice| !slice.is_empty())
        .map(String::from_utf16_lossy);
    let Some(first) = fields.next() else {
        return Vec::new();
    };
    let rest: Vec<String> = fields.collect();
    if rest.is_empty() {
        // Single-file shape — first entry IS the full path.
        return vec![PathBuf::from(first)];
    }
    // Multi-file shape — first entry is the directory, remaining
    // are basenames.
    let dir = PathBuf::from(first);
    rest.into_iter()
        .map(|name| {
            let mut p = dir.clone();
            p.push(name);
            p
        })
        .collect()
}

/// Show the standard "Save As" dialog and return the chosen path,
/// or `None` if the user cancelled. `default_name` (if `Some`)
/// pre-fills the file-name edit field — used by Save As to suggest
/// the active tab's current basename.
///
/// `OFN_OVERWRITEPROMPT` is set so the OS handles the "file
/// already exists, overwrite?" confirmation — saves us
/// reimplementing it. `OFN_PATHMUSTEXIST` rejects nonexistent
/// directories at the dialog level rather than letting the save
/// fail later with a less helpful error.
fn prompt_save_path(owner: HWND, default_name: Option<&str>) -> Option<PathBuf> {
    let filter = build_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    if let Some(name) = default_name {
        // Pre-fill the file-name edit field. Truncate to MAX_PATH
        // and NUL-terminate; longer names would trip Windows' own
        // length check. Truncation here is rare (most file names
        // are well under 260 code units) but trace it so a future
        // user report of "Save As suggested a wrong name" is
        // diagnosable from the log.
        let utf16: Vec<u16> = name.encode_utf16().collect();
        let len = utf16.len().min(MAX_PATH as usize);
        if len < utf16.len() {
            tracing::warn!(
                full_len = utf16.len(),
                truncated_to = len,
                "Save As default filename longer than MAX_PATH; truncated",
            );
        }
        path[..len].copy_from_slice(&utf16[..len]);
        path[len] = 0;
    }

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        // See `prompt_open_path` for why OFN_NOCHANGEDIR is mandatory.
        Flags: OFN_OVERWRITEPROMPT
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };

    // SAFETY: same contract as `prompt_open_path` — fully-init
    // struct, buffers outlive the call.
    let ok = unsafe { GetSaveFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        return None;
    }

    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// File-type filter for the Load / Save Session dialogs — `.xml`
/// first (that's the shape Notepad++ uses for its session files),
/// with an "All Files" fallback so hand-picked non-standard
/// extensions still work. Wire format is the same double-NUL pair
/// list [`build_dialog_filter`] documents.
fn build_session_dialog_filter() -> Vec<u16> {
    "Session Files (*.xml)\0*.xml\0All Files (*.*)\0*.*\0\0"
        .encode_utf16()
        .collect()
}

/// Show the "Open" dialog constrained to `.xml`, single-select.
/// Returns `None` on Cancel or on `CommDlgExtendedError` reporting
/// a non-cancel failure. Ambient dialog behaviour (`OFN_NOCHANGEDIR`,
/// path-must-exist, hide-read-only) matches [`prompt_open_paths`];
/// diverges only in the filter and the single-file result shape.
fn prompt_open_session_xml_path(owner: HWND) -> Option<PathBuf> {
    let filter = build_session_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        Flags: OFN_FILEMUSTEXIST
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };
    // SAFETY: same contract as `prompt_open_paths` — fully-initialised
    // OFN, buffers outlive the call, dialog blocks until dismissed.
    let ok = unsafe { GetOpenFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        let err = unsafe { CommDlgExtendedError() };
        if err.0 != 0 {
            tracing::warn!(
                code = err.0,
                "GetOpenFileNameW (session) failed with a non-cancel error code"
            );
        }
        return None;
    }
    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// Show the "Save As" dialog constrained to `.xml`, pre-filled with
/// `session.xml` as the default name. `OFN_OVERWRITEPROMPT` +
/// `OFN_PATHMUSTEXIST` match the discipline the tab-Save-As helper
/// [`prompt_save_path`] uses; only the filter and default-name
/// suggestion differ.
fn prompt_save_session_xml_path(owner: HWND) -> Option<PathBuf> {
    let filter = build_session_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    let default_name = "session.xml";
    let utf16: Vec<u16> = default_name.encode_utf16().collect();
    let len = utf16.len().min(MAX_PATH as usize);
    path[..len].copy_from_slice(&utf16[..len]);
    path[len] = 0;

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        Flags: OFN_OVERWRITEPROMPT
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };
    // SAFETY: same contract as `prompt_save_path` above — fully-init
    // OFN struct, filter + path buffers outlive the call.
    let ok = unsafe { GetSaveFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        return None;
    }
    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// File → Save Session... — capture every path-bound open tab and
/// write a Notepad++-shape session XML at a user-picked location.
/// Untitled buffers are skipped (no path to record); the resulting
/// file therefore contains only tabs a fresh N++ (or Code++) instance
/// can reopen from disk. The active tab contributes live caret +
/// scroll positions pulled from Scintilla; the rest carry zeros.
///
/// Dialog and file-write happen with **no** `&mut WindowState` borrow
/// held — the OS dialog spins its own message pump that would
/// re-enter `wnd_proc`. Metadata is snapshotted out of state before
/// the dialog opens.
fn handle_save_session(hwnd: HWND) {
    // 1. Snapshot the metadata under a brief borrow. Clone every
    //    field into an owned tuple so the borrow ends before the
    //    dialog opens. Editor reads happen inside the same block
    //    because state.editor and state.shell are disjoint fields
    //    on `&mut WindowState` — the borrow checker treats them
    //    independently.
    struct SaveMeta {
        files: Vec<NppFile>,
        active_index: usize,
    }
    let Some(meta) = (unsafe {
        state_from_hwnd(hwnd).map(|state| {
            let active = state.shell.active_tab;
            // Collect path-bound tabs alongside their original
            // vector index. The original index tells us whether
            // the tab is the active one (so we pull live caret /
            // scroll) or a background tab (zeros).
            let path_tabs: Vec<(usize, PathBuf, LangType, bool)> = state
                .shell
                .tabs
                .iter()
                .enumerate()
                .filter_map(|(i, t)| t.path.as_ref().map(|p| (i, p.clone(), t.lang, t.pinned)))
                .collect();
            // active_index against the FILTERED list — count
            // path-bound tabs preceding the active one. Zero if
            // no active tab or the active tab is untitled.
            let active_index = active.map_or(0, |ai| {
                state
                    .shell
                    .tabs
                    .iter()
                    .take(ai)
                    .filter(|t| t.path.is_some())
                    .count()
            });
            let files: Vec<NppFile> = path_tabs
                .into_iter()
                .map(|(orig_idx, path, lang, pinned)| {
                    let (start_pos, end_pos, first_visible_line) = if Some(orig_idx) == active {
                        let s = state.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
                        let e = state.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
                        let fv = state.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0) as u32;
                        (s, e, fv)
                    } else {
                        // Non-active tabs: zeros for now. Per-tab
                        // caret persistence across tab switches is
                        // tracked as milestone 6b in DESIGN.md and
                        // has the same "future" shape here — same
                        // gap the internal session.xml save path
                        // documents.
                        (0, 0, 0)
                    };
                    NppFile {
                        filename: path,
                        lang: npp_name_for_lang(lang).to_string(),
                        first_visible_line,
                        start_pos,
                        end_pos,
                        tab_pinned: YesNo::from_bool(pinned),
                        encoding: -1,
                        user_read_only: YesNo::No,
                    }
                })
                .collect();
            SaveMeta {
                files,
                active_index,
            }
        })
    }) else {
        return;
    };

    // 2. Prompt for a path. This spins a nested message loop; no
    //    state borrow may be alive when it does.
    let Some(save_path) = prompt_save_session_xml_path(hwnd) else {
        return;
    };

    // 3. Emit the XML. Errors surface via the standard error dialog
    //    — the user picked this path and expects a filesystem
    //    outcome, so a silent log wouldn't be right.
    let doc = NppSessionDoc {
        session: NppSession {
            active_view: 0,
            main_view: NppView {
                active_index: meta.active_index,
                files: meta.files,
            },
            // Sub view is always empty on our side (single view) but
            // written for N++ shape parity so an N++ opening the
            // file sees the element it expects.
            sub_view: Some(NppView::default()),
        },
    };
    if let Err(e) = doc.save_to_xml(&save_path) {
        show_error_dialog(
            hwnd,
            "Save Session failed",
            &format!(
                "Could not write the session file:\n\n{}\n\n{}",
                sanitize_path_for_display(&save_path),
                e
            ),
        );
    }
}

/// File → Load Session... — pick a Notepad++-shape session XML and
/// open every path-bound `<File>` entry inside it. Per-file metadata
/// (caret position, tab pin state, language override) is applied by
/// pre-populating `shell.session.tabs` with matching entries before
/// each `open_file` call — `Shell::apply_load_result` picks the
/// metadata up on load completion via its by-path lookup, the same
/// mechanism the internal startup-restore path uses.
///
/// Already-open paths are handled by `Shell::open_file`'s built-in
/// dedupe: the existing tab activates instead of reloading, so the
/// user's in-progress edits are preserved (Load Session does not
/// force a reset).
fn handle_load_session(hwnd: HWND) {
    // 1. Prompt outside any borrow — dialog spins its own pump.
    let Some(load_path) = prompt_open_session_xml_path(hwnd) else {
        return;
    };

    // 2. Read + parse. Errors surface via the standard dialog.
    let doc = match NppSessionDoc::load_from_xml(&load_path) {
        Ok(d) => d,
        Err(e) => {
            show_error_dialog(
                hwnd,
                "Load Session failed",
                &format!(
                    "Could not read the session file:\n\n{}\n\n{}",
                    sanitize_path_for_display(&load_path),
                    e
                ),
            );
            return;
        }
    };

    // Resolve `active_index` to an absolute path *before* filtering
    // — the UNC/empty-filename `filter_map` below drops entries,
    // which shifts every downstream index left by one and would
    // silently activate the wrong tab (or none, falling back to the
    // last-file-wins effect of `Shell::open_file`). Anchoring to a
    // path instead of a positional index makes the restore
    // independent of what got filtered / truncated. If the recorded
    // active file is itself a rejected UNC path or a corrupt empty
    // entry, `recorded_active_path` naturally becomes `None` when
    // filtering removes it — the later `tabs.iter().position(...)`
    // returns `None` and no override happens, which is the correct
    // fallback ("we can't restore that tab; leave the last-loaded
    // one active").
    let recorded_active_path: Option<PathBuf> = doc
        .session
        .main_view
        .files
        .get(doc.session.main_view.active_index)
        .map(|f| f.filename.clone());

    // Cap the parse-time cost too — bound how many `<File>` entries
    // we walk BEFORE the filter runs, not just after it (the
    // filter allocates one `PathBuf` clone per surviving entry, so
    // an attacker-controlled n-way `<File>` list would otherwise
    // eat unbounded CPU + allocations before the post-filter
    // `.take` truncation caught it). Truncated count is logged
    // below.
    let raw_file_count = doc.session.main_view.files.len();
    let mut rejected_unc = 0usize;
    let entries: Vec<(PathBuf, u64, Option<i32>, bool)> = doc
        .session
        .main_view
        .files
        .into_iter()
        .take(MAX_SESSION_TABS)
        .filter_map(|f| {
            // Skip <File> elements with no filename — corrupt / hand-
            // authored entries. Also skip entries whose filename is
            // empty (parses cleanly but resolves to `.`).
            if f.filename.as_os_str().is_empty() {
                return None;
            }
            // Reject non-local paths. On Windows, any path starting
            // with `\\` is UNC (`\\server\share\...`) or a device /
            // verbatim namespace (`\\.\...`, `\\?\...`). Feeding a
            // hostile UNC into `std::fs::open` triggers an outbound
            // SMB connection with the current user's NTLM
            // credentials — a Responder/ntlmrelayx-style hash
            // capture primitive. A session `.xml` can arrive from a
            // low-trust source (email, chat, "restore my workspace"
            // link), unlike a plugin-driven `NPPM_DOOPEN` where the
            // caller is already in-process trusted code. Reject
            // silently at the parse boundary; count rejections and
            // warn the user once at the end so a legitimate-looking
            // session that happens to reference network shares
            // doesn't disappear without an explanation.
            if is_non_local_windows_path(&f.filename) {
                tracing::warn!(
                    path = ?f.filename,
                    "Load Session: rejected non-local path (UNC / device / verbatim namespace)"
                );
                rejected_unc += 1;
                return None;
            }
            let lang_id = lang_type_from_npp_name(&f.lang).map(|l| l.0);
            Some((f.filename, f.start_pos, lang_id, f.tab_pinned.as_bool()))
        })
        .collect();

    if entries.is_empty() {
        if rejected_unc > 0 {
            show_error_dialog(
                hwnd,
                "Load Session",
                &format!(
                    "This session file contained {rejected_unc} network / UNC path(s), \
                     which Code++ does not open from session files for security reasons.\n\n\
                     No local files were opened."
                ),
            );
        }
        return;
    }

    // Report the truncation from the earlier `.take` — `entries`
    // is already capped, but the user (and future post-mortem
    // reader of the log) needs to know how many `<File>` entries
    // were silently dropped. The cap protects the O(n²) find loop
    // below AND the parse-time allocation cost of the filter above.
    let over_cap = raw_file_count.saturating_sub(MAX_SESSION_TABS);
    if over_cap > 0 {
        tracing::warn!(
            cap = MAX_SESSION_TABS,
            dropped = over_cap,
            "Load Session: entries exceed cap; excess dropped",
        );
    }

    // Discard a sole empty "new N" tab before the batch so a
    // fresh scratch buffer doesn't linger alongside the loaded
    // session. Idempotent across the loop below (after the first
    // opened file lands there are 1+ real tabs, so subsequent
    // calls no-op). Done here — after all filtering / validation
    // succeeds — so a session that failed to load or was entirely
    // UNC-rejected doesn't destroy the scratch buffer.
    unsafe {
        discard_sole_empty_untitled(hwnd);
    }

    // 3. Pre-populate the by-path metadata cache and kick each open.
    //    Re-acquire `state_from_hwnd` on every iteration to match
    //    the discipline `ID_FILE_OPEN` uses — a synchronous plugin
    //    hook added to `Shell::open_file` in a future change
    //    (`NPPN_FILEBEFOREOPEN`, DESIGN.md §7.4) would re-enter
    //    `wnd_proc` and alias the borrow otherwise. Belt and
    //    braces; `open_file` today does not reenter.
    //
    // While iterating we also:
    //
    //   * Apply the pin state via `Shell::set_pinned` on the
    //     just-opened tab. `apply_load_result` only mutates the
    //     `tab.pinned` flag, not the vector position, so without
    //     this call a pinned tab would land at wherever `open_file`
    //     pushed it (end of the vector) and the "pinned before
    //     unpinned" invariant would be broken until the next app
    //     restart, when `normalize_session_pinning` sorts session.xml
    //     back into shape. `set_pinned` is the one path that
    //     relocates the tab into the correct cluster.
    //
    //   * Capture the recorded-active file's stable `tab.id` at
    //     the moment we process its entry. Positional indices
    //     would shift under the `set_pinned` relocations that
    //     happen later in the same loop, and a by-path lookup in
    //     step 4 wouldn't find a still-loading tab (its `tab.path`
    //     stays `None` until `apply_load_result` fires). `tab.id`
    //     is assigned synchronously by `open_file` and never
    //     moves, so it's the only identity that survives both.
    let mut deduped = false;
    let mut recorded_active_target_id: Option<i32> = None;
    for (path, cursor, lang, pinned) in entries {
        let is_recorded_active = recorded_active_path.as_ref() == Some(&path);
        let outcome = unsafe {
            let Some(state) = state_from_hwnd(hwnd) else {
                continue;
            };
            // Merge into shell.session.tabs so apply_load_result's
            // by-path lookup finds our cursor/lang/pinned values
            // when the async load completes. Insert-or-update: if
            // the path already has an entry (e.g. a startup-restore
            // record we haven't consumed yet, or a previous Load
            // Session invocation), overwrite its metadata rather
            // than piling up duplicates.
            let stored = &mut state.shell.session.tabs;
            match stored
                .iter_mut()
                .find(|t| t.path.as_deref() == Some(path.as_path()))
            {
                Some(existing) => {
                    existing.cursor = cursor;
                    existing.lang = lang;
                    existing.pinned = pinned;
                }
                None => stored.push(codepp_core::Tab {
                    path: Some(path.clone()),
                    cursor,
                    lang,
                    pinned,
                    ..codepp_core::Tab::default()
                }),
            }
            let outcome = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                state.shell.open_file(path)
            }))
            .unwrap_or(OpenFileOutcome::Rejected);
            // Post-open reconcile: `open_file` leaves
            // `shell.active_tab` pointing at the affected tab
            // (freshly-pushed or the dedupe target). Capture the
            // stable id BEFORE `set_pinned` potentially relocates,
            // then apply the pin state.
            if !matches!(outcome, OpenFileOutcome::Rejected) {
                if let Some(idx) = state.shell.active_tab {
                    if is_recorded_active {
                        recorded_active_target_id = state.shell.tabs.get(idx).map(|t| t.id);
                    }
                    let _ = state.shell.set_pinned(idx, pinned);
                }
            }
            outcome
        };
        if matches!(outcome, OpenFileOutcome::SwitchedToExisting(_)) {
            deduped = true;
        }
    }

    // 4. Restore the recorded active tab. `Shell::open_file` sets
    //    the just-opened tab as active on every call, so the loop
    //    above ends with the *last* file active — override that by
    //    resolving `recorded_active_target_id` (the tab-id captured
    //    inside the loop at the moment the recorded active file
    //    was processed) back to a live index and setting
    //    `shell.active_tab`. When each async load completes,
    //    `apply_load_result` reads `active_tab` and binds the
    //    Scintilla view to the matching doc iff the just-loaded
    //    tab is the active one; making the target active *before*
    //    its load completes is what lets the paint land on the
    //    correct buffer without a second manual rebind. Using
    //    `tab.id` here (not path, not position) so `set_pinned`
    //    relocations from later iterations don't invalidate the
    //    target.
    let mut activated_recorded = false;
    if let Some(target_id) = recorded_active_target_id {
        unsafe {
            if let Some(state) = state_from_hwnd(hwnd) {
                if let Some(idx) = state.shell.tabs.iter().position(|t| t.id == target_id) {
                    if state.shell.active_tab != Some(idx) {
                        state.shell.active_tab = Some(idx);
                        activated_recorded = true;
                    }
                }
            }
        }
    }

    // 5. Sync the tab strip + drain any queued plugin notifications.
    //    Same tail as ID_FILE_OPEN — the loader's async completions
    //    will re-sync on WM_APP_WAKE, this handles the sync
    //    "switched to existing tab" case and the manual
    //    active-tab override above.
    // SAFETY: these helpers operate on the wnd_proc's own state via
    // HWND lookup; no aliasing `&mut WindowState` is alive at this
    // point (the last state borrow ended with the `if let` above).
    unsafe {
        refresh_tab_chrome(hwnd);
        if deduped || activated_recorded {
            handle_tab_selchange(hwnd);
        }
        fire_queued_notifications(hwnd);
    }
}

/// File → Print — snapshots the active tab's display name plus a copy
/// of the [`EditorHandle`] under a brief `&mut WindowState` borrow,
/// then dispatches to the [`print`] module for the OS print dialog and
/// the two-pass render loop. All GDI + spooler work happens outside
/// the borrow because `PrintDlgW` spins its own message pump that
/// would re-enter `wnd_proc`.
///
/// Idempotent no-op when no tab is open (`refresh_file_menu` greys
/// the menu item in that case, but a plugin-driven `NPPM_MENUCOMMAND`
/// could still fire the id independently — the guard here makes the
/// mismatch a silent no-op instead of a panic).
fn handle_print(hwnd: HWND) {
    // Snapshot: display name (basename / new N / custom label) plus a
    // copy of the editor handle. Editor is `Copy` — captures the
    // direct-call function pointer once at creation, then every copy
    // dispatches identically. Dropping the state borrow BEFORE the
    // dialog opens is the mandatory pattern (see the load-session
    // handler for the same rationale).
    let (display_name, editor) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return;
        };
        let Some(tab) = state.shell.active() else {
            return;
        };
        let name = tab_display_name(tab);
        (name, state.editor)
    };
    print::print_active_document(hwnd, &display_name, editor);
}

/// File → Print Now — same snapshot pattern as `handle_print`
/// (display name + editor handle under a brief borrow), but hands
/// off to [`print::print_active_document_now`] which skips the OS
/// `PrintDlgW` entirely and pushes the document straight to the
/// default printer. All pages, single copy, no confirmation.
fn handle_print_now(hwnd: HWND) {
    let (display_name, editor) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return;
        };
        let Some(tab) = state.shell.active() else {
            return;
        };
        let name = tab_display_name(tab);
        (name, state.editor)
    };
    print::print_active_document_now(hwnd, &display_name, editor);
}

/// File → Print Preview — snapshot the display name + editor handle
/// under a brief `&mut WindowState` borrow, then dispatch to the
/// [`print_preview`] module. Same borrow-lifetime discipline as
/// `handle_print`: the modal preview pump can re-enter this
/// `wnd_proc`, so no borrow may span it.
fn handle_print_preview(hwnd: HWND) {
    let (display_name, editor) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return;
        };
        let Some(tab) = state.shell.active() else {
            return;
        };
        let name = tab_display_name(tab);
        (name, state.editor)
    };
    print_preview::show_print_preview(hwnd, &display_name, editor);
}

/// File → Restore Recent Closed File (Ctrl+Shift+T). Pops the
/// most-recently-closed path off the history and opens it via
/// `Shell::open_file` — same code path a menu click on a
/// specific recent-files entry would take. When the history is
/// empty this is a no-op (the menu item is greyed by
/// `refresh_file_menu` for the same case, so we only reach this
/// handler when either a plugin fires the id or the accelerator
/// beats the menu-greying check by a keystroke).
fn handle_restore_recent(hwnd: HWND) {
    let path = unsafe { state_from_hwnd(hwnd).and_then(|s| s.shell.pop_last_recent_file()) };
    let Some(path) = path else { return };
    open_recent_path_via_shell(hwnd, path);
}

/// File → Open All Recent Files. Drains the entire history and
/// opens each path in most-recent-first order. The list is
/// empty after this returns (matching N++: everything the user
/// just reopened is now open, so it doesn't belong in a "recently
/// closed" list). No confirmation prompt even for a full 30-file
/// history — that matches N++, and the menu label makes the
/// action's scope obvious.
fn handle_open_all_recent(hwnd: HWND) {
    let paths = unsafe {
        state_from_hwnd(hwnd)
            .map(|s| s.shell.take_all_recent_files())
            .unwrap_or_default()
    };
    if paths.is_empty() {
        return;
    }
    for p in paths {
        open_recent_path_via_shell(hwnd, p);
    }
}

/// File → Empty Recent Files List. Drops every retained path
/// and rewrites the (now-empty) `recent_files.xml`. No
/// confirmation — the action is one entry back in the menu
/// history via Ctrl+Z-equivalent (there isn't one, but the
/// list can always be repopulated by closing files again).
/// Matches N++'s no-prompt behaviour.
fn handle_empty_recent(hwnd: HWND) {
    unsafe {
        if let Some(state) = state_from_hwnd(hwnd) {
            state.shell.clear_recent_files();
        }
    }
}

/// File → \[Nth recent file\]. Fires when the user clicks a
/// specific numbered entry in the recent-files region. `index`
/// is 0-based (0 = "the most recently closed file", matching
/// the menu order). Symmetric with Restore Recent Closed File
/// (Ctrl+Shift+T) and Open All Recent Files: the entry is
/// removed from the history the moment it's reopened, since
/// the file is now open again and no longer counts as
/// "recently closed." Closing it again will re-add it to the
/// top of the list via the usual `close_active_tab` push path.
fn handle_open_recent_at(hwnd: HWND, index: usize) {
    let path = unsafe { state_from_hwnd(hwnd).and_then(|s| s.shell.take_recent_file_at(index)) };
    let Some(path) = path else { return };
    open_recent_path_via_shell(hwnd, path);
}

/// Settings → Preferences. Snapshot the current Preferences
/// under a brief borrow, drop the borrow (the modal dialog's
/// pump re-enters this `wnd_proc`, same borrow discipline as
/// every other modal handler), show the dialog, and on Close
/// hand the updated Preferences back to Shell so
/// `set_preferences` can persist them + take side-effect
/// actions (e.g. clearing the recent-files list when the user
/// disables the feature).
fn handle_preferences_menu(hwnd: HWND) {
    let current = unsafe { state_from_hwnd(hwnd).map(|s| s.shell.preferences.clone()) };
    let Some(current) = current else { return };
    let updated = preferences::show_preferences_dialog(hwnd, current);
    if let Some(new) = updated {
        unsafe {
            if let Some(state) = state_from_hwnd(hwnd) {
                state.shell.set_preferences(new);
            }
        }
    }
}

/// Discard the sole open tab if it's an empty, unpinned
/// File→New buffer ("new N" with `untitled_seq` set, no
/// on-disk path, `pinned == false`, and zero characters in
/// the Scintilla document). Returns `true` iff a discard
/// actually happened.
///
/// Mirrors Notepad++'s tab-strip hygiene: when the user opens
/// files while the only open tab is a fresh scratch "new 1", the
/// scratch tab is thrown away rather than piling up next to the
/// files just opened. "Empty" is a live Scintilla content check
/// (`SCI_GETLENGTH == 0`), not the `Tab.dirty` flag — a typed-
/// then-erased scratch reads as empty here and gets discarded
/// (nothing visible is lost; Undo history for a discarded buffer
/// is lost, which matches N++). A scratch with any typed content
/// stays open alongside whatever gets opened.
///
/// The pinned check honours the same "keep this tab across
/// automatic close operations" invariant that
/// `pick_next_close_target(CloseMultiKind::AllButPinned)` and
/// the tab-drag arming guard already respect: a user who
/// explicitly pinned their scratch buffer is signalling "keep
/// this around", and silently discarding it here would violate
/// that signal.
///
/// **Callers**: every user-initiated batch open path — File →
/// Open, File → Load Session, Restore Recent Closed File, Open
/// All Recent Files, click on a specific recent-files entry,
/// drag-and-drop file open, Find-in-Files double-click,
/// Workspace-tree double-click, Workspace right-click → Open.
/// Call **once** at the start of a batch (before the loop that
/// opens N files), not per-file — the scratch tab only exists
/// to be discarded on the first open.
///
/// **Do NOT call from**: File → New (explicitly wants a fresh
/// tab), startup session restore (no scratch tab exists yet at
/// that point), or `apply_file_change` reload (the tab being
/// reloaded IS the tab, not a bystander).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn discard_sole_empty_untitled(hwnd: HWND) -> bool {
    // Cheap Shell-side checks under a brief borrow — must drop
    // before `handle_close_active_tab` runs (it takes its own
    // `&mut WindowState` and may spawn a nested pump for the
    // save-changes dialog, which the empty-untitled exception
    // in `handle_close_active_tab_inner` skips for us).
    //
    // Three candidacy checks matter:
    //
    //   * `tabs.len() == 1` — the "sole tab" premise.
    //   * `active_tab == Some(0)` — Shell-side index consistency.
    //     Message-dispatch flows (nested wnd_proc calls from
    //     WM_APP_WAKE drain paths, batch-open loops that
    //     interleave close + open) can leave `active_tab`
    //     transiently out of sync with `tabs.len()`. Bail on
    //     mismatch rather than trust indices into a
    //     partially-mutated vector.
    //   * The tab's own fields (`path`, `untitled_seq`,
    //     `pinned`) identify a fresh scratch buffer that isn't
    //     pinned.
    //
    // We also capture the Shell-side `scintilla_doc` pointer
    // for `tabs[0]` alongside the editor handle. The length check
    // below reads from whatever document the shared editor view
    // is CURRENTLY bound to, which for the deferred-rebind pattern
    // used elsewhere in this file (`handle_tab_selchange` /
    // `apply_load_result`) is not automatically the same as
    // `tabs[0].scintilla_doc`: Shell can set `active_tab = Some(0)`
    // before the editor's `SCI_SETDOCPOINTER` catches up. Reading
    // the wrong buffer's length here would either mistakenly
    // discard a scratch that has typed content (data loss) or
    // falsely spare an empty one (harmless nuisance). The
    // pointer comparison after we drop the borrow closes both
    // cases.
    let (candidate, editor, expected_doc) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return false;
        };
        if state.shell.tabs.len() == 1 && state.shell.active_tab != Some(0) {
            tracing::warn!(
                active_tab = ?state.shell.active_tab,
                tabs_len = state.shell.tabs.len(),
                "discard_sole_empty_untitled: skipping — active_tab out of sync with tabs.len()"
            );
        }
        let candidate = state.shell.tabs.len() == 1
            && state.shell.active_tab == Some(0)
            && state.shell.tabs[0].path.is_none()
            && state.shell.tabs[0].untitled_seq.is_some()
            && !state.shell.tabs[0].pinned;
        let expected_doc = state.shell.tabs.first().map_or(0, |t| t.scintilla_doc);
        (candidate, state.editor, expected_doc)
    };
    if !candidate {
        return false;
    }
    // Verify the shared editor view is bound to the exact
    // Scintilla document `tabs[0]` owns before we trust the
    // length read. If a deferred rebind hasn't fired yet, the
    // pointers will differ — bail rather than measure some
    // other buffer's length and risk discarding a scratch tab
    // that still has typed content sitting in its (currently
    // unbound) document.
    //
    // `expected_doc == 0` means the tab hasn't been materialised
    // yet (Shell allocates the Tab before Scintilla's
    // `SCI_CREATEDOCUMENT` fires). In that state there's nothing
    // to discard — the buffer is definitionally empty but also
    // pre-editor, so bail cleanly.
    if expected_doc == 0 {
        return false;
    }
    let current_doc = editor.send(SCI_GETDOCPOINTER, 0, 0);
    if current_doc != expected_doc {
        return false;
    }
    // Live content check via the direct-call surface. SCI_GETLENGTH
    // is a pure query — no state mutation, no re-entry into wnd_proc.
    // `editor.send` is a safe method (unsafety hidden inside its
    // impl), so no explicit `unsafe` wrapper is needed here.
    let len = editor.send(SCI_GETLENGTH, 0, 0);
    if len != 0 {
        return false;
    }
    unsafe { handle_close_active_tab(hwnd) };
    true
}

/// Shared open path used by the three recent-files handlers.
/// Wraps [`Shell::open_file`] with the same `catch_unwind` guard
/// and post-open UI refresh dance the multi-file File → Open
/// handler uses, so behaviour is identical whether the user
/// opened the file through the OS picker or through a
/// recent-files menu item. Runs
/// [`discard_sole_empty_untitled`] first so a fresh scratch
/// tab gets thrown away before the actual open — idempotent
/// across a batch (subsequent calls see 1+ real tabs and
/// no-op).
fn open_recent_path_via_shell(hwnd: HWND, path: PathBuf) {
    unsafe {
        discard_sole_empty_untitled(hwnd);
    }
    let outcome = unsafe {
        if let Some(state) = state_from_hwnd(hwnd) {
            std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| state.shell.open_file(path)))
                .unwrap_or(OpenFileOutcome::Rejected)
        } else {
            OpenFileOutcome::Rejected
        }
    };
    unsafe { refresh_tab_chrome(hwnd) };
    if matches!(outcome, OpenFileOutcome::SwitchedToExisting(_)) {
        // Dedupe branch: shell flipped `active_tab` but no async
        // load will wake to fire `handle_tab_selchange`. Fire it
        // manually so the Scintilla view rebinds to the newly
        // active buffer. Same pattern the multi-file Open path
        // uses on its own dedupe branch.
        unsafe { handle_tab_selchange(hwnd) };
    }
}

// --- About dialog ----------------------------------------------------
//
// Custom modal dialog built on a `WS_POPUP` + `WS_CAPTION` + `WS_SYSMENU`
// window — same scaffolding as the Goto / Find-Replace dialogs so the
// modal pump, panic boundary, and themed-paint workaround are reused
// verbatim. Layout mirrors Notepad++'s About box:
//
//   ┌──────────────────────────────────────────────────────────┐
//   │  [icon]   Code++ v<ver>   (64-bit)                       │
//   │           A cross-platform Notepad++ clone …             │
//   │                                                          │
//   │  [icon]  Home:  https://code-plus-plus.org/              │
//   │                                                          │
//   │  ┌──────── MIT License ───────────────────────────────┐  │
//   │  │ <license body, wrapped in a multi-line STATIC>     │  │
//   │  └────────────────────────────────────────────────────┘  │
//   │                          [ OK ]                          │
//   └──────────────────────────────────────────────────────────┘
//
// The two `[icon]` controls are both clickable (`SS_NOTIFY`) and route
// the click to `ShellExecuteW("open", url, …)` so either the small
// icon or the URL text below opens the home page in the user's
// default browser. Hovering the URL text or the small icon switches
// the cursor to `IDC_HAND` via a `WM_SETCURSOR` hook in
// `about_wnd_proc` — the parent override is needed because
// SS_NOTIFY by itself doesn't set a hover cursor.

/// Heap-allocated state for the About dialog. Owned by
/// `show_about_dialog`'s stack frame for the dialog's lifetime; the
/// raw pointer is stashed in the dialog HWND's `GWLP_USERDATA`.
///
/// The bold title `HFONT` is owned by a separate `GdiObjectGuard`
/// because it's only ever read by Win32's message dispatch (via
/// `WM_SETFONT` plumbed through `apply_dialog_font`) and never by
/// our `wnd_proc`, so threading it through state would be noise.
///
/// The chameleon `HICON` *is* tracked here and freed by the
/// `Drop` impl below — that makes the icon's lifetime
/// indistinguishable from the state's, eliminating the
/// declaration-order fragility a separate guard would carry (a
/// reorder that puts the guard above the box would silently let
/// `WM_DRAWITEM` read a freed icon between the guard's drop and
/// the box's drop).
struct AboutDialogState {
    /// HWND of the URL link STATIC. The `wnd_proc` compares `wparam`
    /// against this on `WM_SETCURSOR` to switch to `IDC_HAND`, and
    /// against `lparam` on `WM_CTLCOLORSTATIC` to paint the link
    /// text blue.
    link_hwnd: HWND,
    /// HWND of the owner (main editor) window. The IDOK/IDCANCEL
    /// and `WM_CLOSE` handlers re-enable the owner *before*
    /// `DestroyWindow(dlg)` so window activation transfers
    /// naturally back to the editor instead of falling through
    /// z-order to whatever other app happened to be running — a
    /// Win32 quirk where destroying a child whose owner is
    /// disabled hands focus to the next-eligible window in the
    /// desktop's activation list.
    owner_hwnd: HWND,
    /// Home URL, owned as a UTF-16 string so `ShellExecuteW` can
    /// take a `PCWSTR` directly. The `HSTRING` keeps the buffer
    /// alive across the call.
    home_url: HSTRING,
    /// Chameleon `HICON` for the owner-draw STATIC. Loaded once
    /// by `show_about_dialog`; the `wnd_proc` reads it on every
    /// `WM_DRAWITEM` for the icon control. Drawn via `DrawIconEx`
    /// with `DI_NORMAL` so the icon's 32bpp alpha channel is
    /// honoured rather than masked to black (the bug that
    /// surfaced the original "icon has a black background"
    /// report). Freed by the `Drop` impl below — owning the
    /// handle inside the state ties its lifetime exactly to the
    /// `Box`'s and makes a future reorder safe by construction.
    app_icon: HICON,
    /// HWND of the "MIT License" caption STATIC that sits over
    /// the etched frame's top edge. `WM_CTLCOLORSTATIC` compares
    /// `lparam` against this handle to return `dialog_bg_brush`
    /// (opaque background) for this label only, so the label
    /// paints a solid rectangle over the frame line and visually
    /// breaks it. Every other STATIC still returns `NULL_BRUSH`
    /// (transparent).
    lic_title_hwnd: HWND,
}

impl Drop for AboutDialogState {
    fn drop(&mut self) {
        unsafe {
            if !self.app_icon.is_invalid() {
                let _ = DestroyIcon(self.app_icon);
            }
        }
    }
}

extern "system" fn about_wnd_proc(hwnd: HWND, msg: u32, wparam: WPARAM, lparam: LPARAM) -> LRESULT {
    // Same panic-catch wrapper as the other dialog wnd_procs —
    // unwinding across `extern "system"` is UB. On panic fall back
    // to DefWindowProcW which is the natural no-op for unhandled
    // messages.
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as i32;
                let notif = ((wparam.0 >> 16) & 0xFFFF) as u32;
                if cmd == IDOK.0 || cmd == IDCANCEL.0 {
                    // Re-enable the owner BEFORE destroying the
                    // dialog. If we destroy first, Windows looks
                    // for the next-eligible activation target —
                    // the disabled owner is skipped and focus
                    // falls through to whatever else is in
                    // z-order, including other apps. Re-enabling
                    // first means the owner is the natural
                    // activation target when the dialog
                    // disappears. The `OwnerEnableGuard` below
                    // still runs on scope exit; calling
                    // `EnableWindow(true)` on an already-enabled
                    // window is a documented no-op.
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                    if !state_ptr.is_null() {
                        let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                    }
                    let _ = DestroyWindow(hwnd);
                    LRESULT(0)
                } else if cmd == i32::from(IDC_ABOUT_HOME_LINK) && notif == STN_CLICKED {
                    // URL static was clicked — open the home page
                    // in the user's default browser.
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                    if !state_ptr.is_null() {
                        ShellExecuteW(
                            Some(hwnd),
                            w!("open"),
                            &(*state_ptr).home_url,
                            PCWSTR::null(),
                            PCWSTR::null(),
                            SW_SHOWNORMAL,
                        );
                    }
                    LRESULT(0)
                } else {
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_DRAWITEM => {
                // Owner-draw paint for the chameleon STATIC. We
                // intercept rather than rely on `SS_ICON`'s
                // built-in paint because the SS_ICON path on
                // Win11 strips 32bpp alpha and surfaces
                // transparent pixels as black against the dialog
                // background. Painting the dialog brush first,
                // then `DrawIconEx(DI_NORMAL)`, gives the system
                // a clean backdrop and lets it composite the
                // icon's alpha channel correctly.
                let dis = lparam.0 as *const DRAWITEMSTRUCT;
                if !dis.is_null() {
                    let dis = &*dis;
                    if dis.CtlID == u32::from(IDC_ABOUT_ICON) {
                        // Always return "handled" for our control
                        // id, even if `state_ptr` is unexpectedly
                        // null or the icon failed to load. Windows
                        // does not retry `WM_DRAWITEM` for an
                        // owner-draw STATIC, and falling through
                        // to `DefWindowProcW` would leave the
                        // control area unpainted.
                        let state_ptr =
                            GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                        if !state_ptr.is_null() {
                            FillRect(dis.hDC, &raw const dis.rcItem, dialog_bg_brush());
                            let icon = (*state_ptr).app_icon;
                            if !icon.is_invalid() {
                                let w = dis.rcItem.right - dis.rcItem.left;
                                let h = dis.rcItem.bottom - dis.rcItem.top;
                                let _ = DrawIconEx(
                                    dis.hDC,
                                    dis.rcItem.left,
                                    dis.rcItem.top,
                                    icon,
                                    w,
                                    h,
                                    0,
                                    None,
                                    DI_NORMAL,
                                );
                            }
                        }
                        return LRESULT(1);
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_NCDESTROY => {
                // Defensive: zero `GWLP_USERDATA` so any stray
                // message that races between `DestroyWindow`
                // returning and the modal pump's `IsWindow`
                // break can't deref the dangling state pointer.
                // The `Box<AboutDialogState>` itself is owned by
                // the stack frame in `show_about_dialog` and
                // drops on function return, which always happens
                // *after* `DestroyWindow` synchronously delivers
                // `WM_NCDESTROY` — so the pointer is still valid
                // at the moment we zero it.
                SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_SETCURSOR => {
                // wparam carries the HWND of the child currently
                // under the cursor. SS_NOTIFY on its own doesn't
                // change the cursor, so we override here when the
                // child is the URL link.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() {
                    let child = HWND(wparam.0 as *mut c_void);
                    if child == (*state_ptr).link_hwnd {
                        if let Ok(cursor) = LoadCursorW(None, IDC_HAND) {
                            let _ = SetCursor(Some(cursor));
                        }
                        return LRESULT(1);
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CLOSE => {
                // Same activation-handoff fix as IDOK/IDCANCEL:
                // the title-bar X reaches us as `WM_CLOSE`, and
                // destroying the dialog while the owner is still
                // disabled would leak focus to whatever sits next
                // in z-order (often another app). Re-enable the
                // owner first so activation returns to the editor.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() {
                    let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                }
                let _ = DestroyWindow(hwnd);
                LRESULT(0)
            }
            // Same Win11-themed-paint workaround as the Goto and
            // Find/Replace dialogs: the system theme service
            // overrides our class hbrBackground for `WS_POPUP` +
            // `WS_CAPTION` windows. Painting the client rect
            // ourselves and returning 1 keeps the dialog body in
            // our chosen colour.
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            WM_CTLCOLORSTATIC => {
                // Most STATICs (title line, home-URL row, license
                // body, etched frame) paint on a transparent
                // background so the dialog fill shows through.
                // Exception: the "MIT License" caption sitting on
                // top of the etched frame's top edge — that one
                // needs an opaque `dialog_bg_brush` return so its
                // rect covers the frame line at the caption's
                // position and visually breaks it. Same rect
                // (from the STATIC's own client area) is used as
                // both the text background and the returned
                // brush, keeping the caption's paint fully in
                // its own bounds. Colour the URL STATIC
                // hyperlink-blue (RGB 0,0,238 → COLORREF
                // 0x00EE0000); others keep the system text
                // colour.
                let hdc = HDC(wparam.0 as *mut c_void);
                let target = HWND(lparam.0 as *mut c_void);
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() && target == (*state_ptr).lic_title_hwnd {
                    let _ = SetBkColor(hdc, COLORREF(DIALOG_BG));
                    return LRESULT(dialog_bg_brush().0 as isize);
                }
                let _ = SetBkMode(hdc, TRANSPARENT);
                if !state_ptr.is_null() && target == (*state_ptr).link_hwnd {
                    let _ = SetTextColor(hdc, COLORREF(0x00EE_0000));
                }
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            WM_CTLCOLORBTN => {
                // No `BS_GROUPBOX` in this dialog anymore (frame
                // is `SS_ETCHEDFRAME` on a STATIC), so the only
                // buttons routing through here are the themed OK
                // push button — which paints itself and ignores
                // the brush return. Match the transparent-BkMode
                // + `NULL_BRUSH` pattern the other dialogs use
                // for pushbuttons.
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

